  VALUES (p_run_id, p_table_name, p_row_id);
$$;


ALTER FUNCTION "public"."_demo_register_row"("p_run_id" "uuid", "p_table_name" "text", "p_row_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_ensure_manual_journal"() RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_id uuid;
BEGIN
  -- Prefer existing MISC journal, otherwise any misc-type, otherwise create one
  SELECT id INTO v_id FROM journals
   WHERE code = 'MISC' OR journal_type = 'misc'
   ORDER BY (code = 'MISC') DESC, created_at ASC
   LIMIT 1;

  IF v_id IS NULL THEN
    INSERT INTO journals (code, name, journal_type, currency, sequence_prefix, is_active, description)
    VALUES ('MISC', 'Miscellaneous', 'misc', 'SEK', 'V', true, 'Auto-created for expense bookings')
    RETURNING id INTO v_id;
  END IF;

  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."_ensure_manual_journal"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_flatten_skill_schema"("td" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'public'
    AS $$
DECLARE
  params jsonb;
  branches jsonb;
  branch jsonb;
  if_action_const text;
  if_action_enum jsonb;
  then_required jsonb;
  action_value text;
  x_action_required jsonb := '{}'::jsonb;
  existing_x jsonb;
BEGIN
  IF td IS NULL OR jsonb_typeof(td) <> 'object' THEN
    RETURN td;
  END IF;

  params := td #> '{function,parameters}';
  IF params IS NULL OR jsonb_typeof(params) <> 'object' THEN
    RETURN td;
  END IF;

  -- If no allOf/oneOf/anyOf at top level, nothing to do
  IF NOT (params ? 'allOf' OR params ? 'oneOf' OR params ? 'anyOf') THEN
    RETURN td;
  END IF;

  existing_x := COALESCE(params -> 'x-action-required', '{}'::jsonb);
  x_action_required := existing_x;

  -- Walk allOf branches, harvest if/then required arrays keyed by action const/enum
  branches := params -> 'allOf';
  IF branches IS NOT NULL AND jsonb_typeof(branches) = 'array' THEN
    FOR branch IN SELECT * FROM jsonb_array_elements(branches)
    LOOP
      if_action_const := branch #>> '{if,properties,action,const}';
      if_action_enum  := branch #>  '{if,properties,action,enum}';
      then_required   := branch #>  '{then,required}';

      IF then_required IS NOT NULL AND jsonb_typeof(then_required) = 'array' THEN
        IF if_action_const IS NOT NULL THEN
          x_action_required := jsonb_set(
            x_action_required,
            ARRAY[if_action_const],
            COALESCE(x_action_required -> if_action_const, '[]'::jsonb) || (then_required - 'action'),
            true
          );
        ELSIF if_action_enum IS NOT NULL AND jsonb_typeof(if_action_enum) = 'array' THEN
          FOR action_value IN SELECT jsonb_array_elements_text(if_action_enum)
          LOOP
            x_action_required := jsonb_set(
              x_action_required,
              ARRAY[action_value],
              COALESCE(x_action_required -> action_value, '[]'::jsonb) || (then_required - 'action'),
              true
            );
          END LOOP;
        END IF;
      END IF;
    END LOOP;
  END IF;

  -- Strip the unsafe keywords
  params := params - 'allOf' - 'oneOf' - 'anyOf' - 'if' - 'then' - 'else';

  -- Attach harvested map (only if non-empty)
  IF x_action_required <> '{}'::jsonb THEN
    params := jsonb_set(params, ARRAY['x-action-required'], x_action_required, true);
  END IF;

  RETURN jsonb_set(td, ARRAY['function','parameters'], params, true);
END;
$$;


ALTER FUNCTION "public"."_flatten_skill_schema"("td" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."_flatten_skill_schema"("td" "jsonb") IS 'Removes top-level allOf/oneOf/anyOf/if/then/else from a skill tool_definition and harvests action-discriminator required fields into x-action-required. Used to keep schemas compatible with OpenAI gpt-4.1 strict tool-calling.';



CREATE OR REPLACE FUNCTION "public"."_global_search_internal"("search_query" "text", "result_limit" integer DEFAULT 8) RETURNS TABLE("entity_type" "text", "entity_id" "uuid", "title" "text", "subtitle" "text", "url" "text", "rank" real)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  q tsquery;
  q_like text;
BEGIN
  IF search_query IS NULL OR length(trim(search_query)) < 2 THEN
    RETURN;
  END IF;
  q := websearch_to_tsquery('simple', search_query);
  q_like := '%' || search_query || '%';

  RETURN QUERY
  SELECT * FROM (
  (SELECT 'company'::text AS entity_type, c.id AS entity_id, c.name AS title, coalesce(c.domain, c.industry) AS subtitle, '/admin/companies/' || c.id::text AS url,
          ts_rank(to_tsvector('simple', coalesce(c.name,'') || ' ' || coalesce(c.domain,'') || ' ' || coalesce(c.industry,'') || ' ' || coalesce(c.notes,'')), q) AS rank
   FROM companies c
   WHERE to_tsvector('simple', coalesce(c.name,'') || ' ' || coalesce(c.domain,'') || ' ' || coalesce(c.industry,'') || ' ' || coalesce(c.notes,'')) @@ q OR c.name ILIKE q_like
   ORDER BY 6 DESC LIMIT result_limit)
  UNION ALL
  (SELECT 'lead'::text, l.id, l.name, coalesce(l.email, l.status::text), '/admin/crm?lead=' || l.id::text,
          ts_rank(to_tsvector('simple', coalesce(l.name,'') || ' ' || coalesce(l.email,'') || ' ' || coalesce(l.phone,'') || ' ' || coalesce(l.ai_summary,'')), q)
   FROM leads l
   WHERE to_tsvector('simple', coalesce(l.name,'') || ' ' || coalesce(l.email,'') || ' ' || coalesce(l.phone,'') || ' ' || coalesce(l.ai_summary,'')) @@ q OR l.email ILIKE q_like OR l.name ILIKE q_like
   ORDER BY 6 DESC LIMIT result_limit)
  UNION ALL
  (SELECT 'deal'::text, d.id, coalesce(d.notes, 'Deal ' || substring(d.id::text, 1, 8)), d.stage::text, '/admin/deals?id=' || d.id::text,
          ts_rank(to_tsvector('simple', coalesce(d.notes,'')), q)
   FROM deals d WHERE to_tsvector('simple', coalesce(d.notes,'')) @@ q ORDER BY 6 DESC LIMIT result_limit)
  UNION ALL
  (SELECT 'order'::text, o.id, 'Order ' || substring(o.id::text, 1, 8), coalesce(o.customer_email, o.status::text), '/admin/orders/' || o.id::text,
          ts_rank(to_tsvector('simple', coalesce(o.customer_email,'') || ' ' || coalesce(o.customer_name,'') || ' ' || coalesce(o.tracking_number,'')), q)
   FROM orders o
   WHERE to_tsvector('simple', coalesce(o.customer_email,'') || ' ' || coalesce(o.customer_name,'') || ' ' || coalesce(o.tracking_number,'')) @@ q OR o.customer_email ILIKE q_like
   ORDER BY 6 DESC LIMIT result_limit)
  UNION ALL
  (SELECT 'invoice'::text, i.id, coalesce(i.invoice_number, 'Invoice'), coalesce(i.customer_name, i.customer_email), '/admin/invoices/' || i.id::text,
          ts_rank(to_tsvector('simple', coalesce(i.invoice_number,'') || ' ' || coalesce(i.customer_email,'') || ' ' || coalesce(i.customer_name,'') || ' ' || coalesce(i.notes,'')), q)
   FROM invoices i
   WHERE to_tsvector('simple', coalesce(i.invoice_number,'') || ' ' || coalesce(i.customer_email,'') || ' ' || coalesce(i.customer_name,'') || ' ' || coalesce(i.notes,'')) @@ q OR i.invoice_number ILIKE q_like
   ORDER BY 6 DESC LIMIT result_limit)
  UNION ALL
  (SELECT 'quote'::text, qu.id, coalesce(qu.quote_number, qu.title, 'Quote'), coalesce(qu.customer_name, qu.customer_email), '/admin/quotes/' || qu.id::text,
          ts_rank(to_tsvector('simple', coalesce(qu.quote_number,'') || ' ' || coalesce(qu.title,'') || ' ' || coalesce(qu.customer_name,'') || ' ' || coalesce(qu.customer_email,'')), q)
   FROM quotes qu
   WHERE to_tsvector('simple', coalesce(qu.quote_number,'') || ' ' || coalesce(qu.title,'') || ' ' || coalesce(qu.customer_name,'') || ' ' || coalesce(qu.customer_email,'')) @@ q OR qu.quote_number ILIKE q_like
   ORDER BY 6 DESC LIMIT result_limit)
  UNION ALL
  (SELECT 'ticket'::text, t.id, t.subject, coalesce(t.contact_email, t.status::text), '/admin/tickets/' || t.id::text,
          ts_rank(to_tsvector('simple', coalesce(t.subject,'') || ' ' || coalesce(t.description,'') || ' ' || coalesce(t.contact_email,'') || ' ' || coalesce(t.contact_name,'')), q)
   FROM tickets t
   WHERE to_tsvector('simple', coalesce(t.subject,'') || ' ' || coalesce(t.description,'') || ' ' || coalesce(t.contact_email,'') || ' ' || coalesce(t.contact_name,'')) @@ q
   ORDER BY 6 DESC LIMIT result_limit)
  UNION ALL
  (SELECT 'contract'::text, ct.id, ct.title, coalesce(ct.counterparty_name, ct.status::text), '/admin/contracts/' || ct.id::text,
          ts_rank(to_tsvector('simple', coalesce(ct.title,'') || ' ' || coalesce(ct.counterparty_name,'') || ' ' || coalesce(ct.counterparty_email,'') || ' ' || coalesce(ct.notes,'')), q)
   FROM contracts ct
   WHERE to_tsvector('simple', coalesce(ct.title,'') || ' ' || coalesce(ct.counterparty_name,'') || ' ' || coalesce(ct.counterparty_email,'') || ' ' || coalesce(ct.notes,'')) @@ q
   ORDER BY 6 DESC LIMIT result_limit)
  UNION ALL
  (SELECT 'document'::text, dc.id, dc.title, coalesce(dc.category::text, dc.file_name), '/admin/documents?id=' || dc.id::text,
          ts_rank(to_tsvector('simple', coalesce(dc.title,'') || ' ' || coalesce(dc.file_name,'') || ' ' || coalesce(dc.description,'') || ' ' || coalesce(dc.content_md,'')), q)
   FROM documents dc
   WHERE to_tsvector('simple', coalesce(dc.title,'') || ' ' || coalesce(dc.file_name,'') || ' ' || coalesce(dc.description,'') || ' ' || coalesce(dc.content_md,'')) @@ q
   ORDER BY 6 DESC LIMIT result_limit)
  UNION ALL
  (SELECT 'kb_article'::text, k.id, k.title, k.question, '/admin/kb/' || k.id::text,
          ts_rank(to_tsvector('simple', coalesce(k.title,'') || ' ' || coalesce(k.question,'') || ' ' || coalesce(k.answer_text,'')), q)
   FROM kb_articles k
   WHERE to_tsvector('simple', coalesce(k.title,'') || ' ' || coalesce(k.question,'') || ' ' || coalesce(k.answer_text,'')) @@ q
   ORDER BY 6 DESC LIMIT result_limit)
  UNION ALL
  (SELECT 'product'::text, p.id, p.name, coalesce(p.description, p.barcode), '/admin/products?id=' || p.id::text,
          ts_rank(to_tsvector('simple', coalesce(p.name,'') || ' ' || coalesce(p.description,'') || ' ' || coalesce(p.barcode,'')), q)
   FROM products p
   WHERE to_tsvector('simple', coalesce(p.name,'') || ' ' || coalesce(p.description,'') || ' ' || coalesce(p.barcode,'')) @@ q OR p.barcode ILIKE q_like
   ORDER BY 6 DESC LIMIT result_limit)
  UNION ALL
  (SELECT 'page'::text, pg.id, pg.title, pg.slug, '/admin/pages/' || pg.id::text,
          ts_rank(to_tsvector('simple', coalesce(pg.title,'') || ' ' || coalesce(pg.slug,'')), q)
   FROM pages pg WHERE to_tsvector('simple', coalesce(pg.title,'') || ' ' || coalesce(pg.slug,'')) @@ q AND pg.deleted_at IS NULL
   ORDER BY 6 DESC LIMIT result_limit)
  UNION ALL
  (SELECT 'blog_post'::text, b.id, b.title, b.slug, '/admin/blog/' || b.id::text,
          ts_rank(to_tsvector('simple', coalesce(b.title,'') || ' ' || coalesce(b.slug,'') || ' ' || coalesce(b.excerpt,'')), q)
   FROM blog_posts b WHERE to_tsvector('simple', coalesce(b.title,'') || ' ' || coalesce(b.slug,'') || ' ' || coalesce(b.excerpt,'')) @@ q
   ORDER BY 6 DESC LIMIT result_limit)
  UNION ALL
  (SELECT 'employee'::text, e.id, e.name, coalesce(e.title, e.department, e.email), '/admin/hr?employee=' || e.id::text,
          ts_rank(to_tsvector('simple', coalesce(e.name,'') || ' ' || coalesce(e.email,'') || ' ' || coalesce(e.title,'') || ' ' || coalesce(e.department,'')), q)
   FROM employees e
   WHERE to_tsvector('simple', coalesce(e.name,'') || ' ' || coalesce(e.email,'') || ' ' || coalesce(e.title,'') || ' ' || coalesce(e.department,'')) @@ q
   ORDER BY 6 DESC LIMIT result_limit)
  UNION ALL
  (SELECT 'vendor'::text, v.id, v.name, v.email, '/admin/vendors?id=' || v.id::text,
          ts_rank(to_tsvector('simple', coalesce(v.name,'') || ' ' || coalesce(v.email,'') || ' ' || coalesce(v.notes,'')), q)
   FROM vendors v WHERE to_tsvector('simple', coalesce(v.name,'') || ' ' || coalesce(v.email,'') || ' ' || coalesce(v.notes,'')) @@ q
   ORDER BY 6 DESC LIMIT result_limit)
  UNION ALL
  (SELECT 'project'::text, pr.id, pr.name, coalesce(pr.client_name, pr.description), '/admin/projects?id=' || pr.id::text,
          ts_rank(to_tsvector('simple', coalesce(pr.name,'') || ' ' || coalesce(pr.client_name,'') || ' ' || coalesce(pr.description,'')), q)
   FROM projects pr WHERE to_tsvector('simple', coalesce(pr.name,'') || ' ' || coalesce(pr.client_name,'') || ' ' || coalesce(pr.description,'')) @@ q
   ORDER BY 6 DESC LIMIT result_limit)
  ) AS combined
  ORDER BY combined.rank DESC
  LIMIT result_limit * 4;
END;
$$;


ALTER FUNCTION "public"."_global_search_internal"("search_query" "text", "result_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."_upsert_quant"("_product_id" "uuid", "_location_id" "uuid", "_lot_id" "uuid", "_delta" numeric) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  INSERT INTO public.stock_quants (product_id, location_id, lot_id, quantity, updated_at)
  VALUES (_product_id, _location_id, _lot_id, _delta, now())
  ON CONFLICT (product_id, location_id, lot_id)
  DO UPDATE SET quantity = stock_quants.quantity + _delta, updated_at = now();
END; $$;


ALTER FUNCTION "public"."_upsert_quant"("_product_id" "uuid", "_location_id" "uuid", "_lot_id" "uuid", "_delta" numeric) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."adjust_quant"("p_product_id" "uuid", "p_location_id" "uuid", "p_qty_delta" numeric, "p_lot_id" "uuid" DEFAULT NULL::"uuid", "p_reason" "text" DEFAULT 'manual_adjustment'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_move uuid;
BEGIN
  IF NOT (has_role(auth.uid(),'writer'::app_role) OR has_role(auth.uid(),'admin'::app_role)) THEN RAISE EXCEPTION 'Insufficient privileges'; END IF;
  IF p_qty_delta = 0 THEN RAISE EXCEPTION 'Delta cannot be zero'; END IF;
  PERFORM _upsert_quant(p_product_id, p_location_id, p_lot_id, p_qty_delta);
  INSERT INTO stock_moves (product_id, quantity, move_type, to_location_id, lot_id, notes, created_by, state)
  VALUES (p_product_id, ABS(p_qty_delta)::int, 'adjustment', p_location_id, p_lot_id, p_reason, auth.uid(), 'done')
  RETURNING id INTO v_move;
  RETURN v_move;
END; $$;


ALTER FUNCTION "public"."adjust_quant"("p_product_id" "uuid", "p_location_id" "uuid", "p_qty_delta" numeric, "p_lot_id" "uuid", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."advance_billing_date"("_from" "date", "_interval" "text", "_count" integer) RETURNS "date"
    LANGUAGE "sql" IMMUTABLE
    SET "search_path" TO 'public'
    AS $$
  SELECT CASE lower(_interval)
    WHEN 'day'    THEN _from + (_count || ' days')::interval
    WHEN 'week'   THEN _from + (_count || ' weeks')::interval
    WHEN 'month'  THEN _from + (_count || ' months')::interval
    WHEN 'year'   THEN _from + (_count || ' years')::interval
    ELSE _from + (_count || ' months')::interval
  END::date
$$;


ALTER FUNCTION "public"."advance_billing_date"("_from" "date", "_interval" "text", "_count" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."allocate_picking"("p_order_id" "uuid", "p_source_location_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_picking_id UUID;
  v_order RECORD;
  v_item RECORD;
  v_line_id UUID;
  v_reservation_id UUID;
  v_source_location UUID;
  v_short_count INT := 0;
  v_total_count INT := 0;
  v_lines JSONB := '[]'::JSONB;
BEGIN
  IF NOT (public.has_role(auth.uid(), 'admin') OR public.has_role(auth.uid(), 'employee') OR auth.uid() IS NULL) THEN
    RAISE EXCEPTION 'Insufficient permissions';
  END IF;

  SELECT * INTO v_order FROM public.orders WHERE id = p_order_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Order % not found', p_order_id;
  END IF;

  -- Pick default source location if not given
  v_source_location := COALESCE(
    p_source_location_id,
    (SELECT id FROM public.stock_locations WHERE location_type = 'internal' AND is_active = true ORDER BY created_at LIMIT 1)
  );

  -- Idempotency: reuse open picking_order for this order if exists
  SELECT id INTO v_picking_id
  FROM public.picking_orders
  WHERE order_id = p_order_id AND status IN ('draft','ready','in_progress')
  LIMIT 1;

  IF v_picking_id IS NULL THEN
    INSERT INTO public.picking_orders (order_id, source_location_id, status, ship_to_name, ship_to_address, created_by, allocated_at)
    VALUES (
      p_order_id,
      v_source_location,
      'ready',
      COALESCE(v_order.customer_name, v_order.shipping_address->>'name'),
      v_order.shipping_address,
      auth.uid(),
      now()
    )
    RETURNING id INTO v_picking_id;
  END IF;

  -- Iterate order_items
  FOR v_item IN
    SELECT oi.*, p.name AS p_name, p.sku AS p_sku
    FROM public.order_items oi
    LEFT JOIN public.products p ON p.id = oi.product_id
    WHERE oi.order_id = p_order_id
  LOOP
    v_total_count := v_total_count + 1;
    v_reservation_id := NULL;

    -- Try reserve
    BEGIN
      v_reservation_id := public.reserve_stock(
        v_item.product_id,
        v_source_location,
        v_item.quantity,
        'picking_order',
        v_picking_id
      );
    EXCEPTION WHEN OTHERS THEN
      v_short_count := v_short_count + 1;
    END;

    INSERT INTO public.picking_lines (
      picking_order_id, product_id, product_sku, product_name,
      qty_requested, reservation_id, status
    )
    VALUES (
      v_picking_id, v_item.product_id, v_item.p_sku, COALESCE(v_item.p_name, 'Product'),
      v_item.quantity, v_reservation_id,
      CASE WHEN v_reservation_id IS NOT NULL THEN 'reserved' ELSE 'short' END
    )
    RETURNING id INTO v_line_id;

    v_lines := v_lines || jsonb_build_object(
      'line_id', v_line_id,
      'product_id', v_item.product_id,
      'qty', v_item.quantity,
      'reserved', v_reservation_id IS NOT NULL
    );
  END LOOP;

  -- Audit
  INSERT INTO public.audit_logs (action, entity_type, entity_id, user_id, metadata)
  VALUES ('picking.allocated', 'picking_order', v_picking_id, auth.uid(),
    jsonb_build_object('order_id', p_order_id, 'lines', v_total_count, 'short', v_short_count));

  RETURN jsonb_build_object(
    'success', true,
    'picking_order_id', v_picking_id,
    'lines_total', v_total_count,
    'lines_short', v_short_count,
    'lines', v_lines
  );
END;
$$;


ALTER FUNCTION "public"."allocate_picking"("p_order_id" "uuid", "p_source_location_id" "uuid") OWNER TO "postgres";

