CREATE OR REPLACE FUNCTION "public"."apply_stock_movement_event"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_payload jsonb;
  v_lines jsonb;
  v_line jsonb;
  v_product_id uuid;
  v_qty numeric;
  v_reason text;
  v_source text;
  v_location text := 'WH/MAIN';
BEGIN
  IF NEW.event_name <> 'stock.movement' THEN
    RETURN NEW;
  END IF;

  v_payload := COALESCE(NEW.payload, '{}'::jsonb);
  v_source := COALESCE(NEW.source, 'unknown');
  v_reason := COALESCE(v_payload->>'reason', v_source);

  -- Support both single and batch payloads
  IF v_payload ? 'lines' THEN
    v_lines := v_payload->'lines';
  ELSE
    v_lines := jsonb_build_array(v_payload);
  END IF;

  FOR v_line IN SELECT * FROM jsonb_array_elements(v_lines)
  LOOP
    v_product_id := NULLIF(v_line->>'product_id', '')::uuid;
    v_qty := COALESCE((v_line->>'quantity_delta')::numeric, (v_line->>'qty')::numeric, 0);

    IF v_product_id IS NULL OR v_qty = 0 THEN
      CONTINUE;
    END IF;

    -- Upsert stock_quants
    INSERT INTO public.stock_quants (product_id, location_code, quantity)
    VALUES (v_product_id, v_location, v_qty)
    ON CONFLICT (product_id, location_code)
    DO UPDATE SET quantity = stock_quants.quantity + EXCLUDED.quantity, updated_at = now();

    -- Mirror to products.stock_quantity
    UPDATE public.products
    SET stock_quantity = GREATEST(0, COALESCE(stock_quantity, 0) + v_qty::int),
        updated_at = now()
    WHERE id = v_product_id;

    -- Audit trail (NEW)
    INSERT INTO public.audit_logs (action, entity_type, entity_id, metadata)
    VALUES (
      CASE WHEN v_qty < 0 THEN 'pos.stock.decrement' ELSE 'pos.stock.increment' END,
      'product',
      v_product_id,
      jsonb_build_object(
        'event_id', NEW.id,
        'event_name', NEW.event_name,
        'source', v_source,
        'reason', v_reason,
        'quantity_delta', v_qty,
        'location_code', v_location,
        'sale_id', v_payload->>'sale_id',
        'session_id', v_payload->>'session_id'
      )
    );
  END LOOP;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."apply_stock_movement_event"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."apply_stock_movement_event"("p_payload" "jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_product_id uuid;
  v_qty_delta numeric;
  v_location_id uuid;
  v_location_code text;
  v_reason text;
  v_move_id uuid;
BEGIN
  v_product_id := NULLIF(p_payload->>'product_id','')::uuid;
  v_qty_delta := COALESCE((p_payload->>'qty_delta')::numeric, 0);
  v_location_code := COALESCE(p_payload->>'location_code', 'WH/MAIN');
  v_reason := COALESCE(p_payload->>'reason', 'event:stock.movement');

  -- Skip if no product or zero delta (e.g. POS line with custom product_name only)
  IF v_product_id IS NULL OR v_qty_delta = 0 THEN
    RETURN;
  END IF;

  -- Resolve location
  SELECT id INTO v_location_id
    FROM public.stock_locations
   WHERE code = v_location_code AND is_active = true
   LIMIT 1;

  IF v_location_id IS NULL THEN
    -- Fallback: any internal location
    SELECT id INTO v_location_id
      FROM public.stock_locations
     WHERE location_type = 'internal' AND is_active = true
     ORDER BY created_at LIMIT 1;
  END IF;

  IF v_location_id IS NULL THEN
    RAISE NOTICE 'apply_stock_movement_event: no internal location found, skipping';
    RETURN;
  END IF;

  -- Upsert quant
  INSERT INTO public.stock_quants (product_id, location_id, quantity, lot_id)
  VALUES (v_product_id, v_location_id, v_qty_delta, NULL)
  ON CONFLICT (product_id, location_id, lot_id) WHERE lot_id IS NULL
  DO UPDATE SET quantity = stock_quants.quantity + EXCLUDED.quantity, updated_at = now();

  -- Best-effort: keep products.stock_quantity mirror in sync for low_stock alerts
  UPDATE public.products
     SET stock_quantity = COALESCE(stock_quantity, 0) + v_qty_delta::int,
         updated_at = now()
   WHERE id = v_product_id AND track_inventory = true;

  -- Log a stock_move row for traceability
  BEGIN
    INSERT INTO public.stock_moves
      (product_id, source_location_id, destination_location_id, quantity, state, notes)
    SELECT
      v_product_id,
      CASE WHEN v_qty_delta < 0 THEN v_location_id ELSE (SELECT id FROM stock_locations WHERE code='WH/CUSTOMERS' LIMIT 1) END,
      CASE WHEN v_qty_delta > 0 THEN v_location_id ELSE (SELECT id FROM stock_locations WHERE code='WH/CUSTOMERS' LIMIT 1) END,
      abs(v_qty_delta), 'done', v_reason
    WHERE EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='public' AND table_name='stock_moves');
  EXCEPTION WHEN others THEN
    -- stock_moves shape may differ; don't fail the event apply
    NULL;
  END;
END;
$$;


ALTER FUNCTION "public"."apply_stock_movement_event"("p_payload" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."apply_stock_movement_event"("p_payload" "jsonb") IS 'Internal: applies a stock.movement event payload to stock_quants + products mirror. Called only by handle_stock_movement_event trigger.';



CREATE OR REPLACE FUNCTION "public"."approve_expense_report"("p_report_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_report record;
BEGIN
  SELECT * INTO v_report FROM expense_reports WHERE id = p_report_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Report not found');
  END IF;
  IF v_report.status <> 'submitted' THEN
    RETURN jsonb_build_object('success', false, 'error', 'Only submitted reports can be approved');
  END IF;

  UPDATE expense_reports
  SET status = 'approved', approved_at = now(), approved_by = auth.uid()
  WHERE id = p_report_id;

  RETURN jsonb_build_object('success', true, 'report_id', p_report_id, 'status', 'approved');
END;
$$;


ALTER FUNCTION "public"."approve_expense_report"("p_report_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."approve_payroll_run"("p_run_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_run public.payroll_runs%ROWTYPE;
  v_je_id UUID;
BEGIN
  IF NOT public.has_role(auth.uid(),'admin') THEN
    RAISE EXCEPTION 'Only admins can approve payroll';
  END IF;

  SELECT * INTO v_run FROM public.payroll_runs WHERE id=p_run_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Run not found'; END IF;
  IF v_run.status <> 'draft' THEN RAISE EXCEPTION 'Run already %', v_run.status; END IF;

  INSERT INTO public.journal_entries (entry_date, description, status, source_type, source_id)
  VALUES (v_run.period_date, 'Payroll run '||to_char(v_run.period_date,'YYYY-MM'), 'posted', 'payroll', v_run.id)
  RETURNING id INTO v_je_id;

  -- Dt 7210 (lön)
  IF v_run.total_gross_cents > 0 THEN
    INSERT INTO public.journal_entry_lines (journal_entry_id, account_code, debit_cents, credit_cents, description)
    VALUES (v_je_id, '7210', v_run.total_gross_cents, 0, 'Löner tjänstemän');
  END IF;
  -- Dt 7510 (arb.giv.avg)
  IF v_run.total_social_fee_cents > 0 THEN
    INSERT INTO public.journal_entry_lines (journal_entry_id, account_code, debit_cents, credit_cents, description)
    VALUES (v_je_id, '7510', v_run.total_social_fee_cents, 0, 'Arbetsgivaravgifter');
  END IF;
  -- Cr 2710 (personalskatt)
  IF v_run.total_tax_cents > 0 THEN
    INSERT INTO public.journal_entry_lines (journal_entry_id, account_code, debit_cents, credit_cents, description)
    VALUES (v_je_id, '2710', 0, v_run.total_tax_cents, 'Personalens källskatt');
  END IF;
  -- Cr 2731 (arb.giv.avg skuld)
  IF v_run.total_social_fee_cents > 0 THEN
    INSERT INTO public.journal_entry_lines (journal_entry_id, account_code, debit_cents, credit_cents, description)
    VALUES (v_je_id, '2731', 0, v_run.total_social_fee_cents, 'Avräkning lagstadgade sociala avgifter');
  END IF;
  -- Cr 2710 (nettolöneskuld) - using 2710 sub or 2890
  IF v_run.total_net_cents > 0 THEN
    INSERT INTO public.journal_entry_lines (journal_entry_id, account_code, debit_cents, credit_cents, description)
    VALUES (v_je_id, '2890', 0, v_run.total_net_cents, 'Nettolöneskuld');
  END IF;

  UPDATE public.payroll_runs
    SET status='approved', approved_at=now(), approval_journal_id=v_je_id
  WHERE id=p_run_id;

  RETURN jsonb_build_object('success',true,'run_id',p_run_id,'journal_entry_id',v_je_id);
END; $$;


ALTER FUNCTION "public"."approve_payroll_run"("p_run_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."approve_pending_operation"("p_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_op record;
BEGIN
  SELECT * INTO v_op FROM public.pending_operations WHERE id = p_id;
  IF v_op IS NULL THEN RETURN jsonb_build_object('error', 'pending operation not found'); END IF;
  IF v_op.status <> 'pending' THEN RETURN jsonb_build_object('error', 'operation already ' || v_op.status); END IF;
  UPDATE public.pending_operations SET status = 'approved', reviewed_by = auth.uid(), reviewed_at = now() WHERE id = p_id;
  RETURN jsonb_build_object('approved', true, 'id', p_id, 'skill_name', v_op.skill_name,
    'next', 'Re-invoke the skill with the same args plus _approved_operation_id="' || p_id || '" to execute.');
END; $$;


ALTER FUNCTION "public"."approve_pending_operation"("p_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."approve_procurement_suggestion"("p_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE s procurement_suggestions%ROWTYPE; v_po_id uuid; v_po_number text; v_unit_price integer; v_total integer; v_bom uuid; v_mo uuid;
BEGIN
  IF NOT has_role(auth.uid(),'admin'::app_role) THEN RAISE EXCEPTION 'Only admins can approve procurement suggestions'; END IF;
  SELECT * INTO s FROM procurement_suggestions WHERE id = p_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Suggestion not found'; END IF;
  IF s.status <> 'pending' THEN RAISE EXCEPTION 'Suggestion already %', s.status; END IF;
  IF s.procurement_method = 'buy' THEN
    IF s.preferred_vendor_id IS NULL THEN RAISE EXCEPTION 'No preferred vendor; cannot create PO'; END IF;
    v_po_number := 'PO-' || to_char(now(),'YYYYMMDD') || '-' || substr(gen_random_uuid()::text,1,6);
    SELECT COALESCE(price_cents,0) INTO v_unit_price FROM products WHERE id = s.product_id;
    v_total := COALESCE(v_unit_price,0) * s.suggested_qty::int;
    INSERT INTO purchase_orders (po_number, vendor_id, status, order_date, expected_delivery, subtotal_cents, total_cents, created_by)
    VALUES (v_po_number, s.preferred_vendor_id, 'draft', CURRENT_DATE, s.needed_by, v_total, v_total, auth.uid())
    RETURNING id INTO v_po_id;
    INSERT INTO purchase_order_lines (purchase_order_id, product_id, quantity, unit_price_cents, total_cents)
    VALUES (v_po_id, s.product_id, s.suggested_qty::int, COALESCE(v_unit_price,0), v_total);
    UPDATE procurement_suggestions SET status='materialized', resolved_at=now(), resolved_by=auth.uid(),
      materialized_ref_type='purchase_order', materialized_ref_id=v_po_id WHERE id=p_id;
    RETURN jsonb_build_object('type','purchase_order','id',v_po_id,'po_number',v_po_number);
  ELSIF s.procurement_method = 'manufacture' THEN
    SELECT id INTO v_bom FROM bom_headers WHERE product_id = s.product_id AND is_active = true LIMIT 1;
    IF v_bom IS NULL THEN RAISE EXCEPTION 'No active BOM for product %', s.product_id; END IF;
    v_mo := create_manufacturing_order(v_bom, s.suggested_qty::int, s.needed_by);
    UPDATE procurement_suggestions SET status='materialized', resolved_at=now(), resolved_by=auth.uid(),
      materialized_ref_type='manufacturing_order', materialized_ref_id=v_mo WHERE id=p_id;
    RETURN jsonb_build_object('type','manufacturing_order','id',v_mo);
  END IF;
  RAISE EXCEPTION 'Unknown procurement_method %', s.procurement_method;
END; $$;


ALTER FUNCTION "public"."approve_procurement_suggestion"("p_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."approve_return"("p_return_id" "uuid", "p_notes" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE public.returns
    SET status = 'approved', approved_by = auth.uid(), approved_at = now(),
        internal_notes = COALESCE(internal_notes || E'\n', '') || COALESCE(p_notes, '')
    WHERE id = p_return_id AND status = 'requested';
  IF NOT FOUND THEN RAISE EXCEPTION 'Return not found or not in requested state'; END IF;
  RETURN jsonb_build_object('success', true, 'return_id', p_return_id);
END; $$;


ALTER FUNCTION "public"."approve_return"("p_return_id" "uuid", "p_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."assign_voucher_number"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_series text; v_year int; v_next bigint;
BEGIN
  IF NEW.voucher_number IS NOT NULL AND NEW.voucher_series IS NOT NULL THEN RETURN NEW; END IF;
  v_year := EXTRACT(YEAR FROM NEW.entry_date)::int;
  NEW.voucher_year := v_year;
  IF NEW.voucher_series IS NULL THEN
    SELECT COALESCE(j.sequence_prefix, j.code, 'GEN') INTO v_series
      FROM public.journals j WHERE j.id = NEW.journal_id;
    NEW.voucher_series := COALESCE(v_series, 'GEN');
  END IF;
  IF NEW.voucher_number IS NULL THEN
    SELECT COALESCE(MAX(voucher_number), 0) + 1 INTO v_next
      FROM public.journal_entries
      WHERE voucher_series = NEW.voucher_series AND voucher_year = v_year;
    NEW.voucher_number := v_next;
  END IF;
  RETURN NEW;
END; $$;


ALTER FUNCTION "public"."assign_voucher_number"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."audit_logs_retention_status"() RETURNS "jsonb"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT jsonb_build_object(
    'retention_days', 730,
    'total_rows', (SELECT COUNT(*) FROM public.audit_logs),
    'pos_stock_rows', (SELECT COUNT(*) FROM public.audit_logs WHERE action IN ('pos.stock.decrement', 'pos.stock.increment')),
    'oldest_row_at', (SELECT MIN(created_at) FROM public.audit_logs),
    'newest_row_at', (SELECT MAX(created_at) FROM public.audit_logs),
    'rows_past_retention', (SELECT COUNT(*) FROM public.audit_logs WHERE created_at < now() - interval '730 days'),
    'cutoff_at', (now() - interval '730 days')
  );
$$;


ALTER FUNCTION "public"."audit_logs_retention_status"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_allocate_vacation"("p_year" integer, "p_dry_run" boolean DEFAULT false) RETURNS TABLE("employee_id" "uuid", "employee_name" "text", "allocated_days" integer, "carried_over_days" numeric, "action" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_emp RECORD;
  v_days INTEGER;
  v_max_carry INTEGER;
  v_prev_remaining NUMERIC;
  v_carry NUMERIC;
  v_existing UUID;
  v_action TEXT;
  v_run_id UUID := gen_random_uuid();
  v_total INTEGER := 0;
BEGIN
  IF NOT has_role(auth.uid(), 'admin'::app_role) THEN
    RAISE EXCEPTION 'Only admins can auto-allocate vacation';
  END IF;

  FOR v_emp IN
    SELECT id, name FROM public.employees WHERE status = 'active' ORDER BY name
  LOOP
    v_days := public.calculate_vacation_days(v_emp.id, p_year);

    SELECT max_carry_over_days INTO v_max_carry
    FROM public.vacation_policies
    WHERE is_active = true
    ORDER BY priority DESC LIMIT 1;
    v_max_carry := COALESCE(v_max_carry, 5);

    SELECT GREATEST(0,
      COALESCE(la.allocated_days, 0) + COALESCE(la.carried_over_days, 0)
      - COALESCE((
        SELECT SUM(days) FROM public.leave_requests
        WHERE employee_id = v_emp.id AND leave_type = 'vacation' AND status = 'approved'
          AND EXTRACT(YEAR FROM start_date)::INTEGER = p_year - 1
      ), 0)
    )
    INTO v_prev_remaining
    FROM public.leave_allocations la
    WHERE la.employee_id = v_emp.id AND la.leave_type = 'vacation' AND la.year = p_year - 1;

    v_carry := LEAST(COALESCE(v_prev_remaining, 0), v_max_carry);

    SELECT id INTO v_existing FROM public.leave_allocations
    WHERE employee_id = v_emp.id AND leave_type = 'vacation' AND year = p_year;

    v_action := CASE
      WHEN v_existing IS NOT NULL THEN (CASE WHEN p_dry_run THEN 'would_update' ELSE 'updated' END)
      ELSE (CASE WHEN p_dry_run THEN 'would_create' ELSE 'created' END)
    END;

    IF NOT p_dry_run THEN
      INSERT INTO public.leave_allocations (
        employee_id, leave_type, year, allocated_days, carried_over_days, notes
      ) VALUES (
        v_emp.id, 'vacation', p_year, v_days, v_carry,
        'Auto-allocated ' || to_char(now(), 'YYYY-MM-DD')
      )
      ON CONFLICT (employee_id, leave_type, year) DO UPDATE
      SET allocated_days = EXCLUDED.allocated_days,
          carried_over_days = EXCLUDED.carried_over_days,
          notes = EXCLUDED.notes,
          updated_at = now();

      INSERT INTO public.audit_logs (action, entity_type, entity_id, user_id, metadata)
      VALUES (
        'vacation.auto_allocated',
        'employee',
        v_emp.id,
        auth.uid(),
        jsonb_build_object(
          'run_id', v_run_id,
          'year', p_year,
          'employee_name', v_emp.name,
          'allocated_days', v_days,
          'carried_over_days', v_carry,
          'max_carry_over_cap', v_max_carry,
          'previous_year_remaining', v_prev_remaining,
          'action', v_action
        )
      );
      v_total := v_total + 1;
    END IF;

    employee_id := v_emp.id;
    employee_name := v_emp.name;
    allocated_days := v_days;
    carried_over_days := v_carry;
    action := v_action;
    RETURN NEXT;
  END LOOP;

  IF NOT p_dry_run AND v_total > 0 THEN
    INSERT INTO public.audit_logs (action, entity_type, user_id, metadata)
    VALUES (
      'vacation.auto_allocate_run',
      'leave_allocation',
      auth.uid(),
      jsonb_build_object('run_id', v_run_id, 'year', p_year, 'employees_processed', v_total)
    );
  END IF;
END;
$$;


ALTER FUNCTION "public"."auto_allocate_vacation"("p_year" integer, "p_dry_run" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_approve_vendor_invoice"("p_invoice_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_inv record;
BEGIN
  SELECT * INTO v_inv FROM vendor_invoices WHERE id = p_invoice_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Invoice % not found', p_invoice_id; END IF;

  IF v_inv.match_status <> 'matched' THEN
    RETURN jsonb_build_object(
      'success', false,
      'reason', format('Invoice match_status=%s, only "matched" can auto-approve', v_inv.match_status)
    );
  END IF;

  IF v_inv.approved_at IS NOT NULL THEN
    RETURN jsonb_build_object('success', true, 'already_approved', true);
  END IF;

  UPDATE vendor_invoices
    SET status = 'approved',
        approved_at = now(),
        approved_by = auth.uid(),
        updated_at = now()
    WHERE id = p_invoice_id;

  PERFORM public.emit_platform_event(
    'invoice.approved',
    jsonb_build_object('invoice_id', p_invoice_id, 'auto', true),
    'auto_approve_vendor_invoice'
  );

  RETURN jsonb_build_object('success', true, 'invoice_id', p_invoice_id, 'status', 'approved');
END;
$$;


ALTER FUNCTION "public"."auto_approve_vendor_invoice"("p_invoice_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_generate_purchase_orders"("p_dry_run" boolean DEFAULT false) RETURNS TABLE("po_id" "uuid", "po_number" "text", "vendor_id" "uuid", "vendor_name" "text", "line_count" integer, "total_cents" bigint, "status" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_vendor RECORD; v_line RECORD;
  v_po_id UUID; v_po_number TEXT;
  v_subtotal BIGINT; v_tax BIGINT;
  v_line_count INTEGER; v_skipped_count INTEGER;
BEGIN
  IF NOT (public.has_role(auth.uid(), 'admin'::public.app_role) OR public.has_role(auth.uid(), 'approver'::public.app_role)) THEN
    RAISE EXCEPTION 'Only admins/approvers can auto-generate purchase orders';
  END IF;

  SELECT COUNT(*) INTO v_skipped_count
  FROM public.list_reorder_candidates() c WHERE c.vendor_id IS NULL;

  IF v_skipped_count > 0 THEN
    po_id := NULL; po_number := NULL; vendor_id := NULL;
    vendor_name := v_skipped_count::TEXT || ' product(s) skipped — no preferred vendor';
    line_count := 0; total_cents := 0; status := 'skipped';
    RETURN NEXT;
  END IF;

  FOR v_vendor IN
    SELECT c.vendor_id AS v_id, MAX(c.vendor_name) AS v_name
    FROM public.list_reorder_candidates() c
    WHERE c.vendor_id IS NOT NULL
    GROUP BY c.vendor_id
  LOOP
    v_subtotal := 0; v_tax := 0; v_line_count := 0;

    IF NOT p_dry_run THEN
      INSERT INTO public.purchase_orders (vendor_id, status, order_date, notes, created_by)
      VALUES (v_vendor.v_id, 'draft', CURRENT_DATE,
              'Auto-generated by inventory reorder loop on ' || CURRENT_DATE, auth.uid())
      RETURNING id, purchase_orders.po_number INTO v_po_id, v_po_number;

      FOR v_line IN
        SELECT * FROM public.list_reorder_candidates() c WHERE c.vendor_id = v_vendor.v_id
      LOOP
        INSERT INTO public.purchase_order_lines (
          purchase_order_id, product_id, description, quantity, unit_price_cents, tax_rate, total_cents)
        VALUES (
          v_po_id, v_line.product_id, v_line.product_name,
          v_line.reorder_quantity, v_line.unit_price_cents, 25.00,
          v_line.reorder_quantity * v_line.unit_price_cents);
        v_subtotal := v_subtotal + v_line.estimated_cost_cents;
        v_line_count := v_line_count + 1;
      END LOOP;

      v_tax := ROUND(v_subtotal * 0.25);
      UPDATE public.purchase_orders
      SET subtotal_cents = v_subtotal, tax_cents = v_tax,
          total_cents = v_subtotal + v_tax, updated_at = now()
      WHERE id = v_po_id;
    ELSE
      v_po_id := NULL;
      v_po_number := '(dry-run)';
      SELECT COUNT(*), COALESCE(SUM(c.estimated_cost_cents), 0)
        INTO v_line_count, v_subtotal
      FROM public.list_reorder_candidates() c WHERE c.vendor_id = v_vendor.v_id;
      v_tax := ROUND(v_subtotal * 0.25);
    END IF;

    po_id := v_po_id;
    po_number := v_po_number;
    vendor_id := v_vendor.v_id;
    vendor_name := v_vendor.v_name;
    line_count := v_line_count;
    total_cents := v_subtotal + v_tax;
    status := CASE WHEN p_dry_run THEN 'preview' ELSE 'created' END;
    RETURN NEXT;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."auto_generate_purchase_orders"("p_dry_run" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_link_lead_to_company"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_domain text;
  v_company_id uuid;
BEGIN
  IF NEW.company_id IS NOT NULL OR NEW.email IS NULL THEN
    RETURN NEW;
  END IF;

  v_domain := lower(split_part(NEW.email, '@', 2));
  IF v_domain IS NULL OR v_domain = '' THEN
    RETURN NEW;
  END IF;

  SELECT id INTO v_company_id
  FROM public.companies
  WHERE lower(domain) = v_domain
  LIMIT 1;

  IF v_company_id IS NOT NULL THEN
    NEW.company_id := v_company_id;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."auto_link_lead_to_company"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."auto_mark_invoice_paid"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_invoice public.invoices;
  v_total_matched BIGINT;
  v_updated_count INT;
BEGIN
  IF NEW.entity_type <> 'invoice' OR NEW.entity_id IS NULL THEN RETURN NEW; END IF;
  SELECT * INTO v_invoice FROM public.invoices WHERE id = NEW.entity_id;
  IF v_invoice.id IS NULL OR v_invoice.status = 'paid' THEN RETURN NEW; END IF;

  SELECT COALESCE(SUM(ABS(amount_cents)), 0) INTO v_total_matched
  FROM public.reconciliation_matches
  WHERE entity_type = 'invoice' AND entity_id = NEW.entity_id;

  IF v_total_matched >= v_invoice.total_cents THEN
    UPDATE public.invoices
       SET status = 'paid',
           paid_at = now(),
           paid_amount_cents = v_total_matched,
           updated_at = now()
     WHERE id = NEW.entity_id AND status <> 'paid';

    GET DIAGNOSTICS v_updated_count = ROW_COUNT;

    IF v_updated_count > 0 THEN
      -- Fan out on the platform event bus so the accounting listener
      -- can post the journal entry (Dt 1930 / Cr 1510). Never hardcode
      -- bookkeeping into this trigger.
      PERFORM public.emit_platform_event(
        'invoice.paid',
        jsonb_build_object(
          'invoice_id', v_invoice.id,
          'invoice_number', v_invoice.invoice_number,
          'paid_amount_cents', v_total_matched,
          'total_cents', v_invoice.total_cents,
          'currency', v_invoice.currency,
          'source', 'auto_reconciliation',
          'reconciliation_match_id', NEW.id
        ),
        'trigger:auto_mark_invoice_paid'
      );
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."auto_mark_invoice_paid"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."award_rfq"("_rfq_id" "uuid", "_bid_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_bid public.rfq_bids%ROWTYPE;
  v_rfq public.rfqs%ROWTYPE;
  v_po_id uuid;
  v_line record;
  v_offer jsonb;
  v_unit_price int;
  v_total int := 0;
  v_subtotal int := 0;
BEGIN
  SELECT * INTO v_rfq FROM public.rfqs WHERE id = _rfq_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'RFQ % not found', _rfq_id; END IF;
  IF v_rfq.status = 'awarded' THEN RAISE EXCEPTION 'RFQ % already awarded', _rfq_id; END IF;

  SELECT * INTO v_bid FROM public.rfq_bids
    WHERE id = _bid_id AND rfq_id = _rfq_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Bid % not found for RFQ %', _bid_id, _rfq_id; END IF;

  -- Create draft PO
  INSERT INTO public.purchase_orders (vendor_id, currency, expected_delivery, notes, created_by)
  VALUES (
    v_bid.vendor_id,
    v_rfq.currency,
    v_rfq.expected_delivery,
    'Awarded from ' || v_rfq.rfq_number || ' — ' || COALESCE(v_rfq.title, ''),
    auth.uid()
  )
  RETURNING id INTO v_po_id;

  -- Create PO lines from RFQ lines using bid offer prices
  FOR v_line IN SELECT * FROM public.rfq_lines WHERE rfq_id = _rfq_id ORDER BY position LOOP
    SELECT elem INTO v_offer
      FROM jsonb_array_elements(v_bid.line_offers) elem
      WHERE elem->>'rfq_line_id' = v_line.id::text
      LIMIT 1;

    v_unit_price := COALESCE((v_offer->>'unit_price_cents')::int, 0);
    v_total := v_unit_price * v_line.quantity;
    v_subtotal := v_subtotal + v_total;

    INSERT INTO public.purchase_order_lines
      (purchase_order_id, product_id, description, quantity, unit_price_cents, total_cents)
    VALUES
      (v_po_id, v_line.product_id, v_line.description, v_line.quantity, v_unit_price, v_total);
  END LOOP;

  -- Update PO totals (25% VAT default — same convention as create_po)
  UPDATE public.purchase_orders
     SET subtotal_cents = v_subtotal,
         tax_cents = (v_subtotal * 0.25)::int,
         total_cents = v_subtotal + (v_subtotal * 0.25)::int
   WHERE id = v_po_id;

  -- Mark winning bid + close other bids + award RFQ
  UPDATE public.rfq_bids SET status = 'awarded' WHERE id = _bid_id;
  UPDATE public.rfq_bids SET status = 'rejected'
    WHERE rfq_id = _rfq_id AND id <> _bid_id AND status NOT IN ('withdrawn');

  UPDATE public.rfqs
     SET status = 'awarded',
         awarded_vendor_id = v_bid.vendor_id,
         awarded_po_id = v_po_id
   WHERE id = _rfq_id;

  RETURN v_po_id;
END;
$$;


ALTER FUNCTION "public"."award_rfq"("_rfq_id" "uuid", "_bid_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."book_expense_report"("p_report_id" "uuid", "p_expense_account" "text" DEFAULT '5410'::"text", "p_vat_account" "text" DEFAULT '2641'::"text", "p_liability_account" "text" DEFAULT '2890'::"text", "p_entry_date" "date" DEFAULT NULL::"date") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_report record;
  v_total_cents bigint;
  v_vat_cents bigint;
  v_net_cents bigint;
  v_entry_id uuid;
  v_date date;
BEGIN
  SELECT * INTO v_report FROM expense_reports WHERE id = p_report_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Report not found');
  END IF;
  IF v_report.status <> 'approved' THEN
    RETURN jsonb_build_object('success', false, 'error', 'Only approved reports can be booked');
  END IF;

  SELECT COALESCE(SUM(amount_cents),0), COALESCE(SUM(vat_cents),0)
  INTO v_total_cents, v_vat_cents
  FROM expenses WHERE report_id = p_report_id;

  v_net_cents := v_total_cents - v_vat_cents;
  v_date := COALESCE(p_entry_date, CURRENT_DATE);

  INSERT INTO journal_entries (entry_date, description, source, source_id, status)
  VALUES (v_date, 'Expense report ' || p_report_id::text, 'expense_report', p_report_id, 'posted')
  RETURNING id INTO v_entry_id;

  INSERT INTO journal_entry_lines (entry_id, account_code, debit_cents, credit_cents, description)
  VALUES
    (v_entry_id, p_expense_account, v_net_cents, 0, 'Expense (net)'),
    (v_entry_id, p_vat_account, v_vat_cents, 0, 'Input VAT'),
    (v_entry_id, p_liability_account, 0, v_total_cents, 'Liability to employee');

  UPDATE expense_reports
  SET status = 'booked', booked_at = now(), journal_entry_id = v_entry_id
  WHERE id = p_report_id;

  RETURN jsonb_build_object('success', true, 'report_id', p_report_id, 'journal_entry_id', v_entry_id, 'total_cents', v_total_cents);
END;
$$;


ALTER FUNCTION "public"."book_expense_report"("p_report_id" "uuid", "p_expense_account" "text", "p_vat_account" "text", "p_liability_account" "text", "p_entry_date" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."build_or_tsquery"("query_text" "text") RETURNS "tsquery"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public', 'extensions'
    AS $$
declare
  tokens text[];
  lex text;
  parts text[] := '{}';
begin
  if query_text is null or length(trim(query_text)) = 0 then
    return null;
  end if;
  tokens := regexp_split_to_array(lower(query_text), '[^a-zåäöéèüñ0-9]+');
  foreach lex in array tokens loop
    if length(lex) >= 2 then
      parts := parts || (quote_literal(lex) || ':*');
    end if;
  end loop;
  if array_length(parts, 1) is null then
    return null;
  end if;
  return to_tsquery('simple', array_to_string(parts, ' | '));
exception when others then
  return null;
end;
$$;


ALTER FUNCTION "public"."build_or_tsquery"("query_text" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."bulk_invoice_from_timesheets"("p_project_id" "uuid", "p_start_date" "date", "p_end_date" "date", "p_group_by" "text" DEFAULT 'entry'::"text", "p_due_days" integer DEFAULT 30) RETURNS TABLE("invoice_id" "uuid", "invoice_number" "text", "line_count" integer, "total_cents" bigint, "hours_billed" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_project public.projects;
  v_invoice_id UUID;
  v_invoice_num TEXT;
  v_line_items JSONB := '[]'::jsonb;
  v_subtotal BIGINT := 0;
  v_tax_rate NUMERIC := 0.25;
  v_tax_cents BIGINT;
  v_total_hours NUMERIC := 0;
  v_line_count INTEGER := 0;
  v_count INTEGER;
  v_entry RECORD;
  v_entry_ids UUID[] := '{}';
BEGIN
  IF NOT (public.has_role(auth.uid(), 'admin'::public.app_role) OR public.has_role(auth.uid(), 'approver'::public.app_role)) THEN
    RAISE EXCEPTION 'Only admins/approvers can bulk-invoice timesheets';
  END IF;

  SELECT * INTO v_project FROM public.projects WHERE id = p_project_id;
  IF v_project.id IS NULL THEN RAISE EXCEPTION 'Project not found'; END IF;
  IF NOT v_project.is_billable THEN RAISE EXCEPTION 'Project is not billable'; END IF;
  IF COALESCE(v_project.hourly_rate_cents, 0) <= 0 THEN RAISE EXCEPTION 'Project has no hourly rate set'; END IF;

  IF p_group_by = 'user' THEN
    FOR v_entry IN
      SELECT te.user_id, COALESCE(e.name, 'User') AS user_name, SUM(te.hours) AS total_hours, ARRAY_AGG(te.id) AS ids
      FROM public.time_entries te
      LEFT JOIN public.employees e ON e.user_id = te.user_id
      WHERE te.project_id = p_project_id AND te.entry_date BETWEEN p_start_date AND p_end_date
        AND te.is_billable = true AND te.is_invoiced = false
      GROUP BY te.user_id, e.name
    LOOP
      v_line_items := v_line_items || jsonb_build_object(
        'description', v_entry.user_name || ' — hours ' || to_char(p_start_date,'YYYY-MM-DD') || ' to ' || to_char(p_end_date,'YYYY-MM-DD'),
        'qty', v_entry.total_hours, 'unit_price_cents', v_project.hourly_rate_cents);
      v_subtotal := v_subtotal + ROUND(v_entry.total_hours * v_project.hourly_rate_cents);
      v_total_hours := v_total_hours + v_entry.total_hours;
      v_line_count := v_line_count + 1;
      v_entry_ids := v_entry_ids || v_entry.ids;
    END LOOP;
  ELSIF p_group_by = 'week' THEN
    FOR v_entry IN
      SELECT date_trunc('week', te.entry_date)::date AS week_start, SUM(te.hours) AS total_hours, ARRAY_AGG(te.id) AS ids
      FROM public.time_entries te
      WHERE te.project_id = p_project_id AND te.entry_date BETWEEN p_start_date AND p_end_date
        AND te.is_billable = true AND te.is_invoiced = false
      GROUP BY date_trunc('week', te.entry_date) ORDER BY week_start
    LOOP
      v_line_items := v_line_items || jsonb_build_object(
        'description', 'Week of ' || to_char(v_entry.week_start, 'YYYY-MM-DD'),
        'qty', v_entry.total_hours, 'unit_price_cents', v_project.hourly_rate_cents);
      v_subtotal := v_subtotal + ROUND(v_entry.total_hours * v_project.hourly_rate_cents);
      v_total_hours := v_total_hours + v_entry.total_hours;
      v_line_count := v_line_count + 1;
      v_entry_ids := v_entry_ids || v_entry.ids;
    END LOOP;
  ELSE
    FOR v_entry IN
      SELECT te.id, te.entry_date, te.hours, te.description
      FROM public.time_entries te
      WHERE te.project_id = p_project_id AND te.entry_date BETWEEN p_start_date AND p_end_date
        AND te.is_billable = true AND te.is_invoiced = false
      ORDER BY te.entry_date
    LOOP
      v_line_items := v_line_items || jsonb_build_object(
        'description', to_char(v_entry.entry_date,'YYYY-MM-DD') || ' — ' || COALESCE(v_entry.description, 'Hours'),
        'qty', v_entry.hours, 'unit_price_cents', v_project.hourly_rate_cents);
      v_subtotal := v_subtotal + ROUND(v_entry.hours * v_project.hourly_rate_cents);
      v_total_hours := v_total_hours + v_entry.hours;
      v_line_count := v_line_count + 1;
      v_entry_ids := v_entry_ids || v_entry.id;
    END LOOP;
  END IF;

  IF v_line_count = 0 THEN
    RAISE EXCEPTION 'No billable, uninvoiced hours found for project in given period';
  END IF;

  v_tax_cents := ROUND(v_subtotal * v_tax_rate);
  SELECT COUNT(*) INTO v_count FROM public.invoices;
  v_invoice_num := 'INV-' || LPAD((v_count + 1)::TEXT, 5, '0');

  INSERT INTO public.invoices (
    invoice_number, customer_name, project_id, line_items,
    subtotal_cents, tax_rate, tax_cents, total_cents,
    currency, issue_date, due_date, status, created_by, notes)
  VALUES (
    v_invoice_num, COALESCE(v_project.client_name, v_project.name), p_project_id, v_line_items,
    v_subtotal, v_tax_rate, v_tax_cents, v_subtotal + v_tax_cents,
    v_project.currency, CURRENT_DATE, CURRENT_DATE + p_due_days, 'draft', auth.uid(),
    'Auto-generated from timesheets ' || p_start_date || ' → ' || p_end_date)
  RETURNING id INTO v_invoice_id;

  UPDATE public.time_entries
  SET is_invoiced = true, invoice_id = v_invoice_id, updated_at = now()
  WHERE id = ANY(v_entry_ids);

  invoice_id := v_invoice_id;
  invoice_number := v_invoice_num;
  line_count := v_line_count;
  total_cents := v_subtotal + v_tax_cents;
  hours_billed := v_total_hours;
  RETURN NEXT;
END;
$$;


ALTER FUNCTION "public"."bulk_invoice_from_timesheets"("p_project_id" "uuid", "p_start_date" "date", "p_end_date" "date", "p_group_by" "text", "p_due_days" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."bump_kb_article_feedback"("p_slugs" "text"[], "p_rating" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_slug text;
  v_updated int := 0;
BEGIN
  IF p_rating NOT IN ('positive', 'negative') THEN
    RAISE EXCEPTION 'rating must be positive or negative';
  END IF;

  FOREACH v_slug IN ARRAY p_slugs LOOP
    UPDATE public.kb_articles
    SET
      positive_feedback_count = coalesce(positive_feedback_count, 0)
        + CASE WHEN p_rating = 'positive' THEN 1 ELSE 0 END,
      negative_feedback_count = coalesce(negative_feedback_count, 0)
        + CASE WHEN p_rating = 'negative' THEN 1 ELSE 0 END,
      needs_improvement = (
        (coalesce(negative_feedback_count, 0) + CASE WHEN p_rating = 'negative' THEN 1 ELSE 0 END) >= 3
        OR (
          (coalesce(positive_feedback_count, 0) + coalesce(negative_feedback_count, 0)
            + CASE WHEN p_rating IN ('positive','negative') THEN 1 ELSE 0 END) >= 5
          AND
          (coalesce(negative_feedback_count, 0) + CASE WHEN p_rating = 'negative' THEN 1 ELSE 0 END)::numeric
          / NULLIF(
              (coalesce(positive_feedback_count, 0) + coalesce(negative_feedback_count, 0)
                + CASE WHEN p_rating IN ('positive','negative') THEN 1 ELSE 0 END), 0
            ) > 0.3
        )
      )
    WHERE slug = v_slug;
    IF FOUND THEN v_updated := v_updated + 1; END IF;
  END LOOP;

  RETURN jsonb_build_object('success', true, 'updated', v_updated);
END;
$$;


ALTER FUNCTION "public"."bump_kb_article_feedback"("p_slugs" "text"[], "p_rating" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."bump_template_usage"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.template_id IS NOT NULL AND (TG_OP = 'INSERT' OR OLD.template_id IS DISTINCT FROM NEW.template_id) THEN
    UPDATE public.accounting_templates
       SET usage_count = usage_count + 1,
           updated_at = now()
     WHERE id = NEW.template_id;

    -- Remember the last-used template on the vendor for next-time autokontering
    IF NEW.vendor_id IS NOT NULL THEN
      UPDATE public.vendors
         SET last_used_template_id = NEW.template_id,
             updated_at = now()
       WHERE id = NEW.vendor_id;
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."bump_template_usage"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."calculate_vacation_days"("p_employee_id" "uuid", "p_year" integer) RETURNS integer
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_emp RECORD;
  v_age INTEGER;
  v_tenure_years INTEGER;
  v_days INTEGER;
BEGIN
  SELECT birth_date, start_date INTO v_emp
  FROM public.employees WHERE id = p_employee_id;

  IF v_emp IS NULL THEN RETURN 25; END IF;

  v_age := CASE
    WHEN v_emp.birth_date IS NULL THEN 0
    ELSE EXTRACT(YEAR FROM age(make_date(p_year, 12, 31), v_emp.birth_date))::INTEGER
  END;

  v_tenure_years := CASE
    WHEN v_emp.start_date IS NULL THEN 0
    ELSE GREATEST(0, p_year - EXTRACT(YEAR FROM v_emp.start_date)::INTEGER)
  END;

  -- Pick best matching policy (highest priority that the employee qualifies for)
  SELECT vacation_days INTO v_days
  FROM public.vacation_policies
  WHERE is_active = true
    AND v_age >= min_age
    AND v_tenure_years >= min_tenure_years
  ORDER BY priority DESC, vacation_days DESC
  LIMIT 1;

  RETURN COALESCE(v_days, 25);
END;
$$;


ALTER FUNCTION "public"."calculate_vacation_days"("p_employee_id" "uuid", "p_year" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."calculate_vat_report"("p_year" integer, "p_start_month" integer, "p_end_month" integer DEFAULT NULL::integer) RETURNS TABLE("grid_code" "text", "grid_name" "text", "category" "text", "amount_cents" bigint)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  WITH period AS (
    SELECT make_date(p_year, p_start_month, 1) AS start_date,
           (make_date(p_year, COALESCE(p_end_month, p_start_month), 1)
              + INTERVAL '1 month' - INTERVAL '1 day')::date AS end_date
  )
  SELECT
    g.code,
    g.name,
    g.category,
    COALESCE(SUM(jelt.amount_cents), 0)::BIGINT
  FROM public.tax_grids g
  LEFT JOIN public.journal_entry_line_taxes jelt ON jelt.tax_grid_id = g.id
  LEFT JOIN public.journal_entry_lines jel ON jel.id = jelt.journal_entry_line_id
  LEFT JOIN public.journal_entries je ON je.id = jel.journal_entry_id
  CROSS JOIN period
  WHERE g.locale = 'SE'
    AND g.is_active = true
    AND (je.id IS NULL OR (
      je.status = 'posted'
      AND je.entry_date BETWEEN period.start_date AND period.end_date
    ))
  GROUP BY g.code, g.name, g.category, g.sequence
  ORDER BY g.sequence;
$$;


ALTER FUNCTION "public"."calculate_vat_report"("p_year" integer, "p_start_month" integer, "p_end_month" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cancel_manual_subscription"("_subscription_id" "uuid", "_reason" "text" DEFAULT NULL::"text", "_effective_date" "date" DEFAULT NULL::"date") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  _eff date := COALESCE(_effective_date, CURRENT_DATE);
BEGIN
  IF NOT has_role(auth.uid(), 'admin'::app_role) THEN
    RAISE EXCEPTION 'Only admins can cancel manual subscriptions';
  END IF;

  UPDATE public.subscriptions
  SET status = 'canceled'::subscription_status,
      canceled_at = now(),
      ended_at = _eff::timestamptz,
      cancel_at = _eff::timestamptz,
      next_invoice_date = NULL,
      metadata = metadata || jsonb_build_object('cancel_reason', _reason, 'canceled_by', auth.uid()),
      updated_at = now()
  WHERE id = _subscription_id AND provider = 'manual';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Manual subscription % not found', _subscription_id;
  END IF;

  PERFORM public.emit_platform_event(
    'subscription.canceled',
    jsonb_build_object('subscription_id', _subscription_id, 'reason', _reason, 'effective_date', _eff),
    'cancel_manual_subscription'
  );

  RETURN jsonb_build_object('ok', true, 'subscription_id', _subscription_id, 'effective_date', _eff);
END $$;


ALTER FUNCTION "public"."cancel_manual_subscription"("_subscription_id" "uuid", "_reason" "text", "_effective_date" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cancel_mo"("p_mo_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_status public.mo_status;
BEGIN
  IF NOT (public.has_role(auth.uid(), 'writer') OR public.has_role(auth.uid(), 'admin')) THEN
    RAISE EXCEPTION 'Permission denied';
  END IF;

  SELECT status INTO v_status FROM public.manufacturing_orders WHERE id = p_mo_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'MO % not found', p_mo_id; END IF;

  IF v_status IN ('done', 'cancelled') THEN
    RETURN jsonb_build_object('success', true, 'mo_id', p_mo_id, 'note', 'already terminal: ' || v_status);
  END IF;

  UPDATE public.manufacturing_orders
     SET status = 'cancelled',
         cancelled_at = now(),
         notes = COALESCE(notes, '') || E'\n[cancelled] ' || COALESCE(p_reason, 'no reason'),
         updated_at = now()
   WHERE id = p_mo_id;

  BEGIN
    PERFORM public.emit_platform_event(
      'mo.cancelled',
      jsonb_build_object('mo_id', p_mo_id, 'reason', p_reason),
      'manufacturing'
    );
  EXCEPTION WHEN undefined_function THEN NULL; END;

  RETURN jsonb_build_object('success', true, 'mo_id', p_mo_id, 'status', 'cancelled');
END;
$$;


ALTER FUNCTION "public"."cancel_mo"("p_mo_id" "uuid", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cancel_picking"("p_picking_order_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_line RECORD;
BEGIN
  IF NOT (public.has_role(auth.uid(), 'admin') OR public.has_role(auth.uid(), 'employee')) THEN
    RAISE EXCEPTION 'Insufficient permissions';
  END IF;

  -- Release reservations
  FOR v_line IN SELECT * FROM public.picking_lines WHERE picking_order_id = p_picking_order_id AND reservation_id IS NOT NULL LOOP
    BEGIN
      PERFORM public.cancel_reservation(v_line.reservation_id);
    EXCEPTION WHEN OTHERS THEN NULL; END;
  END LOOP;

  UPDATE public.picking_lines
  SET status = 'cancelled'
  WHERE picking_order_id = p_picking_order_id AND status NOT IN ('picked','cancelled');

  UPDATE public.picking_orders
  SET status = 'cancelled', cancelled_at = now(), cancel_reason = p_reason
  WHERE id = p_picking_order_id;

  INSERT INTO public.audit_logs (action, entity_type, entity_id, user_id, metadata)
  VALUES ('picking.cancelled', 'picking_order', p_picking_order_id, auth.uid(),
    jsonb_build_object('reason', p_reason));

  RETURN jsonb_build_object('success', true, 'picking_order_id', p_picking_order_id);
END;
$$;


ALTER FUNCTION "public"."cancel_picking"("p_picking_order_id" "uuid", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cancel_reservation"("p_reservation_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE r stock_reservations%ROWTYPE;
BEGIN
  IF NOT (has_role(auth.uid(),'writer'::app_role) OR has_role(auth.uid(),'admin'::app_role)) THEN RAISE EXCEPTION 'Insufficient privileges'; END IF;
  SELECT * INTO r FROM stock_reservations WHERE id = p_reservation_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Reservation not found'; END IF;
  IF r.state <> 'reserved' THEN RAISE EXCEPTION 'Reservation not in reserved state (%)', r.state; END IF;
  UPDATE stock_reservations SET state='cancelled', cancelled_at=now() WHERE id=p_reservation_id;
  UPDATE stock_quants SET reserved_quantity = GREATEST(0, COALESCE(reserved_quantity,0) - r.quantity), updated_at = now()
    WHERE product_id = r.product_id AND location_id = r.location_id AND (lot_id IS NOT DISTINCT FROM r.lot_id);
END; $$;


ALTER FUNCTION "public"."cancel_reservation"("p_reservation_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."cancel_webinar"("p_webinar_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_row webinars%ROWTYPE;
BEGIN
  IF NOT (has_role(auth.uid(),'writer') OR has_role(auth.uid(),'approver') OR has_role(auth.uid(),'admin')) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  UPDATE webinars SET status='cancelled', updated_at=now() WHERE id=p_webinar_id AND status NOT IN ('completed','cancelled') RETURNING * INTO v_row;
  IF NOT FOUND THEN RAISE EXCEPTION 'webinar % cannot be cancelled', p_webinar_id; END IF;
  PERFORM emit_platform_event('webinar.cancelled', jsonb_build_object('webinar_id',v_row.id,'title',v_row.title,'reason',p_reason), 'webinars');
  RETURN jsonb_build_object('success',true,'id',v_row.id,'status',v_row.status);
END $$;


ALTER FUNCTION "public"."cancel_webinar"("p_webinar_id" "uuid", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."categorize_nps_response"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.score IS NOT NULL THEN
    NEW.category := CASE
      WHEN NEW.score <= 6 THEN 'detractor'
      WHEN NEW.score <= 8 THEN 'passive'
      ELSE 'promoter'
    END;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."categorize_nps_response"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."check_mo_availability"("p_mo_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_shortages jsonb := '[]'::jsonb;
  v_overall   text := 'ok';
BEGIN
  -- Update per-row availability based on current stock
  WITH stock AS (
    SELECT product_id, COALESCE(quantity_on_hand, 0) AS qty FROM public.product_stock
  ), updated AS (
    UPDATE public.mo_components mc
       SET availability = CASE
                            WHEN COALESCE(s.qty, 0) >= mc.qty_required THEN 'ok'
                            ELSE 'short'
                          END
      FROM (SELECT mc2.id, COALESCE(st.qty, 0) AS qty
              FROM public.mo_components mc2
              LEFT JOIN stock st ON st.product_id = mc2.component_product_id
             WHERE mc2.mo_id = p_mo_id) s
     WHERE mc.id = s.id
     RETURNING mc.component_product_id, mc.qty_required, mc.availability, s.qty AS on_hand
  )
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
           'component_product_id', component_product_id,
           'qty_required', qty_required,
           'qty_on_hand', on_hand,
           'qty_short', GREATEST(qty_required - on_hand, 0)
         )), '[]'::jsonb)
    INTO v_shortages
    FROM updated WHERE availability = 'short';

  IF jsonb_array_length(v_shortages) > 0 THEN v_overall := 'short'; END IF;

  -- Emit shortage event
  IF v_overall = 'short' THEN
    BEGIN
      PERFORM public.emit_platform_event(
        'mo.shortage_detected',
        jsonb_build_object('mo_id', p_mo_id, 'components', v_shortages),
        'manufacturing'
      );
    EXCEPTION WHEN undefined_function THEN NULL; END;
  END IF;

  RETURN jsonb_build_object('mo_id', p_mo_id, 'overall', v_overall, 'shortages', v_shortages);
END;
$$;


ALTER FUNCTION "public"."check_mo_availability"("p_mo_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."checkout_objective"("p_objective_id" "uuid", "p_locked_by" "text" DEFAULT 'heartbeat'::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE rows_affected integer;
BEGIN
  UPDATE agent_objectives SET locked_by = p_locked_by, locked_at = now()
  WHERE id = p_objective_id AND (locked_by IS NULL OR locked_at < now() - interval '30 minutes');
  GET DIAGNOSTICS rows_affected = ROW_COUNT;
  RETURN rows_affected > 0;
END; $$;


ALTER FUNCTION "public"."checkout_objective"("p_objective_id" "uuid", "p_locked_by" "text") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."attendance_entries" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "employee_id" "uuid" NOT NULL,
    "clock_in" timestamp with time zone NOT NULL,
    "clock_out" timestamp with time zone,
    "break_minutes" integer DEFAULT 0 NOT NULL,
    "total_minutes" integer GENERATED ALWAYS AS (
CASE
    WHEN ("clock_out" IS NULL) THEN NULL::integer
    ELSE GREATEST(0, (((EXTRACT(epoch FROM ("clock_out" - "clock_in")))::integer / 60) - "break_minutes"))
END) STORED,
    "notes" "text",
    "source" "text" DEFAULT 'manual'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


ALTER TABLE "public"."attendance_entries" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."clock_in"("p_employee_id" "uuid" DEFAULT NULL::"uuid") RETURNS "public"."attendance_entries"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_emp_id UUID;
  v_row public.attendance_entries;
BEGIN
  IF auth.uid() IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF;

  IF p_employee_id IS NOT NULL THEN
    IF NOT has_role(auth.uid(), 'admin'::app_role) THEN
      RAISE EXCEPTION 'Only admins can clock in for others';
    END IF;
    v_emp_id := p_employee_id;
  ELSE
    SELECT id INTO v_emp_id FROM public.employees WHERE user_id = auth.uid() LIMIT 1;
    IF v_emp_id IS NULL THEN RAISE EXCEPTION 'No employee record found for current user'; END IF;
  END IF;

  IF EXISTS (SELECT 1 FROM public.attendance_entries WHERE employee_id = v_emp_id AND clock_out IS NULL) THEN
    RAISE EXCEPTION 'Already clocked in — please clock out first';
  END IF;

  INSERT INTO public.attendance_entries (employee_id, clock_in, source)
  VALUES (v_emp_id, now(), 'self')
  RETURNING * INTO v_row;
  RETURN v_row;
END;
$$;


ALTER FUNCTION "public"."clock_in"("p_employee_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."clock_out"("p_break_minutes" integer DEFAULT 0, "p_notes" "text" DEFAULT NULL::"text", "p_employee_id" "uuid" DEFAULT NULL::"uuid") RETURNS "public"."attendance_entries"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_emp_id UUID;
  v_row public.attendance_entries;
BEGIN
  IF auth.uid() IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF;

  IF p_employee_id IS NOT NULL THEN
    IF NOT has_role(auth.uid(), 'admin'::app_role) THEN RAISE EXCEPTION 'Only admins can clock out for others'; END IF;
    v_emp_id := p_employee_id;
  ELSE
    SELECT id INTO v_emp_id FROM public.employees WHERE user_id = auth.uid() LIMIT 1;
    IF v_emp_id IS NULL THEN RAISE EXCEPTION 'No employee record found'; END IF;
  END IF;

  UPDATE public.attendance_entries
  SET clock_out = now(),
      break_minutes = COALESCE(p_break_minutes, 0),
      notes = COALESCE(p_notes, notes)
  WHERE employee_id = v_emp_id AND clock_out IS NULL
  RETURNING * INTO v_row;

  IF v_row.id IS NULL THEN RAISE EXCEPTION 'No open clock-in found'; END IF;
  RETURN v_row;
END;
$$;


ALTER FUNCTION "public"."clock_out"("p_break_minutes" integer, "p_notes" "text", "p_employee_id" "uuid") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."accounting_periods" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "fiscal_year" integer NOT NULL,
    "period_month" integer NOT NULL,
    "status" "public"."accounting_period_status" DEFAULT 'open'::"public"."accounting_period_status" NOT NULL,
    "closed_by" "uuid",
    "closed_at" timestamp with time zone,
    "reopened_by" "uuid",
    "reopened_at" timestamp with time zone,
    "total_debit_cents" bigint,
    "total_credit_cents" bigint,
    "entry_count" integer,
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "accounting_periods_period_month_check" CHECK ((("period_month" >= 1) AND ("period_month" <= 12)))
);


ALTER TABLE "public"."accounting_periods" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."close_accounting_period"("p_year" integer, "p_month" integer, "p_notes" "text" DEFAULT NULL::"text") RETURNS "public"."accounting_periods"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_row public.accounting_periods;
  v_start DATE;
  v_end DATE;
  v_total_debit BIGINT;
  v_total_credit BIGINT;
  v_count INTEGER;
  v_unposted INTEGER;
BEGIN
  IF NOT public.has_role(auth.uid(), 'admin'::public.app_role) THEN
    RAISE EXCEPTION 'Only admins can close accounting periods';
  END IF;

  IF p_month NOT BETWEEN 1 AND 12 THEN
    RAISE EXCEPTION 'Invalid month: %', p_month;
  END IF;

  v_start := make_date(p_year, p_month, 1);
  v_end := (v_start + INTERVAL '1 month' - INTERVAL '1 day')::DATE;

  -- Block close if any draft entries remain
  SELECT COUNT(*) INTO v_unposted
  FROM public.journal_entries
  WHERE entry_date BETWEEN v_start AND v_end
    AND status <> 'posted';
  IF v_unposted > 0 THEN
    RAISE EXCEPTION 'Cannot close: % unposted journal entries in %-%', v_unposted, p_year, p_month;
  END IF;

  -- Aggregate snapshot
  SELECT COALESCE(SUM(jel.debit_cents), 0),
         COALESCE(SUM(jel.credit_cents), 0),
         COUNT(DISTINCT je.id)
  INTO v_total_debit, v_total_credit, v_count
  FROM public.journal_entries je
  LEFT JOIN public.journal_entry_lines jel ON jel.journal_entry_id = je.id
  WHERE je.entry_date BETWEEN v_start AND v_end;

  -- Upsert
  INSERT INTO public.accounting_periods (
    fiscal_year, period_month, status,
    closed_by, closed_at,
    total_debit_cents, total_credit_cents, entry_count, notes
  )
  VALUES (
    p_year, p_month, 'closed',
    auth.uid(), now(),
    v_total_debit, v_total_credit, v_count, p_notes
  )
  ON CONFLICT (fiscal_year, period_month) DO UPDATE
  SET status = 'closed',
      closed_by = auth.uid(),
      closed_at = now(),
      reopened_by = NULL,
      reopened_at = NULL,
      total_debit_cents = EXCLUDED.total_debit_cents,
      total_credit_cents = EXCLUDED.total_credit_cents,
      entry_count = EXCLUDED.entry_count,
      notes = COALESCE(EXCLUDED.notes, public.accounting_periods.notes),
      updated_at = now()
  WHERE public.accounting_periods.status <> 'locked'
  RETURNING * INTO v_row;

  IF v_row.id IS NULL THEN
    RAISE EXCEPTION 'Period %-% is locked and cannot be closed again', p_year, p_month;
  END IF;

  RETURN v_row;
END;
$$;


ALTER FUNCTION "public"."close_accounting_period"("p_year" integer, "p_month" integer, "p_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."close_pos_session"("p_session_id" "uuid", "p_closing_cash_cents" integer) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_expected integer;
  v_session record;
BEGIN
  SELECT * INTO v_session FROM public.pos_sessions WHERE id = p_session_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Session not found'; END IF;
  IF v_session.status = 'closed' THEN RAISE EXCEPTION 'Session already closed'; END IF;

  -- Expected = opening + sum of cash sales in this session
  SELECT COALESCE(v_session.opening_cash_cents, 0) + COALESCE(SUM(total_cents), 0)
    INTO v_expected
  FROM public.pos_sales
  WHERE session_id = p_session_id AND status = 'completed' AND payment_method = 'cash';

  UPDATE public.pos_sessions
    SET status = 'closed',
        closing_cash_cents = p_closing_cash_cents,
        expected_cash_cents = v_expected,
        cash_variance_cents = p_closing_cash_cents - v_expected,
        closed_at = now()
    WHERE id = p_session_id;

  RETURN jsonb_build_object(
    'session_id', p_session_id,
    'expected_cash_cents', v_expected,
    'closing_cash_cents', p_closing_cash_cents,
    'variance_cents', p_closing_cash_cents - v_expected
  );
END;
$$;


ALTER FUNCTION "public"."close_pos_session"("p_session_id" "uuid", "p_closing_cash_cents" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."close_pos_session_v2"("p_session_id" "uuid", "p_closing_cash_cents" integer, "p_notes" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_session record;
  v_register record;
  v_payments_by_method jsonb;
  v_total_sales integer;
  v_total_tax integer;
  v_expected_cash integer;
  v_variance integer;
  v_z_report jsonb;
BEGIN
  SELECT * INTO v_session FROM public.pos_sessions WHERE id = p_session_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Session % not found', p_session_id;
  END IF;
  IF v_session.status <> 'open' THEN
    RAISE EXCEPTION 'Session % is not open', p_session_id;
  END IF;

  SELECT * INTO v_register FROM public.pos_registers WHERE id = v_session.register_id;

  -- Aggregate payments by method
  SELECT jsonb_object_agg(method, amt) INTO v_payments_by_method
  FROM (
    SELECT pp.method, COALESCE(SUM(pp.amount_cents), 0) AS amt
      FROM public.pos_payments pp
      JOIN public.pos_sales ps ON ps.id = pp.sale_id
     WHERE ps.session_id = p_session_id AND ps.status = 'completed'
     GROUP BY pp.method
  ) t;

  -- Aggregate totals
  SELECT COALESCE(SUM(total_cents), 0), COALESCE(SUM(tax_cents), 0)
    INTO v_total_sales, v_total_tax
    FROM public.pos_sales
   WHERE session_id = p_session_id AND status = 'completed';

  v_expected_cash := v_session.opening_cash_cents
    + COALESCE((v_payments_by_method->>'cash')::integer, 0);
  v_variance := p_closing_cash_cents - v_expected_cash;

  -- Build Z-report
  v_z_report := jsonb_build_object(
    'session_id', p_session_id,
    'register', v_register.name,
    'cashier', v_session.cashier_name,
    'opened_at', v_session.opened_at,
    'closed_at', now(),
    'opening_cash_cents', v_session.opening_cash_cents,
    'closing_cash_cents', p_closing_cash_cents,
    'expected_cash_cents', v_expected_cash,
    'cash_variance_cents', v_variance,
    'sales_count', v_session.sales_count,
    'total_sales_cents', v_total_sales,
    'total_tax_cents', v_total_tax,
    'payments_by_method', COALESCE(v_payments_by_method, '{}'::jsonb),
    'currency', v_register.currency
  );

  -- Update session
  UPDATE public.pos_sessions
     SET status = 'closed',
         closed_at = now(),
         closing_cash_cents = p_closing_cash_cents,
         expected_cash_cents = v_expected_cash,
         cash_variance_cents = v_variance,
         notes = COALESCE(p_notes, notes),
         metadata = COALESCE(metadata, '{}'::jsonb) || jsonb_build_object('z_report', v_z_report)
   WHERE id = p_session_id;

  -- Emit event for accounting / FlowPilot to pick up and post journal
  PERFORM public.emit_platform_event(
    'pos.session.closed',
    v_z_report,
    'pos'
  );

  RETURN v_z_report;
END;
$$;


ALTER FUNCTION "public"."close_pos_session_v2"("p_session_id" "uuid", "p_closing_cash_cents" integer, "p_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."complete_mo"("p_mo_id" "uuid", "p_actual_qty" numeric DEFAULT NULL::numeric) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_mo         public.manufacturing_orders%ROWTYPE;
  v_qty        numeric;
  v_consumed   int := 0;
  v_comp       record;
BEGIN
  IF NOT (public.has_role(auth.uid(), 'writer') OR public.has_role(auth.uid(), 'admin')) THEN
    RAISE EXCEPTION 'Permission denied';
  END IF;

  SELECT * INTO v_mo FROM public.manufacturing_orders WHERE id = p_mo_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'MO % not found', p_mo_id; END IF;

  IF v_mo.status = 'done' THEN
    RETURN jsonb_build_object('success', true, 'mo_id', p_mo_id, 'note', 'already done');
  END IF;
  IF v_mo.status <> 'in_progress' THEN
    RAISE EXCEPTION 'MO must be in_progress to complete (current: %)', v_mo.status;
  END IF;

  v_qty := COALESCE(p_actual_qty, v_mo.quantity);

  -- Consume components: post negative stock_moves and decrement product_stock
  FOR v_comp IN SELECT component_product_id, qty_required FROM public.mo_components WHERE mo_id = p_mo_id
  LOOP
    INSERT INTO public.stock_moves (product_id, quantity, move_type, reference_type, reference_id, mo_id, created_by, notes)
    VALUES (v_comp.component_product_id, -CEIL(v_comp.qty_required)::int, 'mo_consumption',
            'manufacturing_order', p_mo_id::text, p_mo_id, auth.uid(),
            'Consumed for MO ' || v_mo.mo_number);

    UPDATE public.product_stock
       SET quantity_on_hand = GREATEST(quantity_on_hand - CEIL(v_comp.qty_required)::int, 0),
           updated_at = now()
     WHERE product_id = v_comp.component_product_id;

    UPDATE public.mo_components SET qty_consumed = v_comp.qty_required
     WHERE mo_id = p_mo_id AND component_product_id = v_comp.component_product_id;

    v_consumed := v_consumed + 1;
  END LOOP;

  -- Produce finished good
  INSERT INTO public.stock_moves (product_id, quantity, move_type, reference_type, reference_id, mo_id, created_by, notes)
  VALUES (v_mo.product_id, CEIL(v_qty)::int, 'mo_production',
          'manufacturing_order', p_mo_id::text, p_mo_id, auth.uid(),
          'Produced by MO ' || v_mo.mo_number);

  INSERT INTO public.product_stock (product_id, quantity_on_hand)
  VALUES (v_mo.product_id, CEIL(v_qty)::int)
  ON CONFLICT (product_id) DO UPDATE
    SET quantity_on_hand = public.product_stock.quantity_on_hand + EXCLUDED.quantity_on_hand,
        updated_at = now();

  UPDATE public.manufacturing_orders
     SET status = 'done', completed_at = now(), updated_at = now()
   WHERE id = p_mo_id;

  -- Emit event
  BEGIN
    PERFORM public.emit_platform_event(
      'mo.completed',
      jsonb_build_object('mo_id', p_mo_id, 'qty_produced', v_qty, 'components_consumed', v_consumed),
      'manufacturing'
    );
  EXCEPTION WHEN undefined_function THEN NULL; END;

  RETURN jsonb_build_object('success', true, 'mo_id', p_mo_id, 'qty_produced', v_qty, 'components_consumed', v_consumed);
END;
$$;


ALTER FUNCTION "public"."complete_mo"("p_mo_id" "uuid", "p_actual_qty" numeric) OWNER TO "postgres";


