CREATE TABLE IF NOT EXISTS "public"."fixed_assets" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "name" "text" NOT NULL,
    "description" "text",
    "asset_account" "text" DEFAULT '1210'::"text" NOT NULL,
    "depreciation_account" "text" DEFAULT '7832'::"text" NOT NULL,
    "accumulated_account" "text" DEFAULT '1219'::"text" NOT NULL,
    "cost_cents" bigint NOT NULL,
    "salvage_cents" bigint DEFAULT 0 NOT NULL,
    "purchase_date" "date" DEFAULT CURRENT_DATE NOT NULL,
    "in_service_date" "date" DEFAULT CURRENT_DATE NOT NULL,
    "useful_life_months" integer NOT NULL,
    "depreciation_method" "text" DEFAULT 'straight_line'::"text" NOT NULL,
    "declining_rate" numeric(6,4),
    "status" "text" DEFAULT 'active'::"text" NOT NULL,
    "accumulated_cents" bigint DEFAULT 0 NOT NULL,
    "disposed_at" "date",
    "disposed_amount_cents" bigint,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "fixed_assets_cost_cents_check" CHECK (("cost_cents" >= 0)),
    CONSTRAINT "fixed_assets_depreciation_method_check" CHECK (("depreciation_method" = ANY (ARRAY['straight_line'::"text", 'declining'::"text"]))),
    CONSTRAINT "fixed_assets_salvage_cents_check" CHECK (("salvage_cents" >= 0)),
    CONSTRAINT "fixed_assets_status_check" CHECK (("status" = ANY (ARRAY['active'::"text", 'fully_depreciated'::"text", 'disposed'::"text"]))),
    CONSTRAINT "fixed_assets_useful_life_months_check" CHECK (("useful_life_months" > 0))
);


ALTER TABLE "public"."fixed_assets" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."compute_monthly_depreciation"("p_asset" "public"."fixed_assets") RETURNS bigint
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
DECLARE
  v_remaining BIGINT;
  v_amount BIGINT;
  v_nbv BIGINT;
BEGIN
  v_nbv := p_asset.cost_cents - p_asset.accumulated_cents;
  v_remaining := v_nbv - p_asset.salvage_cents;
  IF v_remaining <= 0 THEN RETURN 0; END IF;

  IF p_asset.depreciation_method = 'straight_line' THEN
    v_amount := (p_asset.cost_cents - p_asset.salvage_cents) / GREATEST(p_asset.useful_life_months, 1);
  ELSIF p_asset.depreciation_method = 'declining' THEN
    -- monthly rate = annual_rate / 12 applied to current NBV
    v_amount := ROUND(v_nbv * COALESCE(p_asset.declining_rate, 0.30) / 12.0);
  ELSE
    v_amount := 0;
  END IF;

  -- Don't depreciate below salvage
  IF v_amount > v_remaining THEN v_amount := v_remaining; END IF;
  RETURN GREATEST(v_amount, 0);
END;
$$;


ALTER FUNCTION "public"."compute_monthly_depreciation"("p_asset" "public"."fixed_assets") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."confirm_mo"("p_mo_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_mo         public.manufacturing_orders%ROWTYPE;
  v_bom_id     uuid;
  v_bom_qty    numeric;
  v_factor     numeric;
  v_shortages  jsonb := '[]'::jsonb;
BEGIN
  IF NOT (public.has_role(auth.uid(), 'writer') OR public.has_role(auth.uid(), 'admin')) THEN
    RAISE EXCEPTION 'Permission denied';
  END IF;

  SELECT * INTO v_mo FROM public.manufacturing_orders WHERE id = p_mo_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'MO % not found', p_mo_id; END IF;

  IF v_mo.status NOT IN ('draft', 'planned') THEN
    -- Idempotent re-check
    PERFORM public.check_mo_availability(p_mo_id);
    RETURN jsonb_build_object('success', true, 'mo_id', p_mo_id, 'status', v_mo.status, 'note', 'already confirmed');
  END IF;

  -- Resolve BOM (use stored bom_id, else active)
  v_bom_id := v_mo.bom_id;
  IF v_bom_id IS NULL THEN
    SELECT id, quantity_produced INTO v_bom_id, v_bom_qty
      FROM public.bom_headers
     WHERE product_id = v_mo.product_id AND is_active = true
     LIMIT 1;
    IF v_bom_id IS NULL THEN
      RAISE EXCEPTION 'No active BOM for product %', v_mo.product_id;
    END IF;
    UPDATE public.manufacturing_orders SET bom_id = v_bom_id WHERE id = p_mo_id;
  ELSE
    SELECT quantity_produced INTO v_bom_qty FROM public.bom_headers WHERE id = v_bom_id;
  END IF;

  v_factor := v_mo.quantity / NULLIF(v_bom_qty, 0);

  -- Snapshot components
  DELETE FROM public.mo_components WHERE mo_id = p_mo_id;
  INSERT INTO public.mo_components (mo_id, component_product_id, qty_required, availability)
  SELECT p_mo_id,
         bl.component_product_id,
         ROUND(bl.quantity * v_factor * (1 + bl.scrap_pct / 100.0), 4),
         'unknown'
    FROM public.bom_lines bl
   WHERE bl.bom_id = v_bom_id;

  UPDATE public.manufacturing_orders
     SET status = 'confirmed', updated_at = now()
   WHERE id = p_mo_id;

  -- Compute availability now
  v_shortages := (public.check_mo_availability(p_mo_id))->'shortages';

  -- Emit event (best-effort; helper exists per memory)
  BEGIN
    PERFORM public.emit_platform_event(
      'mo.confirmed',
      jsonb_build_object('mo_id', p_mo_id, 'shortages', v_shortages),
      'manufacturing'
    );
  EXCEPTION WHEN undefined_function THEN NULL; END;

  RETURN jsonb_build_object(
    'success', true,
    'mo_id', p_mo_id,
    'bom_id', v_bom_id,
    'shortages', v_shortages
  );
END;
$$;


ALTER FUNCTION "public"."confirm_mo"("p_mo_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."confirm_newsletter_subscription"("p_token" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_count int;
BEGIN
  UPDATE public.newsletter_subscribers
  SET status = 'confirmed', confirmed_at = COALESCE(confirmed_at, now())
  WHERE confirmation_token = p_token AND p_token IS NOT NULL;
  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count > 0;
END $$;


ALTER FUNCTION "public"."confirm_newsletter_subscription"("p_token" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."confirm_pick"("p_line_id" "uuid", "p_qty_picked" numeric, "p_lot_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_line RECORD;
  v_picking_id UUID;
  v_all_done BOOLEAN;
BEGIN
  SELECT * INTO v_line FROM public.picking_lines WHERE id = p_line_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Picking line % not found', p_line_id; END IF;

  v_picking_id := v_line.picking_order_id;

  UPDATE public.picking_lines
  SET qty_picked = p_qty_picked,
      lot_id = COALESCE(p_lot_id, lot_id),
      status = CASE
        WHEN p_qty_picked >= qty_requested THEN 'picked'
        WHEN p_qty_picked > 0 THEN 'short'
        ELSE 'pending'
      END,
      picked_at = now(),
      picked_by = auth.uid()
  WHERE id = p_line_id;

  -- If picking_order was draft/ready, move to in_progress
  UPDATE public.picking_orders
  SET status = 'in_progress'
  WHERE id = v_picking_id AND status IN ('draft','ready');

  -- If ALL lines are picked or short, mark picking_order picked
  SELECT NOT EXISTS (
    SELECT 1 FROM public.picking_lines
    WHERE picking_order_id = v_picking_id
      AND status NOT IN ('picked','short','cancelled')
  ) INTO v_all_done;

  IF v_all_done THEN
    UPDATE public.picking_orders SET status = 'picked', picked_at = now()
    WHERE id = v_picking_id AND status NOT IN ('shipped','cancelled');
  END IF;

  INSERT INTO public.audit_logs (action, entity_type, entity_id, user_id, metadata)
  VALUES ('picking.picked', 'picking_line', p_line_id, auth.uid(),
    jsonb_build_object('picking_order_id', v_picking_id, 'qty_picked', p_qty_picked, 'lot_id', p_lot_id));

  RETURN jsonb_build_object('success', true, 'line_id', p_line_id, 'all_done', v_all_done);
END;
$$;


ALTER FUNCTION "public"."confirm_pick"("p_line_id" "uuid", "p_qty_picked" numeric, "p_lot_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."consultant_profile_search_maintenance"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'extensions'
    AS $$
begin
  new.search_tsv :=
      setweight(to_tsvector('simple', coalesce(new.name, '')), 'A') ||
      setweight(to_tsvector('simple', coalesce(new.title, '')), 'A') ||
      setweight(to_tsvector('simple', array_to_string(coalesce(new.skills, '{}'), ' ')), 'A') ||
      setweight(to_tsvector('simple', array_to_string(coalesce(new.certifications, '{}'), ' ')), 'B') ||
      setweight(to_tsvector('simple', array_to_string(coalesce(new.languages, '{}'), ' ')), 'B') ||
      setweight(to_tsvector('simple', coalesce(new.summary, '')), 'B') ||
      setweight(to_tsvector('simple', coalesce(new.bio, '')), 'C');

  if tg_op = 'INSERT' then
    new.embedding_status := 'stale';
    return new;
  end if;

  if new.name is distinct from old.name
     or new.title is distinct from old.title
     or new.bio is distinct from old.bio
     or new.summary is distinct from old.summary
     or new.skills is distinct from old.skills
     or new.certifications is distinct from old.certifications
     or new.languages is distinct from old.languages
     or new.experience_json is distinct from old.experience_json
  then
    new.embedding_status := 'stale';
    new.embedding := null;
    new.embedded_at := null;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."consultant_profile_search_maintenance"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."consume_reservation"("p_reservation_id" "uuid", "p_to_location_code" "text" DEFAULT 'WH/CUSTOMERS'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE r stock_reservations%ROWTYPE; v_to uuid; v_move uuid;
BEGIN
  IF NOT (has_role(auth.uid(),'writer'::app_role) OR has_role(auth.uid(),'admin'::app_role)) THEN RAISE EXCEPTION 'Insufficient privileges'; END IF;
  SELECT * INTO r FROM stock_reservations WHERE id = p_reservation_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Reservation not found'; END IF;
  IF r.state <> 'reserved' THEN RAISE EXCEPTION 'Reservation not in reserved state'; END IF;
  SELECT id INTO v_to FROM stock_locations WHERE code = p_to_location_code;
  IF v_to IS NULL THEN RAISE EXCEPTION 'Destination location % not found', p_to_location_code; END IF;
  UPDATE stock_quants SET reserved_quantity = GREATEST(0, COALESCE(reserved_quantity,0) - r.quantity), updated_at = now()
    WHERE product_id = r.product_id AND location_id = r.location_id AND (lot_id IS NOT DISTINCT FROM r.lot_id);
  PERFORM _upsert_quant(r.product_id, r.location_id, r.lot_id, -r.quantity);
  PERFORM _upsert_quant(r.product_id, v_to, r.lot_id, r.quantity);
  INSERT INTO stock_moves (product_id, quantity, move_type, from_location_id, to_location_id, lot_id, reference_type, reference_id, created_by, state)
  VALUES (r.product_id, r.quantity::int, 'reservation_consumed', r.location_id, v_to, r.lot_id, r.reference_type, r.reference_id, auth.uid(), 'done')
  RETURNING id INTO v_move;
  UPDATE stock_reservations SET state='consumed', consumed_at=now() WHERE id=p_reservation_id;
  RETURN v_move;
END; $$;


ALTER FUNCTION "public"."consume_reservation"("p_reservation_id" "uuid", "p_to_location_code" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_agent_document"("p_uploaded_by" "uuid", "p_peer_name" "text", "p_title" "text", "p_file_name" "text", "p_file_url" "text" DEFAULT NULL::"text", "p_file_type" "text" DEFAULT NULL::"text", "p_file_size_bytes" bigint DEFAULT NULL::bigint, "p_description" "text" DEFAULT NULL::"text", "p_category" "text" DEFAULT 'agent-upload'::"text", "p_tags" "text"[] DEFAULT '{}'::"text"[], "p_content_md" "text" DEFAULT NULL::"text", "p_extraction_status" "text" DEFAULT 'pending'::"text", "p_extraction_error" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_id uuid;
  v_source text;
  v_peer text := COALESCE(NULLIF(trim(p_peer_name), ''), 'unknown');
BEGIN
  IF p_uploaded_by IS NULL THEN
    RAISE EXCEPTION 'uploaded_by required';
  END IF;

  IF NOT (
    public.has_role(p_uploaded_by, 'admin'::app_role)
    OR public.has_role(p_uploaded_by, 'employee'::app_role)
    OR public.has_role(p_uploaded_by, 'manager'::app_role)
  ) THEN
    RAISE EXCEPTION 'caller user lacks role for agent upload';
  END IF;

  IF p_title IS NULL OR length(trim(p_title)) = 0 THEN
    RAISE EXCEPTION 'title required';
  END IF;
  IF p_file_name IS NULL OR length(trim(p_file_name)) = 0 THEN
    RAISE EXCEPTION 'file_name required';
  END IF;

  IF p_extraction_status NOT IN ('pending', 'success', 'failed', 'unsupported', 'not_applicable') THEN
    RAISE EXCEPTION 'invalid extraction_status: %', p_extraction_status;
  END IF;

  v_peer := lower(regexp_replace(v_peer, '[^a-z0-9_-]+', '-', 'gi'));
  v_source := 'agent-upload:' || v_peer;

  INSERT INTO public.documents (
    title, file_name, file_url, file_type, file_size_bytes,
    description, category, tags,
    uploaded_by, source,
    content_md, extraction_status, extraction_error,
    content_extracted_at
  )
  VALUES (
    p_title, p_file_name, COALESCE(p_file_url, ''), p_file_type, p_file_size_bytes,
    p_description, COALESCE(p_category, 'agent-upload'), COALESCE(p_tags, '{}'::text[]),
    p_uploaded_by, v_source,
    p_content_md, p_extraction_status, p_extraction_error,
    CASE WHEN p_extraction_status = 'success' THEN now() ELSE NULL END
  )
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."create_agent_document"("p_uploaded_by" "uuid", "p_peer_name" "text", "p_title" "text", "p_file_name" "text", "p_file_url" "text", "p_file_type" "text", "p_file_size_bytes" bigint, "p_description" "text", "p_category" "text", "p_tags" "text"[], "p_content_md" "text", "p_extraction_status" "text", "p_extraction_error" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_bom"("p_product_id" "uuid", "p_lines" "jsonb", "p_version" "text" DEFAULT NULL::"text", "p_quantity_produced" numeric DEFAULT 1, "p_routing_notes" "text" DEFAULT NULL::"text", "p_activate" boolean DEFAULT true) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_bom_id  uuid;
  v_version text;
  v_line    jsonb;
  v_pos     int := 0;
BEGIN
  IF NOT (public.has_role(auth.uid(), 'writer') OR public.has_role(auth.uid(), 'admin')) THEN
    RAISE EXCEPTION 'Permission denied';
  END IF;

  IF p_product_id IS NULL THEN
    RAISE EXCEPTION 'product_id is required';
  END IF;
  IF p_lines IS NULL OR jsonb_array_length(p_lines) = 0 THEN
    RAISE EXCEPTION 'lines must contain at least one component';
  END IF;

  -- Auto-version: v1, v2, ...
  IF p_version IS NULL OR trim(p_version) = '' THEN
    SELECT 'v' || (COALESCE(COUNT(*), 0) + 1)::text
      INTO v_version
      FROM public.bom_headers WHERE product_id = p_product_id;
  ELSE
    v_version := p_version;
  END IF;

  -- Deactivate other versions if activating this one
  IF p_activate THEN
    UPDATE public.bom_headers SET is_active = false WHERE product_id = p_product_id AND is_active = true;
  END IF;

  INSERT INTO public.bom_headers (product_id, version, is_active, quantity_produced, routing_notes, created_by)
  VALUES (p_product_id, v_version, p_activate, COALESCE(p_quantity_produced, 1), p_routing_notes, auth.uid())
  RETURNING id INTO v_bom_id;

  FOR v_line IN SELECT * FROM jsonb_array_elements(p_lines)
  LOOP
    v_pos := v_pos + 1;
    INSERT INTO public.bom_lines (bom_id, component_product_id, quantity, unit, scrap_pct, position)
    VALUES (
      v_bom_id,
      (v_line->>'component_product_id')::uuid,
      (v_line->>'quantity')::numeric,
      v_line->>'unit',
      COALESCE((v_line->>'scrap_pct')::numeric, 0),
      COALESCE((v_line->>'position')::int, v_pos)
    );
  END LOOP;

  RETURN jsonb_build_object(
    'success', true,
    'bom_id', v_bom_id,
    'version', v_version,
    'line_count', jsonb_array_length(p_lines)
  );
END;
$$;


ALTER FUNCTION "public"."create_bom"("p_product_id" "uuid", "p_lines" "jsonb", "p_version" "text", "p_quantity_produced" numeric, "p_routing_notes" "text", "p_activate" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_contract_from_template"("p_template_id" "uuid", "p_counterparty_name" "text", "p_counterparty_email" "text" DEFAULT NULL::"text", "p_overrides" "jsonb" DEFAULT '{}'::"jsonb") RETURNS TABLE("contract_id" "uuid", "title" "text", "status" "public"."contract_status")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_tpl RECORD;
  v_body TEXT;
  v_title TEXT;
  v_start DATE;
  v_end DATE;
  v_value BIGINT;
  v_currency TEXT;
  v_id UUID;
BEGIN
  IF p_template_id IS NULL THEN RAISE EXCEPTION 'template_id is required'; END IF;
  IF p_counterparty_name IS NULL OR length(trim(p_counterparty_name)) = 0 THEN
    RAISE EXCEPTION 'counterparty_name is required';
  END IF;

  SELECT * INTO v_tpl FROM public.contract_templates WHERE id = p_template_id AND is_active;
  IF NOT FOUND THEN RAISE EXCEPTION 'Template % not found or inactive', p_template_id; END IF;

  v_start := COALESCE((p_overrides->>'start_date')::DATE, CURRENT_DATE);
  v_end := NULLIF(p_overrides->>'end_date','')::DATE;
  v_value := COALESCE((p_overrides->>'value_cents')::BIGINT, v_tpl.default_value_cents);
  v_currency := COALESCE(p_overrides->>'currency', v_tpl.default_currency);
  v_title := COALESCE(p_overrides->>'title', v_tpl.name || ' — ' || p_counterparty_name);

  -- Render tokens
  v_body := v_tpl.body_markdown;
  v_body := replace(v_body, '{{counterparty.name}}', p_counterparty_name);
  v_body := replace(v_body, '{{counterparty.email}}', COALESCE(p_counterparty_email, ''));
  v_body := replace(v_body, '{{today}}', to_char(CURRENT_DATE, 'YYYY-MM-DD'));
  v_body := replace(v_body, '{{start_date}}', to_char(v_start, 'YYYY-MM-DD'));
  v_body := replace(v_body, '{{end_date}}', COALESCE(to_char(v_end, 'YYYY-MM-DD'), 'TBD'));
  v_body := replace(v_body, '{{value}}', to_char(v_value / 100.0, 'FM999G999G999D00'));
  v_body := replace(v_body, '{{currency}}', v_currency);
  v_body := replace(v_body, '{{title}}', v_title);

  INSERT INTO public.contracts (
    title, counterparty_name, counterparty_email, contract_type, status,
    start_date, end_date, value_cents, currency,
    renewal_type, renewal_notice_days,
    body_markdown, body_updated_at, template_id, version
  ) VALUES (
    v_title, p_counterparty_name, p_counterparty_email, v_tpl.contract_type, 'draft',
    v_start, v_end, v_value, v_currency,
    v_tpl.default_renewal_type, v_tpl.default_renewal_notice_days,
    v_body, now(), v_tpl.id, 1
  ) RETURNING id INTO v_id;

  RETURN QUERY SELECT v_id, v_title, 'draft'::contract_status;
END;
$$;


ALTER FUNCTION "public"."create_contract_from_template"("p_template_id" "uuid", "p_counterparty_name" "text", "p_counterparty_email" "text", "p_overrides" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_cowork_document"("p_title" "text", "p_file_name" "text", "p_file_url" "text", "p_file_type" "text" DEFAULT NULL::"text", "p_file_size_bytes" bigint DEFAULT NULL::bigint, "p_description" "text" DEFAULT NULL::"text", "p_category" "text" DEFAULT 'chat-attachment'::"text", "p_tags" "text"[] DEFAULT '{}'::"text"[]) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_id uuid;
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'not authenticated';
  END IF;

  IF NOT (
    public.has_role(v_uid, 'admin'::app_role)
    OR public.has_role(v_uid, 'employee'::app_role)
    OR public.has_role(v_uid, 'hr'::app_role)
  ) THEN
    RAISE EXCEPTION 'insufficient role for cowork upload';
  END IF;

  IF p_title IS NULL OR length(trim(p_title)) = 0 THEN
    RAISE EXCEPTION 'title required';
  END IF;
  IF p_file_name IS NULL OR length(trim(p_file_name)) = 0 THEN
    RAISE EXCEPTION 'file_name required';
  END IF;
  IF p_file_url IS NULL OR length(trim(p_file_url)) = 0 THEN
    RAISE EXCEPTION 'file_url required';
  END IF;

  INSERT INTO public.documents (
    title, file_name, file_url, file_type, file_size_bytes,
    description, category, tags, source, uploaded_by, extraction_status
  ) VALUES (
    p_title, p_file_name, p_file_url, p_file_type, p_file_size_bytes,
    p_description, p_category, p_tags, 'cowork-upload', v_uid, 'pending'
  )
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."create_cowork_document"("p_title" "text", "p_file_name" "text", "p_file_url" "text", "p_file_type" "text", "p_file_size_bytes" bigint, "p_description" "text", "p_category" "text", "p_tags" "text"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_manual_subscription"("_customer_email" "text", "_customer_name" "text", "_product_name" "text", "_unit_amount_cents" integer, "_currency" "text" DEFAULT 'EUR'::"text", "_billing_interval" "text" DEFAULT 'month'::"text", "_billing_interval_count" integer DEFAULT 1, "_quantity" integer DEFAULT 1, "_payment_terms" "text" DEFAULT 'invoice_30'::"text", "_start_date" "date" DEFAULT CURRENT_DATE, "_billing_contact_email" "text" DEFAULT NULL::"text", "_po_number" "text" DEFAULT NULL::"text", "_product_id" "uuid" DEFAULT NULL::"uuid", "_auto_finalize" boolean DEFAULT false) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  _new_id uuid;
BEGIN
  IF NOT has_role(auth.uid(), 'admin'::app_role) THEN
    RAISE EXCEPTION 'Only admins can create manual subscriptions';
  END IF;

  IF _customer_email IS NULL OR length(trim(_customer_email)) = 0 THEN
    RAISE EXCEPTION 'customer_email is required';
  END IF;
  IF _unit_amount_cents IS NULL OR _unit_amount_cents <= 0 THEN
    RAISE EXCEPTION 'unit_amount_cents must be > 0';
  END IF;

  INSERT INTO public.subscriptions (
    customer_email, customer_name, product_name, product_id,
    unit_amount_cents, currency, quantity,
    billing_interval, billing_interval_count,
    payment_terms, billing_contact_email, po_number,
    provider, status,
    current_period_start, current_period_end, next_invoice_date,
    auto_finalize,
    metadata
  ) VALUES (
    lower(trim(_customer_email)), _customer_name, _product_name, _product_id,
    _unit_amount_cents, lower(_currency), GREATEST(1, _quantity),
    lower(_billing_interval), GREATEST(1, _billing_interval_count),
    _payment_terms, _billing_contact_email, _po_number,
    'manual', 'active'::subscription_status,
    _start_date::timestamptz,
    advance_billing_date(_start_date, _billing_interval, _billing_interval_count)::timestamptz,
    _start_date,
    COALESCE(_auto_finalize, false),
    jsonb_build_object('created_via', 'create_manual_subscription', 'created_by', auth.uid(), 'auto_finalize', COALESCE(_auto_finalize, false))
  )
  RETURNING id INTO _new_id;

  PERFORM public.emit_platform_event(
    'subscription.created',
    jsonb_build_object('subscription_id', _new_id, 'provider', 'manual', 'customer_email', _customer_email, 'auto_finalize', COALESCE(_auto_finalize, false)),
    'create_manual_subscription'
  );

  RETURN jsonb_build_object('ok', true, 'subscription_id', _new_id, 'next_invoice_date', _start_date, 'auto_finalize', COALESCE(_auto_finalize, false));
END $$;


ALTER FUNCTION "public"."create_manual_subscription"("_customer_email" "text", "_customer_name" "text", "_product_name" "text", "_unit_amount_cents" integer, "_currency" "text", "_billing_interval" "text", "_billing_interval_count" integer, "_quantity" integer, "_payment_terms" "text", "_start_date" "date", "_billing_contact_email" "text", "_po_number" "text", "_product_id" "uuid", "_auto_finalize" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."create_payroll_run"("p_period_date" "date") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_run_id UUID;
  v_emp RECORD;
  v_gross BIGINT; v_benefits BIGINT; v_deductions BIGINT;
  v_taxable BIGINT; v_tax BIGINT; v_social BIGINT; v_net BIGINT;
  v_components JSONB;
  v_total_gross BIGINT := 0; v_total_tax BIGINT := 0; v_total_social BIGINT := 0; v_total_net BIGINT := 0;
  v_lines INT := 0;
BEGIN
  IF NOT public.has_role(auth.uid(),'admin') THEN
    RAISE EXCEPTION 'Only admins can create payroll runs';
  END IF;

  INSERT INTO public.payroll_runs (period_date, status)
  VALUES (date_trunc('month', p_period_date)::date, 'draft')
  RETURNING id INTO v_run_id;

  FOR v_emp IN
    SELECT id, COALESCE(monthly_salary_cents,0) AS base, COALESCE(tax_rate_pct,30.00) AS tax_pct, full_name
    FROM public.employees
    WHERE COALESCE(employment_status,'active') = 'active'
  LOOP
    v_gross := v_emp.base;
    v_benefits := 0; v_deductions := 0;
    v_components := '[]'::jsonb;

    -- Pull recurring components
    SELECT
      COALESCE(SUM(CASE WHEN component_type IN ('salary','bonus','overtime') AND taxable THEN amount_cents ELSE 0 END),0),
      COALESCE(SUM(CASE WHEN component_type='benefit' THEN amount_cents ELSE 0 END),0),
      COALESCE(SUM(CASE WHEN component_type='deduction' THEN amount_cents ELSE 0 END),0),
      COALESCE(jsonb_agg(jsonb_build_object('type',component_type,'label',label,'amount_cents',amount_cents,'taxable',taxable)),'[]'::jsonb)
    INTO v_gross, v_benefits, v_deductions, v_components
    FROM (
      SELECT component_type, label, amount_cents, taxable FROM public.payroll_components
      WHERE employee_id = v_emp.id AND active AND recurring
    ) c;

    v_gross := COALESCE(v_emp.base,0) + COALESCE(v_gross,0);
    v_taxable := v_gross + v_benefits - v_deductions;
    v_tax := ROUND(v_taxable * v_emp.tax_pct / 100.0);
    v_social := ROUND(v_taxable * 31.42 / 100.0);
    v_net := v_taxable - v_tax;

    INSERT INTO public.payroll_lines (run_id, employee_id, gross_cents, benefits_cents, deductions_cents, taxable_cents, tax_cents, social_fee_cents, net_cents, components)
    VALUES (v_run_id, v_emp.id, v_gross, v_benefits, v_deductions, v_taxable, v_tax, v_social, v_net, v_components);

    v_total_gross := v_total_gross + v_gross;
    v_total_tax := v_total_tax + v_tax;
    v_total_social := v_total_social + v_social;
    v_total_net := v_total_net + v_net;
    v_lines := v_lines + 1;
  END LOOP;

  UPDATE public.payroll_runs
    SET total_gross_cents=v_total_gross, total_tax_cents=v_total_tax,
        total_social_fee_cents=v_total_social, total_net_cents=v_total_net
  WHERE id = v_run_id;

  RETURN jsonb_build_object('success',true,'run_id',v_run_id,'lines',v_lines,
    'total_gross_cents',v_total_gross,'total_tax_cents',v_total_tax,
    'total_social_fee_cents',v_total_social,'total_net_cents',v_total_net);
END; $$;


ALTER FUNCTION "public"."create_payroll_run"("p_period_date" "date") OWNER TO "postgres";


