CREATE OR REPLACE FUNCTION "public"."demo_cycle_cron_status"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
declare
  v_row record;
  v_last record;
begin
  select jobid, jobname, schedule, active into v_row
  from cron.job
  where jobname in ('demo-cycle-daily', 'demo-cycle-hourly')
  order by case jobname when 'demo-cycle-daily' then 0 else 1 end
  limit 1;

  if not found then
    return jsonb_build_object('scheduled', false);
  end if;

  begin
    select start_time, status, return_message into v_last
    from cron.job_run_details
    where jobid = v_row.jobid
    order by start_time desc
    limit 1;
  exception when others then
    v_last := null;
  end;

  return jsonb_build_object(
    'scheduled', true,
    'jobname', v_row.jobname,
    'schedule', v_row.schedule,
    'active', v_row.active,
    'last_run_at', v_last.start_time,
    'last_status', v_last.status,
    'last_message', v_last.return_message
  );
end;
$$;


ALTER FUNCTION "public"."demo_cycle_cron_status"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."disable_demo_cycle_cron"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
declare
  v_removed int := 0;
begin
  if not has_role(auth.uid(), 'admin') then
    raise exception 'admin role required';
  end if;

  if exists (select 1 from cron.job where jobname = 'demo-cycle-daily') then
    perform cron.unschedule('demo-cycle-daily');
    v_removed := v_removed + 1;
  end if;
  if exists (select 1 from cron.job where jobname = 'demo-cycle-hourly') then
    perform cron.unschedule('demo-cycle-hourly');
    v_removed := v_removed + 1;
  end if;

  return jsonb_build_object('unscheduled', v_removed > 0, 'removed', v_removed);
end;
$$;


ALTER FUNCTION "public"."disable_demo_cycle_cron"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."dispatch_automation_event"("event_name" "text", "signal_name" "text", "payload" "jsonb", "entity_type" "text" DEFAULT NULL::"text", "entity_id" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  supabase_url text;
  service_key text;
  headers jsonb;
BEGIN
  supabase_url := (SELECT decrypted_secret FROM vault.decrypted_secrets WHERE name = 'SUPABASE_URL' LIMIT 1);
  service_key := (SELECT decrypted_secret FROM vault.decrypted_secrets WHERE name = 'SUPABASE_SERVICE_ROLE_KEY' LIMIT 1);
  
  IF supabase_url IS NULL OR service_key IS NULL THEN
    RAISE WARNING 'Missing SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY for automation dispatch';
    RETURN;
  END IF;

  headers := jsonb_build_object(
    'Content-Type', 'application/json',
    'Authorization', 'Bearer ' || service_key
  );

  -- Fire event to send-webhook
  IF event_name IS NOT NULL THEN
    PERFORM net.http_post(
      url := supabase_url || '/functions/v1/send-webhook',
      headers := headers,
      body := jsonb_build_object(
        'event', event_name,
        'data', payload
      )
    );
  END IF;

  -- Fire signal to signal-dispatcher
  IF signal_name IS NOT NULL THEN
    PERFORM net.http_post(
      url := supabase_url || '/functions/v1/signal-dispatcher',
      headers := headers,
      body := jsonb_build_object(
        'signal', signal_name,
        'data', payload,
        'context', jsonb_build_object(
          'entity_type', COALESCE(entity_type, 'unknown'),
          'entity_id', COALESCE(entity_id, '')
        )
      )
    );
  END IF;
END;
$$;


ALTER FUNCTION "public"."dispatch_automation_event"("event_name" "text", "signal_name" "text", "payload" "jsonb", "entity_type" "text", "entity_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."dispose_fixed_asset"("p_asset_id" "uuid", "p_sale_amount_cents" bigint DEFAULT 0, "p_disposal_date" "date" DEFAULT CURRENT_DATE, "p_proceeds_account" "text" DEFAULT '1930'::"text", "p_gain_account" "text" DEFAULT '3970'::"text", "p_loss_account" "text" DEFAULT '7970'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_asset public.fixed_assets;
  v_nbv BIGINT;
  v_gain_loss BIGINT;
  v_je_id UUID;
BEGIN
  IF NOT public.has_role(auth.uid(), 'admin') THEN
    RAISE EXCEPTION 'dispose_fixed_asset: admin role required';
  END IF;

  SELECT * INTO v_asset FROM public.fixed_assets WHERE id = p_asset_id;
  IF v_asset.id IS NULL THEN RAISE EXCEPTION 'Asset not found'; END IF;
  IF v_asset.status = 'disposed' THEN RAISE EXCEPTION 'Asset already disposed'; END IF;

  v_nbv := v_asset.cost_cents - v_asset.accumulated_cents;
  v_gain_loss := COALESCE(p_sale_amount_cents,0) - v_nbv;

  IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='public' AND table_name='journal_entries') THEN
    INSERT INTO public.journal_entries (entry_date, description, source, status)
    VALUES (p_disposal_date, format('Disposal: %s', v_asset.name), 'fixed_asset_disposal', 'posted')
    RETURNING id INTO v_je_id;

    -- Remove cost
    INSERT INTO public.journal_entry_lines (entry_id, account_code, debit_cents, credit_cents, description)
    VALUES (v_je_id, v_asset.asset_account, 0, v_asset.cost_cents, 'Reverse cost');
    -- Remove accumulated depreciation
    IF v_asset.accumulated_cents > 0 THEN
      INSERT INTO public.journal_entry_lines (entry_id, account_code, debit_cents, credit_cents, description)
      VALUES (v_je_id, v_asset.accumulated_account, v_asset.accumulated_cents, 0, 'Reverse accum depr');
    END IF;
    -- Cash proceeds
    IF COALESCE(p_sale_amount_cents,0) > 0 THEN
      INSERT INTO public.journal_entry_lines (entry_id, account_code, debit_cents, credit_cents, description)
      VALUES (v_je_id, p_proceeds_account, p_sale_amount_cents, 0, 'Sale proceeds');
    END IF;
    -- Gain or loss
    IF v_gain_loss > 0 THEN
      INSERT INTO public.journal_entry_lines (entry_id, account_code, debit_cents, credit_cents, description)
      VALUES (v_je_id, p_gain_account, 0, v_gain_loss, 'Gain on disposal');
    ELSIF v_gain_loss < 0 THEN
      INSERT INTO public.journal_entry_lines (entry_id, account_code, debit_cents, credit_cents, description)
      VALUES (v_je_id, p_loss_account, ABS(v_gain_loss), 0, 'Loss on disposal');
    END IF;
  END IF;

  UPDATE public.fixed_assets
     SET status='disposed',
         disposed_at = p_disposal_date,
         disposed_amount_cents = p_sale_amount_cents
   WHERE id = p_asset_id;

  RETURN jsonb_build_object(
    'success', true,
    'asset_id', p_asset_id,
    'nbv_cents', v_nbv,
    'sale_cents', p_sale_amount_cents,
    'gain_loss_cents', v_gain_loss,
    'journal_entry_id', v_je_id
  );
END;
$$;


ALTER FUNCTION "public"."dispose_fixed_asset"("p_asset_id" "uuid", "p_sale_amount_cents" bigint, "p_disposal_date" "date", "p_proceeds_account" "text", "p_gain_account" "text", "p_loss_account" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."emit_platform_event"("_event_name" "text", "_payload" "jsonb" DEFAULT '{}'::"jsonb", "_source" "text" DEFAULT 'platform'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  _id UUID;
BEGIN
  INSERT INTO public.agent_events (event_name, payload, source)
  VALUES (_event_name, COALESCE(_payload, '{}'::jsonb), COALESCE(_source, 'platform'))
  RETURNING id INTO _id;
  RETURN _id;
END;
$$;


ALTER FUNCTION "public"."emit_platform_event"("_event_name" "text", "_payload" "jsonb", "_source" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."emit_service_order_event"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    PERFORM public.emit_platform_event('service_order.created',
      jsonb_build_object('id', NEW.id, 'order_number', NEW.order_number, 'customer_name', NEW.customer_name, 'priority', NEW.priority),
      'service_orders');
  ELSIF TG_OP = 'UPDATE' AND NEW.status IS DISTINCT FROM OLD.status THEN
    IF NEW.status = 'completed' THEN
      PERFORM public.emit_platform_event('service_order.completed',
        jsonb_build_object('id', NEW.id, 'order_number', NEW.order_number, 'customer_name', NEW.customer_name, 'customer_email', NEW.customer_email, 'total_amount', NEW.total_amount),
        'service_orders');
    ELSIF NEW.status = 'scheduled' THEN
      PERFORM public.emit_platform_event('service_order.scheduled',
        jsonb_build_object('id', NEW.id, 'order_number', NEW.order_number, 'scheduled_start', NEW.scheduled_start),
        'service_orders');
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."emit_service_order_event"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."emit_ticket_resolved_event"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.status = 'resolved' AND (OLD.status IS DISTINCT FROM 'resolved') THEN
    -- emit only if helper exists
    IF EXISTS (SELECT 1 FROM pg_proc WHERE proname='emit_platform_event') THEN
      PERFORM public.emit_platform_event(
        'ticket.resolved',
        jsonb_build_object(
          'ticket_id', NEW.id,
          'subject', NEW.subject,
          'contact_email', NEW.contact_email,
          'contact_name', NEW.contact_name,
          'company_id', NEW.company_id,
          'lead_id', NEW.lead_id,
          'category', NEW.category,
          'priority', NEW.priority,
          'resolved_at', NEW.resolved_at
        ),
        'tickets'
      );
    END IF;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."emit_ticket_resolved_event"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."emit_vendor_invoice_registered"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  PERFORM public.emit_platform_event(
    'invoice.registered',
    jsonb_build_object(
      'invoice_id', NEW.id,
      'invoice_number', NEW.invoice_number,
      'vendor_id', NEW.vendor_id,
      'purchase_order_id', NEW.purchase_order_id,
      'subtotal_cents', NEW.subtotal_cents,
      'total_cents', NEW.total_cents,
      'currency', NEW.currency,
      'invoice_date', NEW.invoice_date
    ),
    'vendor_invoices.trigger'
  );
  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  -- Never block invoice creation if event bus fails
  RAISE WARNING 'Failed to emit invoice.registered for %: %', NEW.id, SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."emit_vendor_invoice_registered"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."enable_demo_cycle_cron"("p_function_url" "text", "p_anon_key" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $_$
declare
  v_job_id bigint;
  v_command text;
begin
  if not has_role(auth.uid(), 'admin') then
    raise exception 'admin role required';
  end if;
  if p_function_url is null or length(p_function_url) = 0 then
    raise exception 'p_function_url required';
  end if;
  if p_anon_key is null or length(p_anon_key) = 0 then
    raise exception 'p_anon_key required';
  end if;

  v_command := format(
    $cmd$select net.http_post(
      url := %L,
      headers := %L::jsonb,
      body := jsonb_build_object('triggered_at', now())
    );$cmd$,
    p_function_url,
    jsonb_build_object(
      'Content-Type', 'application/json',
      'apikey', p_anon_key,
      'Authorization', 'Bearer ' || p_anon_key
    )::text
  );

  -- Clean up legacy hourly job if it still exists
  if exists (select 1 from cron.job where jobname = 'demo-cycle-hourly') then
    perform cron.unschedule('demo-cycle-hourly');
  end if;
  if exists (select 1 from cron.job where jobname = 'demo-cycle-daily') then
    perform cron.unschedule('demo-cycle-daily');
  end if;

  select cron.schedule('demo-cycle-daily', '0 3 * * *', v_command) into v_job_id;

  return jsonb_build_object(
    'scheduled', true,
    'jobname', 'demo-cycle-daily',
    'job_id', v_job_id,
    'schedule', '0 3 * * *'
  );
end;
$_$;


ALTER FUNCTION "public"."enable_demo_cycle_cron"("p_function_url" "text", "p_anon_key" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."enforce_mcp_exposure_invariant"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.mcp_exposed = true AND NEW.enabled = false THEN
    RAISE EXCEPTION 'MCP invariant violated: skill "%" cannot have mcp_exposed=true while enabled=false. Either re-enable the skill or set mcp_exposed=false.', NEW.name
      USING ERRCODE = 'check_violation';
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."enforce_mcp_exposure_invariant"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."evaluate_approval_required"("p_entity_type" "text", "p_amount_cents" bigint DEFAULT NULL::bigint, "p_currency" "text" DEFAULT 'SEK'::"text") RETURNS TABLE("rule_id" "uuid", "required_role" "public"."app_role", "rule_name" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT id, required_role, name
  FROM public.approval_rules
  WHERE is_active = true
    AND entity_type = p_entity_type
    AND currency = p_currency
    AND (
      amount_threshold_cents IS NULL
      OR (p_amount_cents IS NOT NULL AND p_amount_cents >= amount_threshold_cents)
    )
  ORDER BY priority ASC, amount_threshold_cents DESC NULLS LAST
  LIMIT 1;
$$;


