CREATE OR REPLACE FUNCTION "public"."explain_voucher_gap"("p_series" "text", "p_year" integer, "p_voucher_number" bigint) RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_clues jsonb;
BEGIN
  SELECT jsonb_agg(jsonb_build_object('action', action, 'entity_type', entity_type, 'user_id', user_id, 'metadata', metadata, 'created_at', created_at) ORDER BY created_at DESC)
  INTO v_clues FROM public.audit_logs
  WHERE entity_type IN ('journal_entry','journal_entries','voucher')
    AND (metadata->>'voucher_number' = p_voucher_number::text OR metadata->>'voucher_series' = p_series);
  RETURN jsonb_build_object(
    'series', p_series, 'fiscal_year', p_year, 'voucher_number', p_voucher_number,
    'audit_clues', COALESCE(v_clues, '[]'::jsonb),
    'explanation', CASE WHEN v_clues IS NULL THEN 'No audit trail found — gap likely caused by failed transaction. Investigate before period close.' ELSE 'Audit trail shows related events.' END
  );
END; $$;


ALTER FUNCTION "public"."explain_voucher_gap"("p_series" "text", "p_year" integer, "p_voucher_number" bigint) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."flag_at_risk_subscriptions"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_flagged integer;
BEGIN
  WITH updated AS (
    UPDATE public.subscriptions s
    SET at_risk = true,
        at_risk_reason = CASE
          WHEN s.status = 'past_due' THEN 'payment_failed'
          WHEN s.cancel_at_period_end THEN 'cancellation_scheduled'
          WHEN s.health_score IS NOT NULL AND s.health_score < 30 THEN 'low_health_score'
          ELSE 'unknown'
        END,
        updated_at = now()
    WHERE s.status IN ('active', 'trialing', 'past_due')
      AND (
        s.status = 'past_due'
        OR s.cancel_at_period_end = true
        OR (s.health_score IS NOT NULL AND s.health_score < 30)
      )
      AND s.at_risk = false
    RETURNING s.id
  )
  SELECT count(*) INTO v_flagged FROM updated;

  RETURN jsonb_build_object('flagged', v_flagged, 'run_at', now());
END;
$$;


ALTER FUNCTION "public"."flag_at_risk_subscriptions"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."generate_monthly_expense_report"("p_period" "text" DEFAULT "to_char"((CURRENT_DATE)::timestamp with time zone, 'YYYY-MM'::"text"), "p_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid;
  v_report_id uuid;
  v_count int;
  v_period_start date;
  v_period_end date;
BEGIN
  v_user_id := COALESCE(p_user_id, auth.uid());
  IF v_user_id IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'No user_id available');
  END IF;

  v_period_start := to_date(p_period || '-01', 'YYYY-MM-DD');
  v_period_end := (v_period_start + interval '1 month' - interval '1 day')::date;

  -- Reuse existing draft report for the period or create new
  SELECT id INTO v_report_id
  FROM expense_reports
  WHERE user_id = v_user_id AND period = p_period AND status = 'draft'
  LIMIT 1;

  IF v_report_id IS NULL THEN
    INSERT INTO expense_reports (user_id, period, status)
    VALUES (v_user_id, p_period, 'draft')
    RETURNING id INTO v_report_id;
  END IF;

  UPDATE expenses
  SET report_id = v_report_id
  WHERE user_id = v_user_id
    AND report_id IS NULL
    AND status = 'draft'
    AND expense_date BETWEEN v_period_start AND v_period_end;

  GET DIAGNOSTICS v_count = ROW_COUNT;

  RETURN jsonb_build_object(
    'success', true,
    'report_id', v_report_id,
    'period', p_period,
    'expenses_attached', v_count
  );
END;
$$;


ALTER FUNCTION "public"."generate_monthly_expense_report"("p_period" "text", "p_user_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."generate_payroll_export"("p_year" integer, "p_month" integer) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_export_id UUID;
  v_existing UUID;
  v_total_emp INTEGER := 0;
  v_total_days NUMERIC := 0;
  v_total_cents BIGINT := 0;
  v_row RECORD;
  v_all_leave_ids UUID[] := '{}';
  v_all_expense_ids UUID[] := '{}';
BEGIN
  IF NOT has_role(auth.uid(), 'admin'::app_role) THEN
    RAISE EXCEPTION 'Only admins can generate payroll exports';
  END IF;

  -- Reuse draft export if exists, otherwise reject if locked
  SELECT id INTO v_existing FROM public.payroll_exports
  WHERE period_year = p_year AND period_month = p_month;

  IF v_existing IS NOT NULL THEN
    -- Cannot regenerate locked exports
    IF EXISTS (SELECT 1 FROM public.payroll_exports WHERE id = v_existing AND status = 'locked') THEN
      RAISE EXCEPTION 'Payroll export for %-% is locked and cannot be regenerated', p_year, p_month;
    END IF;
    -- Clear existing lines and unlink source rows so we can rebuild
    DELETE FROM public.payroll_export_lines WHERE export_id = v_existing;
    UPDATE public.leave_requests SET payroll_export_id = NULL WHERE payroll_export_id = v_existing;
    UPDATE public.expenses SET payroll_export_id = NULL WHERE payroll_export_id = v_existing;
    v_export_id := v_existing;
  ELSE
    INSERT INTO public.payroll_exports (period_year, period_month, status, generated_by, generated_at)
    VALUES (p_year, p_month, 'generated', auth.uid(), now())
    RETURNING id INTO v_export_id;
  END IF;

  -- Insert lines from preview
  FOR v_row IN SELECT * FROM public.preview_payroll_period(p_year, p_month) LOOP
    INSERT INTO public.payroll_export_lines (
      export_id, employee_id, employee_name, employee_email, personal_number,
      vacation_days, sick_days, parental_days, other_leave_days,
      expense_reimbursement_cents, representation_cents, expense_count,
      leave_request_ids, expense_ids
    )
    VALUES (
      v_export_id, v_row.employee_id, v_row.employee_name, v_row.employee_email, v_row.personal_number,
      v_row.vacation_days, v_row.sick_days, v_row.parental_days, v_row.other_leave_days,
      v_row.expense_reimbursement_cents, v_row.representation_cents, v_row.expense_count,
      v_row.leave_request_ids, v_row.expense_ids
    );

    v_total_emp := v_total_emp + 1;
    v_total_days := v_total_days + v_row.vacation_days + v_row.sick_days + v_row.parental_days + v_row.other_leave_days;
    v_total_cents := v_total_cents + v_row.expense_reimbursement_cents + v_row.representation_cents;
    v_all_leave_ids := v_all_leave_ids || v_row.leave_request_ids;
    v_all_expense_ids := v_all_expense_ids || v_row.expense_ids;
  END LOOP;

  -- Mark source rows as exported
  IF array_length(v_all_leave_ids, 1) > 0 THEN
    UPDATE public.leave_requests SET payroll_export_id = v_export_id WHERE id = ANY(v_all_leave_ids);
  END IF;
  IF array_length(v_all_expense_ids, 1) > 0 THEN
    UPDATE public.expenses SET payroll_export_id = v_export_id WHERE id = ANY(v_all_expense_ids);
  END IF;

  -- Update totals
  UPDATE public.payroll_exports
  SET total_employees = v_total_emp,
      total_leave_days = v_total_days,
      total_expense_cents = v_total_cents,
      status = 'generated',
      generated_at = now(),
      generated_by = auth.uid()
  WHERE id = v_export_id;

  RETURN v_export_id;
END;
$$;


ALTER FUNCTION "public"."generate_payroll_export"("p_year" integer, "p_month" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."generate_po_number"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  next_num INTEGER;
BEGIN
  SELECT COALESCE(MAX(CAST(SUBSTRING(po_number FROM 4) AS INTEGER)), 0) + 1
  INTO next_num
  FROM public.purchase_orders;
  
  NEW.po_number := 'PO-' || LPAD(next_num::TEXT, 5, '0');
  RETURN NEW;
END;
$$;


