CREATE OR REPLACE FUNCTION "public"."generate_service_order_number"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  next_seq int;
BEGIN
  IF NEW.order_number IS NULL THEN
    SELECT COALESCE(MAX(NULLIF(regexp_replace(order_number, '\D', '', 'g'), '')::int), 0) + 1
      INTO next_seq
    FROM public.service_orders
    WHERE order_number LIKE 'SO-%';
    NEW.order_number := 'SO-' || lpad(next_seq::text, 5, '0');
  END IF;
  RETURN NEW;
END;
$$;


