CREATE OR REPLACE FUNCTION "public"."get_employee_leave_balances"("p_employee_id" "uuid", "p_year" integer DEFAULT (EXTRACT(year FROM CURRENT_DATE))::integer) RETURNS TABLE("leave_type" "text", "year" integer, "allocated_days" numeric, "carried_over_days" numeric, "used_days" numeric, "pending_days" numeric, "remaining_days" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  WITH types AS (
    SELECT DISTINCT leave_type FROM public.leave_allocations
      WHERE employee_id = p_employee_id AND year = p_year
    UNION
    SELECT DISTINCT leave_type FROM public.leave_requests
      WHERE employee_id = p_employee_id
        AND EXTRACT(YEAR FROM start_date)::INTEGER = p_year
  )
  SELECT
    t.leave_type,
    p_year,
    b.allocated_days,
    b.carried_over_days,
    b.used_days,
    b.pending_days,
    b.remaining_days
  FROM types t
  CROSS JOIN LATERAL public.get_leave_balance(p_employee_id, t.leave_type, p_year) b;
$$;


ALTER FUNCTION "public"."get_employee_leave_balances"("p_employee_id" "uuid", "p_year" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_exchange_rate"("p_base" "text", "p_quote" "text", "p_date" "date" DEFAULT CURRENT_DATE) RETURNS numeric
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_rate NUMERIC;
BEGIN
  IF p_base = p_quote THEN
    RETURN 1;
  END IF;

  -- Direct match (most recent on or before p_date)
  SELECT rate INTO v_rate
  FROM public.exchange_rates
  WHERE base_currency = p_base AND quote_currency = p_quote AND rate_date <= p_date
  ORDER BY rate_date DESC LIMIT 1;

  IF v_rate IS NOT NULL THEN
    RETURN v_rate;
  END IF;

  -- Inverse match
  SELECT 1.0 / rate INTO v_rate
  FROM public.exchange_rates
  WHERE base_currency = p_quote AND quote_currency = p_base AND rate_date <= p_date
  ORDER BY rate_date DESC LIMIT 1;

  RETURN COALESCE(v_rate, 1);
END;
$$;


ALTER FUNCTION "public"."get_exchange_rate"("p_base" "text", "p_quote" "text", "p_date" "date") OWNER TO "postgres";


