CREATE OR REPLACE FUNCTION "public"."get_leave_balance"("p_employee_id" "uuid", "p_leave_type" "text", "p_year" integer DEFAULT (EXTRACT(year FROM CURRENT_DATE))::integer) RETURNS TABLE("employee_id" "uuid", "leave_type" "text", "year" integer, "allocated_days" numeric, "carried_over_days" numeric, "used_days" numeric, "pending_days" numeric, "remaining_days" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  WITH alloc AS (
    SELECT
      la.employee_id,
      la.leave_type,
      la.year,
      la.allocated_days,
      la.carried_over_days
    FROM public.leave_allocations la
    WHERE la.employee_id = p_employee_id
      AND la.leave_type = p_leave_type
      AND la.year = p_year
  ),
  usage AS (
    SELECT
      COALESCE(SUM(CASE WHEN lr.status = 'approved' THEN lr.days ELSE 0 END), 0)::NUMERIC AS used_days,
      COALESCE(SUM(CASE WHEN lr.status = 'pending' THEN lr.days ELSE 0 END), 0)::NUMERIC AS pending_days
    FROM public.leave_requests lr
    WHERE lr.employee_id = p_employee_id
      AND lr.leave_type = p_leave_type
      AND EXTRACT(YEAR FROM lr.start_date)::INTEGER = p_year
  )
  SELECT
    p_employee_id,
    p_leave_type,
    p_year,
    COALESCE((SELECT allocated_days FROM alloc), 0),
    COALESCE((SELECT carried_over_days FROM alloc), 0),
    u.used_days,
    u.pending_days,
    (COALESCE((SELECT allocated_days FROM alloc), 0)
      + COALESCE((SELECT carried_over_days FROM alloc), 0)
      - u.used_days
      - u.pending_days) AS remaining_days
  FROM usage u;
$$;


ALTER FUNCTION "public"."get_leave_balance"("p_employee_id" "uuid", "p_leave_type" "text", "p_year" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."get_order_status"("p_id" "uuid", "p_email" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_order public.orders%ROWTYPE;
  v_items jsonb;
  v_is_sandbox boolean;
BEGIN
  SELECT * INTO v_order FROM public.orders WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', 'Order not found');
  END IF;

  -- Lightweight guest auth: if email passed, must match
  IF p_email IS NOT NULL AND lower(coalesce(v_order.customer_email, '')) <> lower(p_email) THEN
    RETURN jsonb_build_object('error', 'Order not found');
  END IF;

  SELECT coalesce(jsonb_agg(jsonb_build_object(
    'id', oi.id,
    'product_name', oi.product_name,
    'quantity', oi.quantity,
    'price_cents', oi.price_cents
  )), '[]'::jsonb) INTO v_items
  FROM public.order_items oi
  WHERE oi.order_id = p_id;

  v_is_sandbox := coalesce((v_order.metadata->>'sandbox')::boolean, false);

  RETURN jsonb_build_object(
    'order', jsonb_build_object(
      'id', v_order.id,
      'status', v_order.status,
      'total_cents', v_order.total_cents,
      'currency', v_order.currency,
      'customer_name', v_order.customer_name,
      'customer_email', v_order.customer_email,
      'created_at', v_order.created_at,
      'updated_at', v_order.updated_at,
      'sandbox', v_is_sandbox
    ),
    'items', v_items
  );
END;
$$;


ALTER FUNCTION "public"."get_order_status"("p_id" "uuid", "p_email" "text") OWNER TO "postgres";


