CREATE OR REPLACE FUNCTION "public"."guard_contracts_require_body"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Allow if a template was used, a file is attached, or body has real content
  IF NEW.template_id IS NOT NULL THEN RETURN NEW; END IF;
  IF NEW.file_url IS NOT NULL AND length(NEW.file_url) > 0 THEN RETURN NEW; END IF;
  IF NEW.body_markdown IS NOT NULL AND length(NEW.body_markdown) >= 200 THEN RETURN NEW; END IF;

  RAISE EXCEPTION 'Contract requires either a template_id, an attached file_url, or body_markdown with at least 200 characters. Use create_contract_from_template, attach a PDF, or write the full agreement text.'
    USING ERRCODE = 'check_violation', HINT = 'Run list_contract_templates to find an existing template, or write body_markdown >= 200 chars.';
END;
$$;


ALTER FUNCTION "public"."guard_contracts_require_body"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."guard_journal_entries_period"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_check_date DATE;
BEGIN
  -- For DELETE the OLD row matters; for INSERT/UPDATE the NEW row
  IF TG_OP = 'DELETE' THEN
    v_check_date := OLD.entry_date;
  ELSE
    v_check_date := NEW.entry_date;
    -- For UPDATE also block if old date was in a closed period
    IF TG_OP = 'UPDATE' AND public.is_period_closed(OLD.entry_date) THEN
      RAISE EXCEPTION 'Cannot modify journal entry: period %-% is closed',
        EXTRACT(YEAR FROM OLD.entry_date)::INTEGER,
        EXTRACT(MONTH FROM OLD.entry_date)::INTEGER
        USING ERRCODE = 'check_violation';
    END IF;
  END IF;

  IF v_check_date IS NOT NULL AND public.is_period_closed(v_check_date) THEN
    RAISE EXCEPTION 'Cannot % journal entry: period %-% is closed',
      LOWER(TG_OP),
      EXTRACT(YEAR FROM v_check_date)::INTEGER,
      EXTRACT(MONTH FROM v_check_date)::INTEGER
      USING ERRCODE = 'check_violation';
  END IF;

  IF TG_OP = 'DELETE' THEN RETURN OLD; ELSE RETURN NEW; END IF;
END;
$$;


ALTER FUNCTION "public"."guard_journal_entries_period"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."guard_journal_entry_lines_period"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_entry_date DATE;
  v_entry_id UUID;
BEGIN
  v_entry_id := COALESCE(NEW.journal_entry_id, OLD.journal_entry_id);
  SELECT entry_date INTO v_entry_date FROM public.journal_entries WHERE id = v_entry_id;
  IF v_entry_date IS NOT NULL AND public.is_period_closed(v_entry_date) THEN
    RAISE EXCEPTION 'Cannot % journal entry line: period %-% is closed',
      LOWER(TG_OP),
      EXTRACT(YEAR FROM v_entry_date)::INTEGER,
      EXTRACT(MONTH FROM v_entry_date)::INTEGER
      USING ERRCODE = 'check_violation';
  END IF;
  IF TG_OP = 'DELETE' THEN RETURN OLD; ELSE RETURN NEW; END IF;
END;
$$;


ALTER FUNCTION "public"."guard_journal_entry_lines_period"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."guard_time_entries_period"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_check_date DATE;
BEGIN
  IF TG_OP = 'DELETE' THEN
    v_check_date := OLD.entry_date;
  ELSE
    v_check_date := NEW.entry_date;
    IF TG_OP = 'UPDATE' AND OLD.entry_date IS NOT NULL
       AND public.is_period_closed(OLD.entry_date) THEN
      RAISE EXCEPTION 'Cannot modify time entry: period %-% is closed (original date %)',
        EXTRACT(YEAR FROM OLD.entry_date)::INTEGER,
        EXTRACT(MONTH FROM OLD.entry_date)::INTEGER,
        OLD.entry_date
        USING ERRCODE = 'check_violation';
    END IF;
  END IF;

  IF v_check_date IS NOT NULL AND public.is_period_closed(v_check_date) THEN
    RAISE EXCEPTION 'Cannot % time entry: period %-% is closed (entry_date %)',
      LOWER(TG_OP),
      EXTRACT(YEAR FROM v_check_date)::INTEGER,
      EXTRACT(MONTH FROM v_check_date)::INTEGER,
      v_check_date
      USING ERRCODE = 'check_violation';
  END IF;

  IF TG_OP = 'DELETE' THEN RETURN OLD; ELSE RETURN NEW; END IF;
END;
$$;


ALTER FUNCTION "public"."guard_time_entries_period"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_deal_won"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_company_id UUID;
BEGIN
  -- Only act on transition INTO closed_won
  IF NEW.stage = 'closed_won' AND (OLD.stage IS DISTINCT FROM 'closed_won') THEN
    -- Bump lead status
    UPDATE public.leads
    SET status = 'customer', updated_at = now()
    WHERE id = NEW.lead_id AND status <> 'customer';

    -- Find lead's company and bump lifecycle
    SELECT company_id INTO v_company_id FROM public.leads WHERE id = NEW.lead_id;
    IF v_company_id IS NOT NULL THEN
      UPDATE public.companies
      SET lifecycle_stage = 'customer',
          customer_since = COALESCE(customer_since, now()),
          updated_at = now()
      WHERE id = v_company_id AND lifecycle_stage <> 'customer';
    END IF;
  END IF;

  -- Optional: handle churn
  IF NEW.stage = 'closed_lost' AND OLD.stage = 'closed_won' THEN
    -- Lost after won = potential churn signal, but don't auto-churn (manual decision)
    NULL;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_deal_won"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_new_user"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  signup_type text;
BEGIN
  signup_type := COALESCE(NEW.raw_user_meta_data ->> 'signup_type', 'admin');

  INSERT INTO public.profiles (id, email, full_name)
  VALUES (
    NEW.id,
    NEW.email,
    COALESCE(NEW.raw_user_meta_data ->> 'full_name', NEW.email)
  )
  ON CONFLICT (id) DO NOTHING;

  IF signup_type = 'customer' THEN
    INSERT INTO public.user_roles (user_id, role)
    VALUES (NEW.id, 'customer')
    ON CONFLICT (user_id, role) DO NOTHING;
  ELSIF signup_type = 'admin' THEN
    INSERT INTO public.user_roles (user_id, role)
    VALUES (NEW.id, 'admin')
    ON CONFLICT (user_id, role) DO NOTHING;
  ELSE
    INSERT INTO public.user_roles (user_id, role)
    VALUES (NEW.id, 'writer')
    ON CONFLICT (user_id, role) DO NOTHING;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_new_user"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_order_to_crm"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_lead_id UUID;
  v_company_id UUID;
  v_domain TEXT;
BEGIN
  IF NEW.customer_email IS NULL OR NEW.customer_email = '' THEN
    RETURN NEW;
  END IF;

  -- Extract domain
  v_domain := LOWER(SPLIT_PART(NEW.customer_email, '@', 2));

  -- Try to match existing company by domain (skip free-mail providers)
  IF v_domain IS NOT NULL AND v_domain NOT IN ('gmail.com','hotmail.com','outlook.com','yahoo.com','icloud.com','live.com','me.com','aol.com','protonmail.com') THEN
    SELECT id INTO v_company_id FROM public.companies
    WHERE LOWER(domain) = v_domain
    LIMIT 1;

    IF v_company_id IS NOT NULL AND NEW.company_id IS NULL THEN
      NEW.company_id := v_company_id;
      -- Bump company to customer
      UPDATE public.companies
      SET lifecycle_stage = 'customer',
          customer_since = COALESCE(customer_since, now()),
          updated_at = now()
      WHERE id = v_company_id AND lifecycle_stage <> 'customer';
    END IF;
  END IF;

  -- Match or create lead
  SELECT id INTO v_lead_id FROM public.leads
  WHERE LOWER(email) = LOWER(NEW.customer_email)
  LIMIT 1;

  IF v_lead_id IS NOT NULL THEN
    UPDATE public.leads
    SET status = 'customer',
        company_id = COALESCE(company_id, v_company_id),
        updated_at = now()
    WHERE id = v_lead_id;
  ELSE
    INSERT INTO public.leads (email, name, source, source_id, status, score, company_id)
    VALUES (
      NEW.customer_email,
      NEW.customer_name,
      'order',
      NEW.id::text,
      'customer',
      50,
      v_company_id
    );
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_order_to_crm"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."handle_stock_movement_event"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_line jsonb;
BEGIN
  IF NEW.event_name <> 'stock.movement' THEN RETURN NEW; END IF;

  -- Two payload shapes supported:
  --   single: { product_id, qty_delta, location_code?, reason? }
  --   batch:  { lines: [ {...}, {...} ], location_code?, reason? }
  IF jsonb_typeof(NEW.payload->'lines') = 'array' THEN
    FOR v_line IN SELECT * FROM jsonb_array_elements(NEW.payload->'lines')
    LOOP
      PERFORM public.apply_stock_movement_event(
        v_line || jsonb_build_object(
          'location_code', COALESCE(v_line->>'location_code', NEW.payload->>'location_code', 'WH/MAIN'),
          'reason', COALESCE(v_line->>'reason', NEW.payload->>'reason', 'event:stock.movement')
        )
      );
    END LOOP;
  ELSE
    PERFORM public.apply_stock_movement_event(NEW.payload);
  END IF;

  RETURN NEW;
EXCEPTION WHEN others THEN
  -- Never block the event insert; log and continue
  RAISE NOTICE 'handle_stock_movement_event failed: %', SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_stock_movement_event"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."handle_stock_movement_event"() IS 'Reactive listener on agent_events: when a stock.movement event is emitted (e.g. by record_pos_sale_v2), automatically decrements/increments the relevant stock_quant on WH/MAIN.';



CREATE OR REPLACE FUNCTION "public"."handle_task_completion"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.status = 'done' AND OLD.status != 'done' THEN
    NEW.completed_at := now();
  ELSIF NEW.status != 'done' AND OLD.status = 'done' THEN
    NEW.completed_at := NULL;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."handle_task_completion"() OWNER TO "postgres";


