CREATE OR REPLACE FUNCTION "public"."link_employee_to_auth_user"("p_employee_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_email text;
  v_user_id uuid;
BEGIN
  SELECT email INTO v_email FROM public.employees WHERE id = p_employee_id;
  IF v_email IS NULL THEN RETURN NULL; END IF;

  SELECT id INTO v_user_id FROM auth.users WHERE lower(email) = lower(v_email) LIMIT 1;
  IF v_user_id IS NULL THEN RETURN NULL; END IF;

  UPDATE public.employees SET user_id = v_user_id, updated_at = now()
  WHERE id = p_employee_id AND (user_id IS NULL OR user_id <> v_user_id);

  -- Grant employee role (idempotent)
  INSERT INTO public.user_roles (user_id, role)
  VALUES (v_user_id, 'employee')
  ON CONFLICT (user_id, role) DO NOTHING;

  RETURN v_user_id;
END;
$$;


ALTER FUNCTION "public"."link_employee_to_auth_user"("p_employee_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."lint_get_not_null_columns"() RETURNS TABLE("table_name" "text", "column_name" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT c.table_name::text, c.column_name::text
  FROM information_schema.columns c
  WHERE c.table_schema = 'public'
    AND c.is_nullable = 'NO'
    AND c.column_default IS NULL;
$$;


