CREATE OR REPLACE FUNCTION "public"."list_reorder_candidates"() RETURNS TABLE("product_id" "uuid", "product_name" "text", "quantity_on_hand" integer, "reorder_point" integer, "reorder_quantity" integer, "vendor_id" "uuid", "vendor_name" "text", "unit_price_cents" integer, "lead_time_days" integer, "min_order_quantity" integer, "estimated_cost_cents" bigint)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT
    p.id, p.name, ps.quantity_on_hand, ps.reorder_point,
    GREATEST(ps.reorder_quantity, COALESCE(vp.min_order_quantity, 1)) AS reorder_qty,
    vp.vendor_id, v.name,
    vp.unit_price_cents, vp.lead_time_days, vp.min_order_quantity,
    GREATEST(ps.reorder_quantity, COALESCE(vp.min_order_quantity, 1))::BIGINT
      * COALESCE(vp.unit_price_cents, 0)::BIGINT
  FROM public.product_stock ps
  JOIN public.products p ON p.id = ps.product_id
  LEFT JOIN public.vendor_products vp ON vp.product_id = p.id AND vp.is_preferred = true
  LEFT JOIN public.vendors v ON v.id = vp.vendor_id AND v.is_active = true
  WHERE ps.auto_reorder = true
    AND ps.quantity_on_hand <= ps.reorder_point
    AND ps.reorder_quantity > 0
  ORDER BY (ps.reorder_point - ps.quantity_on_hand) DESC;
$$;


ALTER FUNCTION "public"."list_reorder_candidates"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."list_voucher_gaps"("p_year" integer DEFAULT (EXTRACT(year FROM CURRENT_DATE))::integer, "p_series" "text" DEFAULT NULL::"text") RETURNS TABLE("series" "text", "fiscal_year" integer, "expected_number" bigint, "next_existing_number" bigint, "gap_size" bigint, "last_seen_date" "date")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  WITH seq AS (
    SELECT voucher_series, voucher_year, voucher_number, entry_date,
           LEAD(voucher_number) OVER (PARTITION BY voucher_series, voucher_year ORDER BY voucher_number) AS next_num
    FROM public.journal_entries
    WHERE voucher_year = p_year AND voucher_number IS NOT NULL
      AND (p_series IS NULL OR voucher_series = p_series)
  )
  SELECT voucher_series, voucher_year, voucher_number + 1, next_num,
         (next_num - voucher_number - 1), entry_date
  FROM seq
  WHERE next_num IS NOT NULL AND next_num > voucher_number + 1
  ORDER BY voucher_series, voucher_number;
$$;


ALTER FUNCTION "public"."list_voucher_gaps"("p_year" integer, "p_series" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."lock_accounting_period"("p_year" integer, "p_month" integer) RETURNS "public"."accounting_periods"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_row public.accounting_periods;
BEGIN
  IF NOT public.has_role(auth.uid(), 'admin'::public.app_role) THEN
    RAISE EXCEPTION 'Only admins can lock accounting periods';
  END IF;

  UPDATE public.accounting_periods
  SET status = 'locked', updated_at = now()
  WHERE fiscal_year = p_year
    AND period_month = p_month
    AND status = 'closed'
  RETURNING * INTO v_row;

  IF v_row.id IS NULL THEN
    RAISE EXCEPTION 'Period %-% not found or not in closed state', p_year, p_month;
  END IF;

  RETURN v_row;
END;
$$;


ALTER FUNCTION "public"."lock_accounting_period"("p_year" integer, "p_month" integer) OWNER TO "postgres";


