CREATE OR REPLACE FUNCTION "public"."lock_payroll_export"("p_export_id" "uuid") RETURNS "public"."payroll_exports"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_row public.payroll_exports;
BEGIN
  IF NOT has_role(auth.uid(), 'admin'::app_role) THEN
    RAISE EXCEPTION 'Only admins can lock payroll exports';
  END IF;
  UPDATE public.payroll_exports
  SET status = 'locked', locked_at = now()
  WHERE id = p_export_id
  RETURNING * INTO v_row;
  RETURN v_row;
END;
$$;


ALTER FUNCTION "public"."lock_payroll_export"("p_export_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."lock_timesheet_period"("p_fiscal_year" integer, "p_period_month" integer, "p_notes" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  _lock_id uuid;
  _entry_count integer;
BEGIN
  IF NOT (has_role(auth.uid(), 'admin'::app_role) OR auth.uid() IS NULL) THEN
    RAISE EXCEPTION 'Only admins can lock timesheet periods';
  END IF;
  IF p_fiscal_year IS NULL OR p_period_month IS NULL THEN
    RAISE EXCEPTION 'fiscal_year and period_month are required';
  END IF;
  IF p_period_month < 1 OR p_period_month > 12 THEN
    RAISE EXCEPTION 'period_month must be 1-12 (got %)', p_period_month;
  END IF;

  INSERT INTO public.timesheet_period_locks (fiscal_year, period_month, notes, locked_by)
  VALUES (p_fiscal_year, p_period_month, p_notes, auth.uid())
  ON CONFLICT (fiscal_year, period_month)
  DO UPDATE SET notes = COALESCE(EXCLUDED.notes, public.timesheet_period_locks.notes),
                locked_at = now(),
                locked_by = auth.uid()
  RETURNING id INTO _lock_id;

  SELECT count(*) INTO _entry_count
  FROM public.time_entries
  WHERE date_part('year', entry_date) = p_fiscal_year
    AND date_part('month', entry_date) = p_period_month;

  PERFORM public.emit_platform_event(
    'timesheet.period_locked',
    jsonb_build_object('fiscal_year', p_fiscal_year, 'period_month', p_period_month, 'entries_locked', _entry_count),
    'lock_timesheet_period'
  );

  RETURN jsonb_build_object(
    'ok', true,
    'lock_id', _lock_id,
    'fiscal_year', p_fiscal_year,
    'period_month', p_period_month,
    'entries_locked', _entry_count
  );
END $$;


ALTER FUNCTION "public"."lock_timesheet_period"("p_fiscal_year" integer, "p_period_month" integer, "p_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."log_ai_usage"("p_source" "text", "p_provider" "text" DEFAULT NULL::"text", "p_model" "text" DEFAULT NULL::"text", "p_prompt_tokens" integer DEFAULT 0, "p_completion_tokens" integer DEFAULT 0, "p_total_tokens" integer DEFAULT 0, "p_latency_ms" integer DEFAULT NULL::integer, "p_status" "text" DEFAULT 'success'::"text", "p_error" "text" DEFAULT NULL::"text", "p_user_id" "uuid" DEFAULT NULL::"uuid", "p_conversation_id" "text" DEFAULT NULL::"text", "p_request_id" "text" DEFAULT NULL::"text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_id uuid;
BEGIN
  IF p_source IS NULL OR length(p_source) = 0 THEN
    RAISE EXCEPTION 'source is required';
  END IF;

  INSERT INTO public.ai_usage_logs (
    source, provider, model,
    prompt_tokens, completion_tokens, total_tokens,
    latency_ms, status, error,
    user_id, conversation_id, request_id, metadata
  ) VALUES (
    p_source,
    p_provider,
    p_model,
    COALESCE(p_prompt_tokens, 0),
    COALESCE(p_completion_tokens, 0),
    COALESCE(p_total_tokens, 0),
    p_latency_ms,
    COALESCE(p_status, 'success'),
    CASE WHEN p_error IS NOT NULL THEN left(p_error, 1000) ELSE NULL END,
    p_user_id,
    p_conversation_id,
    p_request_id,
    COALESCE(p_metadata, '{}'::jsonb)
  )
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."log_ai_usage"("p_source" "text", "p_provider" "text", "p_model" "text", "p_prompt_tokens" integer, "p_completion_tokens" integer, "p_total_tokens" integer, "p_latency_ms" integer, "p_status" "text", "p_error" "text", "p_user_id" "uuid", "p_conversation_id" "text", "p_request_id" "text", "p_metadata" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."log_application_stage_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    INSERT INTO public.application_stages (application_id, from_stage, to_stage, changed_by)
    VALUES (NEW.id, NULL, NEW.stage, auth.uid());
  ELSIF TG_OP = 'UPDATE' AND OLD.stage IS DISTINCT FROM NEW.stage THEN
    INSERT INTO public.application_stages (application_id, from_stage, to_stage, changed_by)
    VALUES (NEW.id, OLD.stage, NEW.stage, auth.uid());
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."log_application_stage_change"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."log_cache_invalidation"("p_slug" "text" DEFAULT NULL::"text", "p_all" boolean DEFAULT false) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id uuid := auth.uid();
BEGIN
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'authentication required';
  END IF;

  INSERT INTO public.audit_logs (action, entity_type, entity_id, user_id, metadata)
  VALUES (
    'cache_invalidate',
    'cache',
    coalesce(p_slug, 'all'),
    v_user_id,
    jsonb_build_object('slug', p_slug, 'all', p_all, 'timestamp', now())
  );

  RETURN jsonb_build_object(
    'success', true,
    'message', CASE WHEN p_all THEN 'All page caches marked for invalidation'
                    ELSE 'Cache for "' || coalesce(p_slug, '') || '" marked for invalidation' END,
    'invalidated_at', now()
  );
END;
$$;


ALTER FUNCTION "public"."log_cache_invalidation"("p_slug" "text", "p_all" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."log_mo_cancellation"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.status = 'cancelled' AND (OLD.status IS DISTINCT FROM 'cancelled') THEN
    INSERT INTO public.audit_logs (action, entity_type, entity_id, user_id, metadata)
    VALUES (
      'mo.cancelled',
      'manufacturing_order',
      NEW.id,
      auth.uid(),
      jsonb_build_object(
        'mo_number', NEW.mo_number,
        'product_id', NEW.product_id,
        'previous_status', OLD.status,
        'cancelled_at', COALESCE(NEW.cancelled_at, now()),
        'quantity', NEW.quantity,
        'notes_tail', RIGHT(COALESCE(NEW.notes, ''), 500)
      )
    );
  ELSIF NEW.status = 'done' AND (OLD.status IS DISTINCT FROM 'done') THEN
    INSERT INTO public.audit_logs (action, entity_type, entity_id, user_id, metadata)
    VALUES (
      'mo.completed',
      'manufacturing_order',
      NEW.id,
      auth.uid(),
      jsonb_build_object(
        'mo_number', NEW.mo_number,
        'product_id', NEW.product_id,
        'previous_status', OLD.status,
        'completed_at', COALESCE(NEW.completed_at, now()),
        'quantity', NEW.quantity
      )
    );
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."log_mo_cancellation"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."log_role_module_access_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    INSERT INTO public.audit_logs (action, entity_type, entity_id, user_id, metadata)
    VALUES (
      'role_module_access.grant',
      'role_module_access',
      NULL,
      auth.uid(),
      jsonb_build_object('role', NEW.role, 'module_id', NEW.module_id)
    );
    RETURN NEW;
  ELSIF TG_OP = 'DELETE' THEN
    INSERT INTO public.audit_logs (action, entity_type, entity_id, user_id, metadata)
    VALUES (
      'role_module_access.revoke',
      'role_module_access',
      NULL,
      auth.uid(),
      jsonb_build_object('role', OLD.role, 'module_id', OLD.module_id)
    );
    RETURN OLD;
  END IF;
  RETURN NULL;
END;
$$;


ALTER FUNCTION "public"."log_role_module_access_change"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."lookup_order_tracking"("p_order_id" "uuid", "p_email" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_order record;
  v_items jsonb;
BEGIN
  IF p_order_id IS NULL OR p_email IS NULL OR length(trim(p_email)) = 0 THEN
    RETURN jsonb_build_object('found', false, 'reason', 'missing_params');
  END IF;

  SELECT id, customer_email, customer_name, status, fulfillment_status,
         total_cents, currency, created_at,
         picked_at, packed_at, shipped_at, delivered_at,
         tracking_number, tracking_url
    INTO v_order
  FROM public.orders
  WHERE id = p_order_id
    AND lower(customer_email) = lower(trim(p_email))
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('found', false, 'reason', 'not_found');
  END IF;

  SELECT COALESCE(jsonb_agg(jsonb_build_object(
           'product_name', product_name,
           'quantity', quantity,
           'price_cents', price_cents
         ) ORDER BY product_name), '[]'::jsonb)
    INTO v_items
  FROM public.order_items
  WHERE order_id = v_order.id;

  RETURN jsonb_build_object(
    'found', true,
    'order', jsonb_build_object(
      'id', v_order.id,
      'customer_name', v_order.customer_name,
      'customer_email', v_order.customer_email,
      'status', v_order.status,
      'fulfillment_status', COALESCE(v_order.fulfillment_status, 'unfulfilled'),
      'total_cents', v_order.total_cents,
      'currency', v_order.currency,
      'created_at', v_order.created_at,
      'picked_at', v_order.picked_at,
      'packed_at', v_order.packed_at,
      'shipped_at', v_order.shipped_at,
      'delivered_at', v_order.delivered_at,
      'tracking_number', v_order.tracking_number,
      'tracking_url', v_order.tracking_url
    ),
    'items', v_items
  );
END $$;


ALTER FUNCTION "public"."lookup_order_tracking"("p_order_id" "uuid", "p_email" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."mark_expense_report_paid"("p_report_id" "uuid", "p_method" "text" DEFAULT 'manual'::"text", "p_reference" "text" DEFAULT NULL::"text", "p_paid_at" "date" DEFAULT NULL::"date", "p_bank_account" "text" DEFAULT '1930'::"text", "p_liability_account" "text" DEFAULT '2890'::"text", "p_notes" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_report record;
  v_total_cents bigint;
  v_entry_id uuid;
  v_payment_id uuid;
  v_date date;
BEGIN
  SELECT * INTO v_report FROM expense_reports WHERE id = p_report_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Report not found');
  END IF;
  IF v_report.status <> 'booked' THEN
    RETURN jsonb_build_object('success', false, 'error', 'Only booked reports can be marked paid');
  END IF;

  SELECT COALESCE(SUM(amount_cents),0) INTO v_total_cents
  FROM expenses WHERE report_id = p_report_id;

  v_date := COALESCE(p_paid_at, CURRENT_DATE);

  INSERT INTO journal_entries (entry_date, description, source, source_id, status)
  VALUES (v_date, 'Payment of expense report ' || p_report_id::text, 'expense_payment', p_report_id, 'posted')
  RETURNING id INTO v_entry_id;

  INSERT INTO journal_entry_lines (entry_id, account_code, debit_cents, credit_cents, description)
  VALUES
    (v_entry_id, p_liability_account, v_total_cents, 0, 'Settle liability'),
    (v_entry_id, p_bank_account, 0, v_total_cents, 'Bank payment');

  INSERT INTO expense_payments (report_id, amount_cents, method, reference, paid_at, journal_entry_id, notes)
  VALUES (p_report_id, v_total_cents, p_method::text, p_reference, v_date, v_entry_id, p_notes)
  RETURNING id INTO v_payment_id;

  UPDATE expense_reports
  SET status = 'paid', paid_at = v_date
  WHERE id = p_report_id;

  RETURN jsonb_build_object('success', true, 'report_id', p_report_id, 'payment_id', v_payment_id, 'journal_entry_id', v_entry_id);
END;
$$;


ALTER FUNCTION "public"."mark_expense_report_paid"("p_report_id" "uuid", "p_method" "text", "p_reference" "text", "p_paid_at" "date", "p_bank_account" "text", "p_liability_account" "text", "p_notes" "text") OWNER TO "postgres";


