      jsonb_build_object(
        'response_id', NEW.id,
        'campaign_id', NEW.campaign_id,
        'score', NEW.score,
        'category', NEW.category,
        'recipient_email', NEW.recipient_email,
        'lead_id', NEW.lead_id
      ),
      'surveys'
    );
  END IF;
  RETURN NEW;
END;
$$;


