CREATE OR REPLACE FUNCTION "public"."mark_webinar_attendance"("p_registration_id" "uuid", "p_attended" boolean DEFAULT true) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_reg webinar_registrations%ROWTYPE;
BEGIN
  IF NOT (has_role(auth.uid(),'writer') OR has_role(auth.uid(),'approver') OR has_role(auth.uid(),'admin')) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  UPDATE webinar_registrations SET attended=p_attended WHERE id=p_registration_id RETURNING * INTO v_reg;
  IF NOT FOUND THEN RAISE EXCEPTION 'registration % not found', p_registration_id; END IF;
  IF p_attended AND v_reg.lead_id IS NOT NULL THEN
    UPDATE leads SET score = COALESCE(score,0) + 10, updated_at=now() WHERE id = v_reg.lead_id;
  END IF;
  PERFORM emit_platform_event('webinar.attended', jsonb_build_object('webinar_id',v_reg.webinar_id,'registration_id',v_reg.id,'lead_id',v_reg.lead_id,'attended',p_attended), 'webinars');
  RETURN jsonb_build_object('success',true,'id',v_reg.id,'attended',p_attended);
END $$;


ALTER FUNCTION "public"."mark_webinar_attendance"("p_registration_id" "uuid", "p_attended" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."match_consultants"("query_embedding" "extensions"."vector", "query_text" "text" DEFAULT NULL::"text", "match_count" integer DEFAULT 10, "semantic_weight" double precision DEFAULT 0.6, "only_active" boolean DEFAULT true, "rrf_k" integer DEFAULT 60) RETURNS TABLE("id" "uuid", "name" "text", "title" "text", "skills" "text"[], "experience_years" integer, "availability" "text", "summary" "text", "semantic_score" double precision, "text_score" double precision, "semantic_rank" integer, "text_rank" integer, "hybrid_score" double precision)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
  with q as (
    select public.build_or_tsquery(query_text) as tsq
  ),
  candidates as (
    select c.*
    from public.consultant_profiles c
    where (not only_active or c.is_active = true)
      -- skip empty placeholder profiles
      and (
        coalesce(length(trim(c.title)), 0) > 0
        or coalesce(array_length(c.skills, 1), 0) > 0
        or coalesce(length(trim(c.summary)), 0) > 0
        or coalesce(length(trim(c.bio)), 0) > 0
      )
  ),
  semantic as (
    select c.id,
           1 - (c.embedding operator(extensions.<=>) query_embedding) as score,
           row_number() over (order by c.embedding operator(extensions.<=>) query_embedding asc) as rnk
    from candidates c
    where query_embedding is not null and c.embedding is not null
    order by c.embedding operator(extensions.<=>) query_embedding asc
    limit greatest(match_count * 4, 20)
  ),
  textual as (
    select c.id,
           ts_rank_cd(c.search_tsv, (select tsq from q)) as score,
           row_number() over (order by ts_rank_cd(c.search_tsv, (select tsq from q)) desc) as rnk
    from candidates c
    where (select tsq from q) is not null
      and c.search_tsv @@ (select tsq from q)
    order by ts_rank_cd(c.search_tsv, (select tsq from q)) desc
    limit greatest(match_count * 4, 20)
  ),
  fused as (
    select
      c.id, c.name, c.title, c.skills, c.experience_years, c.availability, c.summary,
      coalesce(s.score, 0)::float as semantic_score,
      coalesce(t.score, 0)::float as text_score,
      s.rnk::int as semantic_rank,
      t.rnk::int as text_rank,
      (case when s.rnk is not null then 1.0 / (rrf_k + s.rnk) else 0 end
       + case when t.rnk is not null then 1.0 / (rrf_k + t.rnk) else 0 end)::float as hybrid_score
    from candidates c
    left join semantic s on s.id = c.id
    left join textual  t on t.id = c.id
    where s.id is not null or t.id is not null
  )
  select id, name, title, skills, experience_years, availability, summary,
         semantic_score, text_score, semantic_rank, text_rank, hybrid_score
  from fused
  order by hybrid_score desc, semantic_score desc
  limit match_count;
$$;


ALTER FUNCTION "public"."match_consultants"("query_embedding" "extensions"."vector", "query_text" "text", "match_count" integer, "semantic_weight" double precision, "only_active" boolean, "rrf_k" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."match_invoice_to_receipt"("p_invoice_id" "uuid", "p_tolerance_pct" numeric DEFAULT 2.0) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_inv record;
  v_po_total bigint;
  v_received_value bigint;
  v_variance bigint;
  v_variance_pct numeric;
  v_match_status text;
  v_notes text;
BEGIN
  SELECT * INTO v_inv FROM vendor_invoices WHERE id = p_invoice_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Invoice % not found', p_invoice_id; END IF;

  IF v_inv.purchase_order_id IS NULL THEN
    UPDATE vendor_invoices
      SET match_status = 'no_po', variance_cents = 0,
          variance_notes = 'Invoice not linked to any PO', updated_at = now()
      WHERE id = p_invoice_id;
    RETURN jsonb_build_object('success', true, 'match_status', 'no_po');
  END IF;

  -- Sum the value of received goods on this PO
  SELECT
    COALESCE(SUM(grl.quantity_received * pol.unit_price_cents), 0)::bigint
  INTO v_received_value
  FROM goods_receipt_lines grl
  JOIN goods_receipts gr ON gr.id = grl.goods_receipt_id
  JOIN purchase_order_lines pol ON pol.id = grl.po_line_id
  WHERE gr.purchase_order_id = v_inv.purchase_order_id;

  SELECT total_cents INTO v_po_total FROM purchase_orders WHERE id = v_inv.purchase_order_id;

  -- Variance = invoice - received (positive = over-invoiced)
  v_variance := v_inv.subtotal_cents - v_received_value;
  v_variance_pct := CASE WHEN v_received_value > 0
    THEN abs(v_variance)::numeric / v_received_value * 100
    ELSE 100 END;

  IF v_received_value = 0 THEN
    v_match_status := 'no_receipt';
    v_notes := 'No goods received yet against this PO';
  ELSIF v_variance_pct <= p_tolerance_pct THEN
    v_match_status := 'matched';
    v_notes := format('Within %.2f%% tolerance', p_tolerance_pct);
  ELSIF v_variance > 0 THEN
    v_match_status := 'over_invoiced';
    v_notes := format('Invoice %s cents > received value %s cents (%.2f%% variance)',
                       v_inv.subtotal_cents, v_received_value, v_variance_pct);
  ELSE
    v_match_status := 'under_invoiced';
    v_notes := format('Invoice %s cents < received value %s cents (%.2f%% variance)',
                       v_inv.subtotal_cents, v_received_value, v_variance_pct);
  END IF;

  UPDATE vendor_invoices
    SET match_status = v_match_status,
        variance_cents = v_variance,
        variance_notes = v_notes,
        updated_at = now()
    WHERE id = p_invoice_id;

  -- Emit event for downstream automation (FlowPilot can auto-approve matched, escalate variance)
  PERFORM public.emit_platform_event(
    'invoice.matched',
    jsonb_build_object(
      'invoice_id', p_invoice_id,
      'purchase_order_id', v_inv.purchase_order_id,
      'match_status', v_match_status,
      'variance_cents', v_variance,
      'variance_pct', round(v_variance_pct, 2)
    ),
    'match_invoice_to_receipt'
  );

  RETURN jsonb_build_object(
    'success', true,
    'invoice_id', p_invoice_id,
    'match_status', v_match_status,
    'variance_cents', v_variance,
    'variance_pct', round(v_variance_pct, 2),
    'received_value_cents', v_received_value,
    'po_total_cents', v_po_total,
    'notes', v_notes
  );
END;
$$;


ALTER FUNCTION "public"."match_invoice_to_receipt"("p_invoice_id" "uuid", "p_tolerance_pct" numeric) OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."vendor_invoices" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "invoice_number" "text" NOT NULL,
    "vendor_id" "uuid" NOT NULL,
    "purchase_order_id" "uuid",
    "invoice_date" "date" DEFAULT CURRENT_DATE NOT NULL,
    "due_date" "date",
    "subtotal_cents" bigint DEFAULT 0 NOT NULL,
    "tax_cents" bigint DEFAULT 0 NOT NULL,
    "total_cents" bigint DEFAULT 0 NOT NULL,
    "currency" "text" DEFAULT 'SEK'::"text" NOT NULL,
    "status" "text" DEFAULT 'received'::"text" NOT NULL,
    "match_status" "text" DEFAULT 'unmatched'::"text" NOT NULL,
    "variance_cents" bigint DEFAULT 0 NOT NULL,
    "variance_notes" "text",
    "approved_by" "uuid",
    "approved_at" timestamp with time zone,
    "paid_at" timestamp with time zone,
    "notes" "text",
    "created_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "vendor_invoices_match_status_check" CHECK (("match_status" = ANY (ARRAY['unmatched'::"text", 'matched'::"text", 'partial'::"text", 'variance'::"text"]))),
    CONSTRAINT "vendor_invoices_status_check" CHECK (("status" = ANY (ARRAY['received'::"text", 'matched'::"text", 'variance'::"text", 'approved'::"text", 'rejected'::"text", 'paid'::"text"])))
);


ALTER TABLE "public"."vendor_invoices" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."match_po_to_invoice"("p_invoice_id" "uuid", "p_variance_tolerance_pct" numeric DEFAULT 2.0) RETURNS "public"."vendor_invoices"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_inv public.vendor_invoices;
  v_po public.purchase_orders;
  v_received_total BIGINT := 0;
  v_variance BIGINT;
  v_variance_pct NUMERIC;
  v_match_status TEXT; v_new_status TEXT; v_notes TEXT;
BEGIN
  IF auth.uid() IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF;
  SELECT * INTO v_inv FROM public.vendor_invoices WHERE id = p_invoice_id FOR UPDATE;
  IF v_inv.id IS NULL THEN RAISE EXCEPTION 'Vendor invoice not found'; END IF;
  IF v_inv.purchase_order_id IS NULL THEN RAISE EXCEPTION 'Invoice has no linked purchase order'; END IF;
  SELECT * INTO v_po FROM public.purchase_orders WHERE id = v_inv.purchase_order_id;
  IF v_po.id IS NULL THEN RAISE EXCEPTION 'Linked purchase order not found'; END IF;
  SELECT COALESCE(SUM(pol.received_quantity * pol.unit_price_cents), 0) INTO v_received_total
    FROM public.purchase_order_lines pol WHERE pol.purchase_order_id = v_po.id;
  v_variance := v_inv.total_cents - v_received_total;
  v_variance_pct := CASE WHEN v_received_total = 0 THEN 100
                         ELSE ABS(v_variance)::NUMERIC / v_received_total * 100 END;
  IF v_received_total = 0 THEN
    v_match_status := 'unmatched'; v_new_status := 'variance';
    v_notes := 'No goods receipts recorded against PO';
  ELSIF v_variance_pct <= p_variance_tolerance_pct THEN
    v_match_status := 'matched'; v_new_status := 'matched';
    v_notes := format('3-way match OK (variance %.2f%% within %.2f%%)', v_variance_pct, p_variance_tolerance_pct);
  ELSE
    v_match_status := 'variance'; v_new_status := 'variance';
    v_notes := format('Variance %.2f%% exceeds tolerance %.2f%% (invoice %s vs received %s)',
      v_variance_pct, p_variance_tolerance_pct, v_inv.total_cents, v_received_total);
  END IF;
  UPDATE public.vendor_invoices
  SET match_status = v_match_status, status = v_new_status,
      variance_cents = v_variance, variance_notes = v_notes, updated_at = now()
  WHERE id = p_invoice_id RETURNING * INTO v_inv;
  RETURN v_inv;
END; $$;


ALTER FUNCTION "public"."match_po_to_invoice"("p_invoice_id" "uuid", "p_variance_tolerance_pct" numeric) OWNER TO "postgres";


