CREATE OR REPLACE FUNCTION "public"."prevent_manager_cycle"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.manager_id IS NULL THEN
    RETURN NEW;
  END IF;

  IF NEW.manager_id = NEW.id THEN
    RAISE EXCEPTION 'An employee cannot be their own manager';
  END IF;

  -- Walk up the chain to detect cycle
  IF EXISTS (
    WITH RECURSIVE chain AS (
      SELECT id, manager_id FROM public.employees WHERE id = NEW.manager_id
      UNION ALL
      SELECT e.id, e.manager_id FROM public.employees e
      JOIN chain c ON e.id = c.manager_id
    )
    SELECT 1 FROM chain WHERE id = NEW.id
  ) THEN
    RAISE EXCEPTION 'Cycle detected: this employee is already in the manager chain above';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."prevent_manager_cycle"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."preview_payroll_period"("p_year" integer, "p_month" integer) RETURNS TABLE("employee_id" "uuid", "employee_name" "text", "employee_email" "text", "personal_number" "text", "vacation_days" numeric, "sick_days" numeric, "parental_days" numeric, "other_leave_days" numeric, "expense_reimbursement_cents" bigint, "representation_cents" bigint, "expense_count" integer, "leave_request_ids" "uuid"[], "expense_ids" "uuid"[])
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  WITH period AS (
    SELECT
      make_date(p_year, p_month, 1) AS start_date,
      (make_date(p_year, p_month, 1) + INTERVAL '1 month' - INTERVAL '1 day')::date AS end_date
  ),
  leave_agg AS (
    SELECT
      lr.employee_id,
      COALESCE(SUM(CASE WHEN lr.leave_type = 'vacation' THEN lr.days ELSE 0 END), 0)::numeric AS vacation_days,
      COALESCE(SUM(CASE WHEN lr.leave_type = 'sick' THEN lr.days ELSE 0 END), 0)::numeric AS sick_days,
      COALESCE(SUM(CASE WHEN lr.leave_type = 'parental' THEN lr.days ELSE 0 END), 0)::numeric AS parental_days,
      COALESCE(SUM(CASE WHEN lr.leave_type NOT IN ('vacation','sick','parental') THEN lr.days ELSE 0 END), 0)::numeric AS other_leave_days,
      array_agg(lr.id) AS leave_request_ids
    FROM public.leave_requests lr, period
    WHERE lr.status = 'approved'
      AND lr.payroll_export_id IS NULL
      AND lr.start_date <= period.end_date
      AND lr.end_date >= period.start_date
    GROUP BY lr.employee_id
  ),
  expense_agg AS (
    SELECT
      e.user_id,
      COALESCE(SUM(CASE WHEN NOT e.is_representation THEN e.amount_cents ELSE 0 END), 0)::bigint AS expense_reimbursement_cents,
      COALESCE(SUM(CASE WHEN e.is_representation THEN e.amount_cents ELSE 0 END), 0)::bigint AS representation_cents,
      COUNT(*)::int AS expense_count,
      array_agg(e.id) AS expense_ids
    FROM public.expenses e, period
    WHERE e.status = 'approved'
      AND e.payroll_export_id IS NULL
      AND e.expense_date BETWEEN period.start_date AND period.end_date
    GROUP BY e.user_id
  )
  SELECT
    emp.id,
    emp.name,
    emp.email,
    emp.personal_number,
    COALESCE(la.vacation_days, 0),
    COALESCE(la.sick_days, 0),
    COALESCE(la.parental_days, 0),
    COALESCE(la.other_leave_days, 0),
    COALESCE(ea.expense_reimbursement_cents, 0),
    COALESCE(ea.representation_cents, 0),
    COALESCE(ea.expense_count, 0),
    COALESCE(la.leave_request_ids, '{}'::uuid[]),
    COALESCE(ea.expense_ids, '{}'::uuid[])
  FROM public.employees emp
  LEFT JOIN leave_agg la ON la.employee_id = emp.id
  LEFT JOIN expense_agg ea ON ea.user_id = emp.user_id
  WHERE emp.status = 'active'
    AND (la.employee_id IS NOT NULL OR ea.user_id IS NOT NULL)
  ORDER BY emp.name;
$$;


ALTER FUNCTION "public"."preview_payroll_period"("p_year" integer, "p_month" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."procurement_run"() RETURNS TABLE("suggestions_created" integer, "rules_evaluated" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_rule record; v_on_hand numeric; v_reserved numeric; v_incoming numeric; v_virtual numeric; v_qty_to_order numeric; v_count integer := 0; v_evaluated integer := 0;
BEGIN
  IF NOT (has_role(auth.uid(),'writer'::app_role) OR has_role(auth.uid(),'admin'::app_role)) THEN RAISE EXCEPTION 'Insufficient privileges'; END IF;
  FOR v_rule IN SELECT * FROM reorder_rules WHERE is_active = true LOOP
    v_evaluated := v_evaluated + 1;
    SELECT COALESCE(SUM(quantity),0), COALESCE(SUM(reserved_quantity),0) INTO v_on_hand, v_reserved
      FROM stock_quants WHERE product_id = v_rule.product_id AND location_id = v_rule.location_id;
    SELECT COALESCE(SUM(pol.quantity - COALESCE(pol.received_quantity,0)),0) INTO v_incoming
      FROM purchase_order_lines pol JOIN purchase_orders po ON po.id = pol.purchase_order_id
      WHERE pol.product_id = v_rule.product_id AND po.status IN ('draft','sent','confirmed','partial');
    v_virtual := v_on_hand - v_reserved + COALESCE(v_incoming,0);
    IF v_virtual < v_rule.min_qty THEN
      v_qty_to_order := COALESCE(NULLIF(v_rule.reorder_qty,0), v_rule.max_qty - v_virtual);
      IF v_qty_to_order <= 0 THEN v_qty_to_order := v_rule.min_qty - v_virtual; END IF;
      IF NOT EXISTS (SELECT 1 FROM procurement_suggestions WHERE product_id = v_rule.product_id AND location_id = v_rule.location_id AND status = 'pending') THEN
        INSERT INTO procurement_suggestions (product_id, location_id, suggested_qty, procurement_method, preferred_vendor_id, needed_by, reasoning)
        VALUES (v_rule.product_id, v_rule.location_id, v_qty_to_order, v_rule.procurement_method, v_rule.preferred_vendor_id,
          (CURRENT_DATE + (v_rule.lead_time_days || ' days')::interval)::date,
          jsonb_build_object('on_hand', v_on_hand, 'reserved', v_reserved, 'incoming', v_incoming, 'virtual', v_virtual, 'min_qty', v_rule.min_qty, 'max_qty', v_rule.max_qty));
        v_count := v_count + 1;
      END IF;
    END IF;
  END LOOP;
  RETURN QUERY SELECT v_count, v_evaluated;
END; $$;


ALTER FUNCTION "public"."procurement_run"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."propose_accruals"("p_year" integer) RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_year_end date := make_date(p_year, 12, 31);
  v_invoices jsonb := '[]'::jsonb;
  v_expenses jsonb := '[]'::jsonb;
BEGIN
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'source','invoice','source_id',i.id,'reference',i.invoice_number,
    'issue_date',i.issue_date,'due_date',i.due_date,
    'amount_cents',i.total_cents - COALESCE(i.paid_amount_cents,0),
    'suggested_action', CASE WHEN i.due_date > v_year_end THEN 'defer_revenue' ELSE 'accrue_receivable' END
  )), '[]'::jsonb) INTO v_invoices
  FROM public.invoices i
  WHERE EXTRACT(YEAR FROM i.issue_date) = p_year
    AND i.status::text NOT IN ('paid','cancelled','void')
    AND (i.total_cents - COALESCE(i.paid_amount_cents,0)) > 0;

  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'source','expense_report','source_id',er.id,
    'amount_cents',er.total_cents,'status',er.status,
    'suggested_action','accrue_payable'
  )), '[]'::jsonb) INTO v_expenses
  FROM public.expense_reports er
  WHERE er.status IN ('approved','booked') AND er.total_cents > 0;

  RETURN jsonb_build_object(
    'year', p_year, 'year_end', v_year_end,
    'proposals', v_invoices || v_expenses,
    'proposal_count', jsonb_array_length(v_invoices) + jsonb_array_length(v_expenses),
    'note', 'Universal accrual scan. Locale packs add country-specific proposals via year_end_proposals callback.'
  );
END; $$;


ALTER FUNCTION "public"."propose_accruals"("p_year" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."propose_annual_depreciation"("p_year" integer) RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_year_end date := make_date(p_year, 12, 31);
  v_proposals jsonb;
BEGIN
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'asset_id', fa.id, 'asset_name', fa.name,
    'depreciation_account', fa.depreciation_account,
    'accumulated_account', fa.accumulated_account,
    'method', fa.depreciation_method,
    'annual_amount_cents', CASE
      WHEN fa.depreciation_method = 'straight_line'
        THEN (fa.cost_cents - fa.salvage_cents) / fa.useful_life_months * 12
      WHEN fa.depreciation_method = 'declining' AND fa.declining_rate IS NOT NULL
        THEN ROUND((fa.cost_cents - fa.accumulated_cents) * fa.declining_rate)::bigint
      ELSE 0 END,
    'remaining_after_cents', fa.cost_cents - fa.accumulated_cents
  )), '[]'::jsonb) INTO v_proposals
  FROM public.fixed_assets fa
  WHERE fa.status = 'active' AND fa.in_service_date <= v_year_end
    AND fa.accumulated_cents < (fa.cost_cents - fa.salvage_cents);

  RETURN jsonb_build_object(
    'year', p_year, 'asset_count', jsonb_array_length(v_proposals),
    'proposals', v_proposals,
    'note', 'Post via manage_journal_entry per asset (staged for approval).'
  );
END; $$;


ALTER FUNCTION "public"."propose_annual_depreciation"("p_year" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."publish_scheduled_pages"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_now timestamptz := now();
  v_page record;
  v_published int := 0;
  v_results jsonb := '[]'::jsonb;
BEGIN
  FOR v_page IN
    SELECT id, title, slug, scheduled_at
    FROM public.pages
    WHERE status = 'reviewing'
      AND scheduled_at IS NOT NULL
      AND scheduled_at <= v_now
  LOOP
    UPDATE public.pages
       SET status = 'published',
           scheduled_at = NULL,
           updated_at = v_now
     WHERE id = v_page.id;

    INSERT INTO public.audit_logs (action, entity_type, entity_id, metadata)
    VALUES (
      'scheduled_publish',
      'page',
      v_page.id::text,
      jsonb_build_object('title', v_page.title, 'slug', v_page.slug, 'scheduled_at', v_page.scheduled_at)
    );

    INSERT INTO public.audit_logs (action, entity_type, entity_id, metadata)
    VALUES (
      'cache_invalidate',
      'cache',
      v_page.slug,
      jsonb_build_object('slug', v_page.slug, 'source', 'scheduled_publish', 'timestamp', v_now)
    );

    v_published := v_published + 1;
    v_results := v_results || jsonb_build_object('id', v_page.id, 'title', v_page.title, 'success', true);
  END LOOP;

  RETURN jsonb_build_object('success', true, 'published', v_published, 'results', v_results);
END;
$$;


ALTER FUNCTION "public"."publish_scheduled_pages"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."publish_webinar"("p_webinar_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_row webinars%ROWTYPE;
BEGIN
  IF NOT (has_role(auth.uid(),'writer') OR has_role(auth.uid(),'approver') OR has_role(auth.uid(),'admin')) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  UPDATE webinars SET status='published', updated_at=now() WHERE id=p_webinar_id AND status='draft' RETURNING * INTO v_row;
  IF NOT FOUND THEN RAISE EXCEPTION 'webinar % not found or not in draft', p_webinar_id; END IF;
  PERFORM emit_platform_event('webinar.published', jsonb_build_object('webinar_id',v_row.id,'title',v_row.title,'date',v_row.date), 'webinars');
  RETURN jsonb_build_object('success',true,'id',v_row.id,'status',v_row.status);
END $$;


ALTER FUNCTION "public"."publish_webinar"("p_webinar_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."purge_audit_logs_past_retention"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_deleted int;
BEGIN
  WITH del AS (
    DELETE FROM public.audit_logs
    WHERE created_at < now() - interval '730 days'
    RETURNING id
  )
  SELECT COUNT(*) INTO v_deleted FROM del;

  INSERT INTO public.audit_logs (action, entity_type, metadata)
  VALUES (
    'audit_logs.retention.purge',
    'system',
    jsonb_build_object('deleted_rows', v_deleted, 'retention_days', 730, 'ran_at', now())
  );

  RETURN jsonb_build_object('deleted_rows', v_deleted, 'ran_at', now());
END;
$$;


ALTER FUNCTION "public"."purge_audit_logs_past_retention"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."recalc_bank_tx_match_status"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_tx_id UUID;
  v_total_matched BIGINT;
  v_tx_amount BIGINT;
BEGIN
  v_tx_id := COALESCE(NEW.bank_transaction_id, OLD.bank_transaction_id);
  
  SELECT COALESCE(SUM(ABS(amount_cents)), 0) INTO v_total_matched
  FROM public.reconciliation_matches WHERE bank_transaction_id = v_tx_id;
  
  SELECT ABS(amount_cents) INTO v_tx_amount
  FROM public.bank_transactions WHERE id = v_tx_id;
  
  UPDATE public.bank_transactions
  SET matched_amount_cents = v_total_matched,
      status = CASE
        WHEN v_total_matched = 0 THEN 'unmatched'
        WHEN v_total_matched >= v_tx_amount THEN 'matched'
        ELSE 'partial'
      END,
      updated_at = now()
  WHERE id = v_tx_id;
  
  RETURN NULL;
END;
$$;


ALTER FUNCTION "public"."recalc_bank_tx_match_status"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."recalc_quote_item"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_gross BIGINT;
  v_after_disc BIGINT;
BEGIN
  v_gross := ROUND(NEW.quantity * NEW.unit_price_cents);
  v_after_disc := ROUND(v_gross * (1 - NEW.discount_pct / 100.0));
  NEW.line_subtotal_cents := v_after_disc;
  NEW.line_tax_cents := ROUND(v_after_disc * (NEW.tax_rate_pct / 100.0));
  NEW.line_total_cents := NEW.line_subtotal_cents + NEW.line_tax_cents;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."recalc_quote_item"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."recalc_quote_totals"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_quote_id UUID;
  v_sub BIGINT;
  v_tax BIGINT;
  v_total BIGINT;
  v_item_count INTEGER;
BEGIN
  v_quote_id := COALESCE(NEW.quote_id, OLD.quote_id);
  SELECT COUNT(*), COALESCE(SUM(line_subtotal_cents), 0), COALESCE(SUM(line_tax_cents), 0), COALESCE(SUM(line_total_cents), 0)
  INTO v_item_count, v_sub, v_tax, v_total
  FROM public.quote_items WHERE quote_id = v_quote_id;
  IF v_item_count > 0 THEN
    UPDATE public.quotes
    SET subtotal_cents = v_sub, tax_cents = v_tax, total_cents = v_total, updated_at = now()
    WHERE id = v_quote_id;
  END IF;
  RETURN NULL;
END;
$$;


ALTER FUNCTION "public"."recalc_quote_totals"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."receive_purchase_order"("p_purchase_order_id" "uuid", "p_lines" "jsonb", "p_to_location_id" "uuid" DEFAULT NULL::"uuid", "p_received_date" "date" DEFAULT CURRENT_DATE, "p_notes" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_receipt_id uuid;
  v_po record;
  v_vendor_loc uuid;
  v_to_loc uuid := p_to_location_id;
  v_line jsonb;
  v_pol record;
  v_new_received int;
  v_lot_id uuid;
  v_all_received boolean;
  v_some_received boolean;
  v_new_status purchase_order_status;
  v_lines_inserted int := 0;
  v_total_qty int := 0;
BEGIN
  -- Validate PO
  SELECT * INTO v_po FROM purchase_orders WHERE id = p_purchase_order_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Purchase order % not found', p_purchase_order_id;
  END IF;

  IF v_po.status NOT IN ('sent', 'confirmed', 'partially_received') THEN
    RAISE EXCEPTION 'Cannot receive PO in status %', v_po.status;
  END IF;

  IF jsonb_array_length(p_lines) = 0 THEN
    RAISE EXCEPTION 'No lines provided';
  END IF;

  -- Resolve default destination location (first internal)
  IF v_to_loc IS NULL THEN
    SELECT id INTO v_to_loc FROM stock_locations
      WHERE location_type = 'internal' AND is_active = true
      ORDER BY created_at LIMIT 1;
  END IF;

  -- Vendor source location
  SELECT id INTO v_vendor_loc FROM stock_locations
    WHERE location_type = 'vendor' AND is_active = true
    ORDER BY created_at LIMIT 1;

  -- Create receipt header
  INSERT INTO goods_receipts (purchase_order_id, received_date, notes, created_by)
  VALUES (p_purchase_order_id, p_received_date, p_notes, auth.uid())
  RETURNING id INTO v_receipt_id;

  -- Process each line
  FOR v_line IN SELECT * FROM jsonb_array_elements(p_lines)
  LOOP
    SELECT * INTO v_pol FROM purchase_order_lines
      WHERE id = (v_line->>'po_line_id')::uuid
        AND purchase_order_id = p_purchase_order_id;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'PO line % does not belong to PO %', v_line->>'po_line_id', p_purchase_order_id;
    END IF;

    DECLARE
      v_qty int := (v_line->>'quantity_received')::int;
    BEGIN
      IF v_qty <= 0 THEN CONTINUE; END IF;

      -- Cap at remaining quantity to prevent over-receipt
      IF v_pol.received_quantity + v_qty > v_pol.quantity THEN
        v_qty := v_pol.quantity - v_pol.received_quantity;
        IF v_qty <= 0 THEN CONTINUE; END IF;
      END IF;

      -- Insert receipt line
      INSERT INTO goods_receipt_lines (goods_receipt_id, po_line_id, quantity_received)
      VALUES (v_receipt_id, v_pol.id, v_qty);

      -- Update PO line cumulative received
      UPDATE purchase_order_lines
        SET received_quantity = received_quantity + v_qty
        WHERE id = v_pol.id;

      -- Stock move (vendor → internal) for tracked products
      IF v_pol.product_id IS NOT NULL THEN
        -- Optional lot creation
        v_lot_id := NULL;
        IF v_line ? 'lot_number' AND length(coalesce(v_line->>'lot_number','')) > 0 THEN
          INSERT INTO stock_lots (product_id, lot_number, expiration_date)
          VALUES (v_pol.product_id, v_line->>'lot_number', NULLIF(v_line->>'expiration_date','')::date)
          ON CONFLICT (product_id, lot_number) DO UPDATE SET lot_number = excluded.lot_number
          RETURNING id INTO v_lot_id;
        END IF;

        INSERT INTO stock_moves (
          product_id, quantity, move_type, reference_type, reference_id,
          from_location_id, to_location_id, lot_id, state, notes, created_by
        ) VALUES (
          v_pol.product_id, v_qty, 'in', 'goods_receipt', v_receipt_id::text,
          v_vendor_loc, v_to_loc, v_lot_id, 'done',
          format('Goods receipt for PO %s', v_po.po_number), auth.uid()
        );

        -- Legacy product_stock fallback (keep on-hand in sync if row exists)
        UPDATE product_stock
          SET quantity_on_hand = quantity_on_hand + v_qty,
              updated_at = now()
          WHERE product_id = v_pol.product_id;
      END IF;

      v_lines_inserted := v_lines_inserted + 1;
      v_total_qty := v_total_qty + v_qty;
    END;
  END LOOP;

  IF v_lines_inserted = 0 THEN
    RAISE EXCEPTION 'No valid lines received (all zero or already fully received)';
  END IF;

  -- Update PO status
  SELECT
    bool_and(received_quantity >= quantity),
    bool_or(received_quantity > 0)
  INTO v_all_received, v_some_received
  FROM purchase_order_lines WHERE purchase_order_id = p_purchase_order_id;

  v_new_status := CASE
    WHEN v_all_received THEN 'received'::purchase_order_status
    WHEN v_some_received THEN 'partially_received'::purchase_order_status
    ELSE v_po.status
  END;

  UPDATE purchase_orders SET status = v_new_status, updated_at = now()
    WHERE id = p_purchase_order_id;

  -- Emit platform event
  PERFORM public.emit_platform_event(
    'goods.received',
    jsonb_build_object(
      'receipt_id', v_receipt_id,
      'purchase_order_id', p_purchase_order_id,
      'po_number', v_po.po_number,
      'vendor_id', v_po.vendor_id,
      'lines_received', v_lines_inserted,
      'total_quantity', v_total_qty,
      'po_status', v_new_status
    ),
    'receive_purchase_order'
  );

  RETURN jsonb_build_object(
    'success', true,
    'receipt_id', v_receipt_id,
    'purchase_order_id', p_purchase_order_id,
    'po_status', v_new_status,
    'lines_received', v_lines_inserted,
    'total_quantity', v_total_qty
  );
END;
$$;


ALTER FUNCTION "public"."receive_purchase_order"("p_purchase_order_id" "uuid", "p_lines" "jsonb", "p_to_location_id" "uuid", "p_received_date" "date", "p_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."receive_return"("p_return_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE public.returns SET status = 'received', received_at = now()
    WHERE id = p_return_id AND status = 'approved';
  IF NOT FOUND THEN RAISE EXCEPTION 'Return must be approved before receiving'; END IF;
  INSERT INTO public.agent_events (event_name, payload, source)
  SELECT 'stock.movement',
    jsonb_build_object('lines', jsonb_agg(jsonb_build_object(
      'product_id', ri.product_id, 'qty', ri.quantity,
      'reason', 'rma_restock', 'reference_id', p_return_id::text)))
    , 'returns'
  FROM public.return_items ri
  WHERE ri.return_id = p_return_id AND ri.restock = true AND ri.product_id IS NOT NULL
  GROUP BY p_return_id HAVING COUNT(*) > 0;
  RETURN jsonb_build_object('success', true, 'return_id', p_return_id);
END; $$;


ALTER FUNCTION "public"."receive_return"("p_return_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."recompute_service_order_total"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_order_id uuid;
BEGIN
  v_order_id := COALESCE(NEW.service_order_id, OLD.service_order_id);
  UPDATE public.service_orders
     SET total_amount = COALESCE((SELECT SUM(total) FROM public.service_order_lines WHERE service_order_id = v_order_id), 0),
         updated_at = now()
   WHERE id = v_order_id;
  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION "public"."recompute_service_order_total"() OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."payment_reconciliations" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "invoice_id" "uuid" NOT NULL,
    "status" "text" DEFAULT 'partial'::"text" NOT NULL,
    "reconciled_amount_cents" bigint DEFAULT 0 NOT NULL,
    "invoice_total_cents" bigint NOT NULL,
    "currency" "text" DEFAULT 'SEK'::"text" NOT NULL,
    "journal_entry_id" "uuid",
    "reversal_journal_entry_id" "uuid",
    "reconciled_by" "uuid",
    "reconciled_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "reversed_by" "uuid",
    "reversed_at" timestamp with time zone,
    "reversal_reason" "text",
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "payment_reconciliations_status_check" CHECK (("status" = ANY (ARRAY['partial'::"text", 'full'::"text", 'reversed'::"text"])))
);


ALTER TABLE "public"."payment_reconciliations" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reconcile_invoice_payments"("p_invoice_id" "uuid", "p_bank_transaction_ids" "uuid"[], "p_notes" "text" DEFAULT NULL::"text") RETURNS "public"."payment_reconciliations"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_invoice public.invoices;
  v_total BIGINT;
  v_already_paid BIGINT;
  v_remaining BIGINT;
  v_sum BIGINT := 0;
  v_apply BIGINT := 0;
  v_tx public.bank_transactions;
  v_tx_id UUID;
  v_tx_remaining BIGINT;
  v_tx_total_matched BIGINT;
  v_rec public.payment_reconciliations;
  v_journal_id UUID;
  v_je_id UUID;
  v_match_amount BIGINT;
BEGIN
  IF NOT (public.has_role(auth.uid(),'admin'::public.app_role)
       OR public.has_role(auth.uid(),'approver'::public.app_role)) THEN
    RAISE EXCEPTION 'Only admins/approvers can reconcile payments';
  END IF;

  SELECT * INTO v_invoice FROM public.invoices WHERE id = p_invoice_id FOR UPDATE;
  IF v_invoice.id IS NULL THEN RAISE EXCEPTION 'Invoice not found'; END IF;
  IF v_invoice.status::text = 'cancelled' THEN RAISE EXCEPTION 'Cannot reconcile cancelled invoice'; END IF;

  v_total := COALESCE(v_invoice.total_cents,0)::bigint;
  v_already_paid := COALESCE(v_invoice.paid_amount_cents,0);
  v_remaining := GREATEST(0, v_total - v_already_paid);

  IF v_remaining = 0 THEN RAISE EXCEPTION 'Invoice already fully reconciled'; END IF;
  IF p_bank_transaction_ids IS NULL OR array_length(p_bank_transaction_ids,1) IS NULL THEN
    RAISE EXCEPTION 'No bank transactions provided';
  END IF;

  -- Create the reconciliation group (status filled in later)
  INSERT INTO public.payment_reconciliations (
    invoice_id, status, reconciled_amount_cents, invoice_total_cents,
    currency, reconciled_by, notes
  )
  VALUES (
    p_invoice_id, 'partial', 0, v_total, v_invoice.currency, auth.uid(), p_notes
  )
  RETURNING * INTO v_rec;

  -- Walk through bank transactions, allocate up to remaining amount each
  FOREACH v_tx_id IN ARRAY p_bank_transaction_ids LOOP
    SELECT * INTO v_tx FROM public.bank_transactions WHERE id = v_tx_id FOR UPDATE;
    IF v_tx.id IS NULL THEN
      RAISE EXCEPTION 'Bank transaction % not found', v_tx_id;
    END IF;

    IF v_tx.currency <> v_invoice.currency THEN
      RAISE EXCEPTION 'Currency mismatch: invoice % vs transaction %', v_invoice.currency, v_tx.currency
        USING ERRCODE = 'check_violation';
    END IF;

    IF v_tx.amount_cents <= 0 THEN
      RAISE EXCEPTION 'Bank transaction % has non-positive amount (%); refunds must be reconciled separately',
        v_tx_id, v_tx.amount_cents
        USING ERRCODE = 'check_violation';
    END IF;

    -- residual on this tx
    SELECT COALESCE(SUM(ABS(amount_cents)),0) INTO v_tx_total_matched
    FROM public.reconciliation_matches WHERE bank_transaction_id = v_tx_id;
    v_tx_remaining := GREATEST(0, ABS(v_tx.amount_cents) - v_tx_total_matched);

    IF v_tx_remaining = 0 THEN
      RAISE EXCEPTION 'Bank transaction % is already fully matched', v_tx_id
        USING ERRCODE = 'check_violation';
    END IF;

    v_apply := LEAST(v_tx_remaining, v_remaining - v_sum);
    EXIT WHEN v_apply <= 0;

    INSERT INTO public.reconciliation_matches (
      bank_transaction_id, entity_type, entity_id, amount_cents,
      match_type, confidence, reconciliation_id, created_by
    ) VALUES (
      v_tx_id, 'invoice', p_invoice_id, v_apply,
      'manual', 1.0, v_rec.id, auth.uid()
    );

    v_sum := v_sum + v_apply;
    EXIT WHEN v_sum >= v_remaining;
  END LOOP;

  IF v_sum = 0 THEN
    DELETE FROM public.payment_reconciliations WHERE id = v_rec.id;
    RAISE EXCEPTION 'No amount could be allocated (all transactions exhausted)';
  END IF;

  -- Post bookkeeping in BANK journal
  SELECT id INTO v_journal_id FROM public.journals WHERE code = 'BANK' AND is_active = true LIMIT 1;

  INSERT INTO public.journal_entries (
    entry_date, description, reference_number, status, source,
    invoice_id, journal_id, created_by
  ) VALUES (
    CURRENT_DATE,
    'Reconciliation — ' || COALESCE(v_invoice.invoice_number, v_invoice.id::text),
    v_invoice.invoice_number,
    'posted', 'reconciliation',
    p_invoice_id, v_journal_id, auth.uid()
  ) RETURNING id INTO v_je_id;

  v_match_amount := v_sum;
  -- Debit 1930 Bank, Credit 1510 Kundfordringar
  INSERT INTO public.journal_entry_lines (journal_entry_id, account_code, account_name, debit_cents, credit_cents, description) VALUES
    (v_je_id, '1930', 'Företagskonto / Bank', v_match_amount, 0, 'Payment received'),
    (v_je_id, '1510', 'Kundfordringar', 0, v_match_amount, 'Settle receivable');

  -- Update invoice
  UPDATE public.invoices
  SET paid_amount_cents = v_already_paid + v_match_amount,
      reconciliation_id = v_rec.id,
      status = CASE
        WHEN v_already_paid + v_match_amount >= v_total THEN 'paid'::invoice_status
        ELSE COALESCE(NULLIF(status::text,'draft'), 'sent')::invoice_status
      END,
      paid_at = CASE
        WHEN v_already_paid + v_match_amount >= v_total THEN now()
        ELSE paid_at
      END,
      updated_at = now()
  WHERE id = p_invoice_id;

  -- Finalize the group
  UPDATE public.payment_reconciliations
  SET reconciled_amount_cents = v_match_amount,
      status = CASE WHEN v_already_paid + v_match_amount >= v_total THEN 'full' ELSE 'partial' END,
      journal_entry_id = v_je_id,
      updated_at = now()
  WHERE id = v_rec.id
  RETURNING * INTO v_rec;

  RETURN v_rec;
END;
$$;


ALTER FUNCTION "public"."reconcile_invoice_payments"("p_invoice_id" "uuid", "p_bank_transaction_ids" "uuid"[], "p_notes" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reconcile_invoice_payments"("p_invoice_id" "uuid", "p_bank_transaction_ids" "uuid"[], "p_notes" "text" DEFAULT NULL::"text", "p_skip_auth" boolean DEFAULT false) RETURNS "public"."payment_reconciliations"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_invoice public.invoices;
  v_total BIGINT; v_already_paid BIGINT; v_remaining BIGINT;
  v_sum BIGINT := 0; v_apply BIGINT := 0;
  v_tx public.bank_transactions; v_tx_id UUID;
  v_tx_remaining BIGINT; v_tx_total_matched BIGINT;
  v_rec public.payment_reconciliations;
  v_journal_id UUID; v_je_id UUID; v_match_amount BIGINT;
  v_matched_tx_ids UUID[] := ARRAY[]::UUID[];
  v_match_details JSONB := '[]'::jsonb;
BEGIN
  IF NOT p_skip_auth AND NOT (public.has_role(auth.uid(),'admin'::public.app_role)
       OR public.has_role(auth.uid(),'approver'::public.app_role)) THEN
    RAISE EXCEPTION 'Only admins/approvers can reconcile payments';
  END IF;

  SELECT * INTO v_invoice FROM public.invoices WHERE id = p_invoice_id FOR UPDATE;
  IF v_invoice.id IS NULL THEN RAISE EXCEPTION 'Invoice not found'; END IF;
  IF v_invoice.status::text = 'cancelled' THEN RAISE EXCEPTION 'Cannot reconcile cancelled invoice'; END IF;

  v_total := COALESCE(v_invoice.total_cents,0)::bigint;
  v_already_paid := COALESCE(v_invoice.paid_amount_cents,0);
  v_remaining := GREATEST(0, v_total - v_already_paid);

  IF v_remaining = 0 THEN RAISE EXCEPTION 'Invoice already fully reconciled'; END IF;
  IF p_bank_transaction_ids IS NULL OR array_length(p_bank_transaction_ids,1) IS NULL THEN
    RAISE EXCEPTION 'No bank transactions provided';
  END IF;

  INSERT INTO public.payment_reconciliations (invoice_id, status, reconciled_amount_cents, invoice_total_cents, currency, reconciled_by, notes)
  VALUES (p_invoice_id, 'partial', 0, v_total, v_invoice.currency, auth.uid(), p_notes)
  RETURNING * INTO v_rec;

  -- Audit: reconciliation.created
  INSERT INTO public.audit_logs (action, entity_type, entity_id, user_id, metadata)
  VALUES ('reconciliation.created','payment_reconciliation', v_rec.id, auth.uid(),
    jsonb_build_object(
      'invoice_id', p_invoice_id,
      'invoice_number', v_invoice.invoice_number,
      'invoice_total_cents', v_total,
      'remaining_cents', v_remaining,
      'currency', v_invoice.currency,
      'bank_transaction_ids', to_jsonb(p_bank_transaction_ids),
      'notes', p_notes
    ));

  FOREACH v_tx_id IN ARRAY p_bank_transaction_ids LOOP
    SELECT * INTO v_tx FROM public.bank_transactions WHERE id = v_tx_id FOR UPDATE;
    IF v_tx.id IS NULL THEN RAISE EXCEPTION 'Bank transaction % not found', v_tx_id; END IF;
    IF v_tx.currency <> v_invoice.currency THEN
      RAISE EXCEPTION 'Currency mismatch: invoice % vs transaction %', v_invoice.currency, v_tx.currency
        USING ERRCODE='check_violation';
    END IF;
    IF v_tx.amount_cents <= 0 THEN
      RAISE EXCEPTION 'Bank transaction % has non-positive amount (%); refunds must be reconciled separately',
        v_tx_id, v_tx.amount_cents USING ERRCODE='check_violation';
    END IF;

    SELECT COALESCE(SUM(ABS(amount_cents)),0) INTO v_tx_total_matched
    FROM public.reconciliation_matches WHERE bank_transaction_id = v_tx_id;
    v_tx_remaining := GREATEST(0, ABS(v_tx.amount_cents) - v_tx_total_matched);

    IF v_tx_remaining = 0 THEN
      RAISE EXCEPTION 'Bank transaction % is already fully matched', v_tx_id USING ERRCODE='check_violation';
    END IF;

    v_apply := LEAST(v_tx_remaining, v_remaining - v_sum);
    EXIT WHEN v_apply <= 0;

    INSERT INTO public.reconciliation_matches (bank_transaction_id, entity_type, entity_id, amount_cents, match_type, confidence, reconciliation_id, created_by)
    VALUES (v_tx_id, 'invoice', p_invoice_id, v_apply, 'manual', 1.0, v_rec.id, auth.uid());

    -- Audit: reconciliation.match_added (per transaktion)
    INSERT INTO public.audit_logs (action, entity_type, entity_id, user_id, metadata)
    VALUES ('reconciliation.match_added','payment_reconciliation', v_rec.id, auth.uid(),
      jsonb_build_object(
        'invoice_id', p_invoice_id,
        'bank_transaction_id', v_tx_id,
        'amount_cents', v_apply,
        'tx_remaining_before_cents', v_tx_remaining,
        'currency', v_invoice.currency
      ));

    v_matched_tx_ids := v_matched_tx_ids || v_tx_id;
    v_match_details := v_match_details || jsonb_build_object('bank_transaction_id', v_tx_id, 'amount_cents', v_apply);

    v_sum := v_sum + v_apply;
    EXIT WHEN v_sum >= v_remaining;
  END LOOP;

  IF v_sum = 0 THEN
    DELETE FROM public.payment_reconciliations WHERE id = v_rec.id;
    INSERT INTO public.audit_logs (action, entity_type, entity_id, user_id, metadata)
    VALUES ('reconciliation.aborted','payment_reconciliation', v_rec.id, auth.uid(),
      jsonb_build_object('invoice_id', p_invoice_id, 'reason','no_amount_allocated','bank_transaction_ids', to_jsonb(p_bank_transaction_ids)));
    RAISE EXCEPTION 'No amount could be allocated';
  END IF;

  SELECT id INTO v_journal_id FROM public.journals WHERE code='BANK' AND is_active=true LIMIT 1;
  INSERT INTO public.journal_entries (entry_date, description, reference_number, status, source, invoice_id, journal_id, created_by)
  VALUES (CURRENT_DATE, 'Reconciliation — '||COALESCE(v_invoice.invoice_number,v_invoice.id::text), v_invoice.invoice_number, 'posted', 'reconciliation', p_invoice_id, v_journal_id, auth.uid())
  RETURNING id INTO v_je_id;

  v_match_amount := v_sum;
  INSERT INTO public.journal_entry_lines (journal_entry_id, account_code, account_name, debit_cents, credit_cents, description) VALUES
    (v_je_id,'1930','Företagskonto / Bank',v_match_amount,0,'Payment received'),
    (v_je_id,'1510','Kundfordringar',0,v_match_amount,'Settle receivable');

  UPDATE public.invoices SET
    paid_amount_cents = v_already_paid + v_match_amount,
    reconciliation_id = v_rec.id,
    status = CASE WHEN v_already_paid + v_match_amount >= v_total THEN 'paid'::invoice_status ELSE COALESCE(NULLIF(status::text,'draft'),'sent')::invoice_status END,
    paid_at = CASE WHEN v_already_paid + v_match_amount >= v_total THEN now() ELSE paid_at END,
    updated_at = now()
  WHERE id = p_invoice_id;

  UPDATE public.payment_reconciliations SET
    reconciled_amount_cents = v_match_amount,
    status = CASE WHEN v_already_paid + v_match_amount >= v_total THEN 'full' ELSE 'partial' END,
    journal_entry_id = v_je_id, updated_at = now()
  WHERE id = v_rec.id RETURNING * INTO v_rec;

  -- Audit: reconciliation.completed (full eller partial)
  INSERT INTO public.audit_logs (action, entity_type, entity_id, user_id, metadata)
  VALUES (
    CASE WHEN v_rec.status='full' THEN 'reconciliation.completed_full' ELSE 'reconciliation.completed_partial' END,
    'payment_reconciliation', v_rec.id, auth.uid(),
    jsonb_build_object(
      'invoice_id', p_invoice_id,
      'invoice_number', v_invoice.invoice_number,
      'reconciled_amount_cents', v_match_amount,
      'invoice_total_cents', v_total,
      'paid_amount_cents_after', v_already_paid + v_match_amount,
      'outstanding_cents_after', GREATEST(0, v_total - (v_already_paid + v_match_amount)),
      'matched_bank_transaction_ids', to_jsonb(v_matched_tx_ids),
      'matches', v_match_details,
      'journal_entry_id', v_je_id,
      'currency', v_invoice.currency,
      'notes', p_notes
    ));

  RETURN v_rec;
END;
$$;


ALTER FUNCTION "public"."reconcile_invoice_payments"("p_invoice_id" "uuid", "p_bank_transaction_ids" "uuid"[], "p_notes" "text", "p_skip_auth" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_churn_reason"("p_subscription_id" "uuid", "p_reason" "public"."churn_reason_category", "p_feedback" "text" DEFAULT NULL::"text", "p_nps_score" integer DEFAULT NULL::integer, "p_would_return" boolean DEFAULT NULL::boolean) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_id uuid;
  v_email text;
BEGIN
  SELECT customer_email INTO v_email FROM public.subscriptions WHERE id = p_subscription_id;
  INSERT INTO public.subscription_churn_reasons
    (subscription_id, customer_email, reason, feedback, nps_score, would_return)
  VALUES (p_subscription_id, v_email, p_reason, p_feedback, p_nps_score, p_would_return)
  RETURNING id INTO v_id;

  -- Emit event if helper exists
  BEGIN
    PERFORM public.emit_platform_event('subscription.churn_reason_recorded',
      jsonb_build_object('subscription_id', p_subscription_id, 'reason', p_reason),
      'subscriptions');
  EXCEPTION WHEN undefined_function THEN NULL;
  END;

  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."record_churn_reason"("p_subscription_id" "uuid", "p_reason" "public"."churn_reason_category", "p_feedback" "text", "p_nps_score" integer, "p_would_return" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_pos_sale"("p_register_id" "uuid", "p_session_id" "uuid", "p_lines" "jsonb", "p_payment_method" "text" DEFAULT 'cash'::"text", "p_customer_email" "text" DEFAULT NULL::"text", "p_discount_cents" integer DEFAULT 0) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_sale_id uuid;
  v_receipt text;
  v_subtotal integer := 0;
  v_tax integer := 0;
  v_total integer := 0;
  v_currency text;
  v_default_tax numeric;
  v_line jsonb;
  v_line_total integer;
  v_line_tax integer;
BEGIN
  SELECT currency, default_tax_rate INTO v_currency, v_default_tax
  FROM public.pos_registers WHERE id = p_register_id;

  IF NOT FOUND THEN RAISE EXCEPTION 'Register not found'; END IF;

  v_receipt := public.generate_pos_receipt_number();

  INSERT INTO public.pos_sales
    (receipt_number, register_id, session_id, cashier_id, customer_email,
     payment_method, currency, discount_cents, status)
  VALUES
    (v_receipt, p_register_id, p_session_id, auth.uid(), p_customer_email,
     p_payment_method, v_currency, COALESCE(p_discount_cents, 0), 'completed')
  RETURNING id INTO v_sale_id;

  FOR v_line IN SELECT * FROM jsonb_array_elements(p_lines) LOOP
    v_line_total := ((v_line->>'quantity')::numeric * (v_line->>'unit_price_cents')::integer)::integer
                    - COALESCE((v_line->>'discount_cents')::integer, 0);
    v_line_tax := ROUND(v_line_total * COALESCE((v_line->>'tax_rate')::numeric, v_default_tax) / 100.0)::integer;

    INSERT INTO public.pos_sale_lines
      (sale_id, product_id, product_name, sku, quantity, unit_price_cents,
       discount_cents, tax_rate, line_total_cents)
    VALUES
      (v_sale_id,
       NULLIF(v_line->>'product_id','')::uuid,
       v_line->>'product_name',
       v_line->>'sku',
       (v_line->>'quantity')::numeric,
       (v_line->>'unit_price_cents')::integer,
       COALESCE((v_line->>'discount_cents')::integer, 0),
       COALESCE((v_line->>'tax_rate')::numeric, v_default_tax),
       v_line_total);

    v_subtotal := v_subtotal + v_line_total;
    v_tax := v_tax + v_line_tax;
  END LOOP;

  v_total := v_subtotal + v_tax - COALESCE(p_discount_cents, 0);

  UPDATE public.pos_sales
    SET subtotal_cents = v_subtotal,
        tax_cents = v_tax,
        total_cents = v_total
    WHERE id = v_sale_id;

  -- Update session totals
  IF p_session_id IS NOT NULL THEN
    UPDATE public.pos_sessions
      SET total_sales_cents = total_sales_cents + v_total,
          sales_count = sales_count + 1
      WHERE id = p_session_id;
  END IF;

  -- Emit event
  BEGIN
    PERFORM public.emit_platform_event('pos.sale_completed',
      jsonb_build_object('sale_id', v_sale_id, 'total_cents', v_total, 'register_id', p_register_id),
      'pos');
  EXCEPTION WHEN undefined_function THEN NULL; END;

  RETURN jsonb_build_object(
    'sale_id', v_sale_id,
    'receipt_number', v_receipt,
    'subtotal_cents', v_subtotal,
    'tax_cents', v_tax,
    'total_cents', v_total
  );
END;
$$;


ALTER FUNCTION "public"."record_pos_sale"("p_register_id" "uuid", "p_session_id" "uuid", "p_lines" "jsonb", "p_payment_method" "text", "p_customer_email" "text", "p_discount_cents" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."record_pos_sale_v2"("p_register_id" "uuid", "p_session_id" "uuid", "p_lines" "jsonb", "p_payments" "jsonb", "p_customer_id" "uuid" DEFAULT NULL::"uuid", "p_customer_email" "text" DEFAULT NULL::"text", "p_discount_cents" integer DEFAULT 0, "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_sale_id uuid;
  v_receipt text;
  v_subtotal integer := 0;
  v_tax integer := 0;
  v_total integer := 0;
  v_paid integer := 0;
  v_line jsonb;
  v_payment jsonb;
  v_register_currency text;
  v_default_tax numeric;
  v_line_subtotal integer;
  v_line_tax integer;
  v_line_total integer;
  v_tax_rate numeric;
  v_product record;
  v_payment_summary text;
BEGIN
  -- Validate session is open
  IF NOT EXISTS (
    SELECT 1 FROM public.pos_sessions
     WHERE id = p_session_id AND register_id = p_register_id AND status = 'open'
  ) THEN
    RAISE EXCEPTION 'Session % is not open for register %', p_session_id, p_register_id;
  END IF;

  SELECT currency, default_tax_rate
    INTO v_register_currency, v_default_tax
    FROM public.pos_registers WHERE id = p_register_id;

  -- Generate receipt
  v_receipt := 'R-' || to_char(now(), 'YYYYMMDD') || '-' || lpad((EXTRACT(EPOCH FROM now())::bigint % 100000)::text, 5, '0');

  -- Calculate totals + validate products
  FOR v_line IN SELECT * FROM jsonb_array_elements(p_lines)
  LOOP
    v_tax_rate := COALESCE((v_line->>'tax_rate')::numeric, v_default_tax, 0);
    v_line_subtotal := ((v_line->>'unit_price_cents')::integer * (v_line->>'quantity')::numeric)::integer
                       - COALESCE((v_line->>'discount_cents')::integer, 0);
    v_line_tax := round(v_line_subtotal * v_tax_rate / 100.0)::integer;
    v_line_total := v_line_subtotal + v_line_tax;

    v_subtotal := v_subtotal + v_line_subtotal;
    v_tax := v_tax + v_line_tax;
    v_total := v_total + v_line_total;

    -- If product_id given, ensure it's POS-enabled
    IF (v_line->>'product_id') IS NOT NULL THEN
      SELECT id, name, available_in_pos INTO v_product
        FROM public.products WHERE id = (v_line->>'product_id')::uuid;
      IF NOT FOUND THEN
        RAISE EXCEPTION 'Product % not found', v_line->>'product_id';
      END IF;
      IF NOT v_product.available_in_pos THEN
        RAISE EXCEPTION 'Product % is not available in POS', v_product.name;
      END IF;
    END IF;
  END LOOP;

  v_total := v_total - COALESCE(p_discount_cents, 0);

  -- Validate payments cover the total
  FOR v_payment IN SELECT * FROM jsonb_array_elements(p_payments)
  LOOP
    v_paid := v_paid + (v_payment->>'amount_cents')::integer;
  END LOOP;

  IF v_paid < v_total THEN
    RAISE EXCEPTION 'Insufficient payment: paid %, total %', v_paid, v_total;
  END IF;

  -- Determine payment_method label (split if >1)
  IF jsonb_array_length(p_payments) > 1 THEN
    v_payment_summary := 'split';
  ELSE
    v_payment_summary := COALESCE(p_payments->0->>'method', 'cash');
  END IF;

  -- Create sale
  INSERT INTO public.pos_sales (
    receipt_number, register_id, session_id, customer_id, customer_email,
    subtotal_cents, tax_cents, discount_cents, total_cents, currency,
    payment_method, status, metadata
  )
  VALUES (
    v_receipt, p_register_id, p_session_id, p_customer_id, p_customer_email,
    v_subtotal, v_tax, COALESCE(p_discount_cents, 0), v_total, v_register_currency,
    v_payment_summary, 'completed', p_metadata
  )
  RETURNING id INTO v_sale_id;

  -- Insert lines
  FOR v_line IN SELECT * FROM jsonb_array_elements(p_lines)
  LOOP
    v_tax_rate := COALESCE((v_line->>'tax_rate')::numeric, v_default_tax, 0);
    v_line_subtotal := ((v_line->>'unit_price_cents')::integer * (v_line->>'quantity')::numeric)::integer
                       - COALESCE((v_line->>'discount_cents')::integer, 0);
    v_line_tax := round(v_line_subtotal * v_tax_rate / 100.0)::integer;

    INSERT INTO public.pos_sale_lines (
      sale_id, product_id, product_name, sku, quantity,
      unit_price_cents, discount_cents, tax_rate, line_total_cents
    )
    VALUES (
      v_sale_id,
      NULLIF(v_line->>'product_id','')::uuid,
      v_line->>'product_name',
      v_line->>'sku',
      (v_line->>'quantity')::numeric,
      (v_line->>'unit_price_cents')::integer,
      COALESCE((v_line->>'discount_cents')::integer, 0),
      v_tax_rate,
      v_line_subtotal + v_line_tax
    );

    -- Stock event (fire-and-forget — stock module listens)
    IF (v_line->>'product_id') IS NOT NULL THEN
      PERFORM public.emit_platform_event(
        'stock.movement',
        jsonb_build_object(
          'product_id', v_line->>'product_id',
          'quantity', -((v_line->>'quantity')::numeric),
          'reason', 'pos_sale',
          'reference_type', 'pos_sale',
          'reference_id', v_sale_id,
          'sku', v_line->>'sku'
        ),
        'pos'
      );
    END IF;
  END LOOP;

  -- Insert payments
  FOR v_payment IN SELECT * FROM jsonb_array_elements(p_payments)
  LOOP
    INSERT INTO public.pos_payments (sale_id, method, amount_cents, reference, metadata)
    VALUES (
      v_sale_id,
      v_payment->>'method',
      (v_payment->>'amount_cents')::integer,
      v_payment->>'reference',
      COALESCE(v_payment->'metadata', '{}'::jsonb)
    );
  END LOOP;

  -- Update session totals
  UPDATE public.pos_sessions
     SET total_sales_cents = total_sales_cents + v_total,
         sales_count = sales_count + 1
   WHERE id = p_session_id;

  RETURN jsonb_build_object(
    'sale_id', v_sale_id,
    'receipt_number', v_receipt,
    'total_cents', v_total,
    'tax_cents', v_tax,
    'change_cents', v_paid - v_total
  );
END;
$$;


ALTER FUNCTION "public"."record_pos_sale_v2"("p_register_id" "uuid", "p_session_id" "uuid", "p_lines" "jsonb", "p_payments" "jsonb", "p_customer_id" "uuid", "p_customer_email" "text", "p_discount_cents" integer, "p_metadata" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."refund_return"("p_return_id" "uuid", "p_refund_cents" integer, "p_method" "text" DEFAULT 'manual'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE public.returns
    SET status = 'refunded', refund_amount_cents = p_refund_cents,
        refund_method = p_method, refund_processed_at = now()
    WHERE id = p_return_id AND status IN ('received', 'approved');
  IF NOT FOUND THEN RAISE EXCEPTION 'Return not in refundable state'; END IF;
  RETURN jsonb_build_object('success', true, 'return_id', p_return_id, 'refunded_cents', p_refund_cents);
END; $$;


ALTER FUNCTION "public"."refund_return"("p_return_id" "uuid", "p_refund_cents" integer, "p_method" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."register_fixed_asset"("p_name" "text", "p_cost_cents" bigint, "p_useful_life_months" integer, "p_purchase_date" "date" DEFAULT CURRENT_DATE, "p_in_service_date" "date" DEFAULT NULL::"date", "p_salvage_cents" bigint DEFAULT 0, "p_method" "text" DEFAULT 'straight_line'::"text", "p_declining_rate" numeric DEFAULT NULL::numeric, "p_asset_account" "text" DEFAULT '1210'::"text", "p_depreciation_account" "text" DEFAULT '7832'::"text", "p_accumulated_account" "text" DEFAULT '1219'::"text", "p_credit_account" "text" DEFAULT '1930'::"text", "p_description" "text" DEFAULT NULL::"text", "p_create_journal_entry" boolean DEFAULT true) RETURNS "public"."fixed_assets"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_asset public.fixed_assets;
  v_je_id UUID;
BEGIN
  IF NOT public.has_role(auth.uid(), 'admin') THEN
    RAISE EXCEPTION 'register_fixed_asset: admin role required';
  END IF;

  INSERT INTO public.fixed_assets (
    name, description, cost_cents, salvage_cents, purchase_date, in_service_date,
    useful_life_months, depreciation_method, declining_rate,
    asset_account, depreciation_account, accumulated_account
  ) VALUES (
    p_name, p_description, p_cost_cents, COALESCE(p_salvage_cents,0),
    p_purchase_date, COALESCE(p_in_service_date, p_purchase_date),
    p_useful_life_months, p_method, p_declining_rate,
    p_asset_account, p_depreciation_account, p_accumulated_account
  ) RETURNING * INTO v_asset;

  IF p_create_journal_entry
     AND EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='public' AND table_name='journal_entries')
     AND EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema='public' AND table_name='journal_entry_lines') THEN
    INSERT INTO public.journal_entries (entry_date, description, source, status)
    VALUES (
      v_asset.purchase_date,
      format('Acquisition of fixed asset: %s', v_asset.name),
      'fixed_asset_register',
      'posted'
    ) RETURNING id INTO v_je_id;

    INSERT INTO public.journal_entry_lines (entry_id, account_code, debit_cents, credit_cents, description)
    VALUES
      (v_je_id, p_asset_account,  p_cost_cents, 0, format('Asset: %s', v_asset.name)),
      (v_je_id, p_credit_account, 0, p_cost_cents, format('Acquisition: %s', v_asset.name));
  END IF;

  RETURN v_asset;
END;
$$;


ALTER FUNCTION "public"."register_fixed_asset"("p_name" "text", "p_cost_cents" bigint, "p_useful_life_months" integer, "p_purchase_date" "date", "p_in_service_date" "date", "p_salvage_cents" bigint, "p_method" "text", "p_declining_rate" numeric, "p_asset_account" "text", "p_depreciation_account" "text", "p_accumulated_account" "text", "p_credit_account" "text", "p_description" "text", "p_create_journal_entry" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."register_flowpilot_cron"("p_supabase_url" "text", "p_anon_key" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_catalog', 'extensions'
    AS $$
DECLARE
  result jsonb := '{}'::jsonb;
  job_exists boolean;
  auth_header text;
BEGIN
  auth_header := json_build_object(
    'Content-Type', 'application/json',
    'Authorization', 'Bearer ' || p_anon_key
  )::text;

  -- 1. Heartbeat (every 12h)
  SELECT EXISTS(SELECT 1 FROM cron.job WHERE jobname = 'flowpilot-heartbeat') INTO job_exists;
  IF NOT job_exists THEN
    PERFORM cron.schedule(
      'flowpilot-heartbeat',
      '0 0,12 * * *',
      format(
        'SELECT net.http_post(url := %L, headers := %L::jsonb, body := concat(''{"time":"'', now(), ''"}'')::jsonb) AS request_id;',
        p_supabase_url || '/functions/v1/flowpilot-heartbeat',
        auth_header
      )
    );
    result := result || '{"heartbeat": "registered"}'::jsonb;
  ELSE
    result := result || '{"heartbeat": "already_exists"}'::jsonb;
  END IF;

  -- 2. Automation dispatcher (every minute)
  SELECT EXISTS(SELECT 1 FROM cron.job WHERE jobname = 'automation-dispatcher-every-minute') INTO job_exists;
  IF NOT job_exists THEN
    PERFORM cron.schedule(
      'automation-dispatcher-every-minute',
      '* * * * *',
      format(
        'SELECT net.http_post(url := %L, headers := %L::jsonb, body := ''{"source": "pg_cron"}''::jsonb) AS request_id;',
        p_supabase_url || '/functions/v1/automation-dispatcher',
        auth_header
      )
    );
    result := result || '{"automation_dispatcher": "registered"}'::jsonb;
  ELSE
    result := result || '{"automation_dispatcher": "already_exists"}'::jsonb;
  END IF;

  -- 3. Publish scheduled pages (every 5 minutes — keeps per-minute cron write load
  --    down; pg_cron logs every run to cron.job_run_details. See retention migration.)
  SELECT EXISTS(SELECT 1 FROM cron.job WHERE jobname = 'publish-scheduled-pages') INTO job_exists;
  IF NOT job_exists THEN
    PERFORM cron.schedule(
      'publish-scheduled-pages',
      '*/5 * * * *',
      format(
        'SELECT net.http_post(url := %L, headers := %L::jsonb, body := ''{}''::jsonb) AS request_id;',
        p_supabase_url || '/functions/v1/publish-scheduled-pages',
        auth_header
      )
    );
    result := result || '{"publish_scheduled_pages": "registered"}'::jsonb;
  ELSE
    result := result || '{"publish_scheduled_pages": "already_exists"}'::jsonb;
  END IF;

  -- 4. FlowPilot learn (daily at 03:00)
  SELECT EXISTS(SELECT 1 FROM cron.job WHERE jobname = 'flowpilot-learn') INTO job_exists;
  IF NOT job_exists THEN
    PERFORM cron.schedule(
      'flowpilot-learn',
      '0 3 * * *',
      format(
        'SELECT net.http_post(url := %L, headers := %L::jsonb, body := concat(''{"time":"'', now(), ''"}'')::jsonb) AS request_id;',
        p_supabase_url || '/functions/v1/flowpilot-learn',
        auth_header
      )
    );
    result := result || '{"flowpilot_learn": "registered"}'::jsonb;
  ELSE
    result := result || '{"flowpilot_learn": "already_exists"}'::jsonb;
  END IF;

  -- 5. Daily briefing (daily at 07:00)
  SELECT EXISTS(SELECT 1 FROM cron.job WHERE jobname = 'flowpilot-daily-briefing') INTO job_exists;
  IF NOT job_exists THEN
    PERFORM cron.schedule(
      'flowpilot-daily-briefing',
      '0 7 * * *',
      format(
        'SELECT net.http_post(url := %L, headers := %L::jsonb, body := ''{"source": "cron"}''::jsonb) AS request_id;',
        p_supabase_url || '/functions/v1/flowpilot-briefing',
        auth_header
      )
    );
    result := result || '{"daily_briefing": "registered"}'::jsonb;
  ELSE
    result := result || '{"daily_briefing": "already_exists"}'::jsonb;
  END IF;

  -- 6. Instance health check (every 6 hours)
  SELECT EXISTS(SELECT 1 FROM cron.job WHERE jobname = 'instance-health-check') INTO job_exists;
  IF NOT job_exists THEN
    PERFORM cron.schedule(
      'instance-health-check',
      '0 */6 * * *',
      format(
        'SELECT net.http_post(url := %L, headers := %L::jsonb, body := ''{"source": "cron"}''::jsonb) AS request_id;',
        p_supabase_url || '/functions/v1/instance-health',
        auth_header
      )
    );
    result := result || '{"instance_health_check": "registered"}'::jsonb;
  ELSE
    result := result || '{"instance_health_check": "already_exists"}'::jsonb;
  END IF;

  -- Cleanup: remove duplicate heartbeat-12h if it exists
  IF EXISTS(SELECT 1 FROM cron.job WHERE jobname = 'flowpilot-heartbeat-12h') THEN
    PERFORM cron.unschedule('flowpilot-heartbeat-12h');
    result := result || '{"heartbeat_12h_duplicate": "removed"}'::jsonb;
  END IF;

  RETURN result;
END;
$$;


ALTER FUNCTION "public"."register_flowpilot_cron"("p_supabase_url" "text", "p_anon_key" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."register_for_webinar"("p_webinar_id" "uuid", "p_name" "text", "p_email" "text", "p_phone" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_webinar webinars%ROWTYPE;
  v_lead_id uuid;
  v_reg_id uuid;
BEGIN
  IF p_email IS NULL OR p_email = '' THEN RAISE EXCEPTION 'email required'; END IF;
  SELECT * INTO v_webinar FROM webinars WHERE id=p_webinar_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'webinar % not found', p_webinar_id; END IF;
  IF v_webinar.status NOT IN ('published','live') THEN RAISE EXCEPTION 'webinar not open for registration'; END IF;

  -- Auto-link or create lead
  SELECT id INTO v_lead_id FROM leads WHERE lower(email)=lower(p_email);
  IF v_lead_id IS NULL THEN
    INSERT INTO leads (email, name, phone, source, source_id, score)
    VALUES (lower(p_email), p_name, p_phone, 'webinar', v_webinar.id::text, 15)
    RETURNING id INTO v_lead_id;
  ELSE
    UPDATE leads SET score = COALESCE(score,0) + 15, updated_at=now(),
                     name = COALESCE(name, p_name), phone = COALESCE(phone, p_phone)
    WHERE id = v_lead_id;
  END IF;

  INSERT INTO webinar_registrations (webinar_id, name, email, phone, lead_id)
  VALUES (p_webinar_id, p_name, lower(p_email), p_phone, v_lead_id)
  ON CONFLICT (webinar_id, email) DO UPDATE SET name=EXCLUDED.name, phone=COALESCE(EXCLUDED.phone, webinar_registrations.phone)
  RETURNING id INTO v_reg_id;

  PERFORM emit_platform_event('webinar.registered',
    jsonb_build_object('webinar_id',p_webinar_id,'registration_id',v_reg_id,'lead_id',v_lead_id,'email',lower(p_email)),
    'webinars');

  RETURN jsonb_build_object('success',true,'registration_id',v_reg_id,'lead_id',v_lead_id);
END $$;


ALTER FUNCTION "public"."register_for_webinar"("p_webinar_id" "uuid", "p_name" "text", "p_email" "text", "p_phone" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reject_pending_operation"("p_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE public.pending_operations SET status = 'rejected', reviewed_by = auth.uid(), reviewed_at = now(), rejection_reason = p_reason
    WHERE id = p_id AND status = 'pending';
  IF NOT FOUND THEN RETURN jsonb_build_object('error', 'operation not pending or not found'); END IF;
  RETURN jsonb_build_object('rejected', true, 'id', p_id, 'reason', p_reason);
END; $$;


