CREATE OR REPLACE FUNCTION "public"."reopen_accounting_period"("p_year" integer, "p_month" integer, "p_reason" "text" DEFAULT NULL::"text") RETURNS "public"."accounting_periods"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_row public.accounting_periods;
BEGIN
  IF NOT public.has_role(auth.uid(), 'admin'::public.app_role) THEN
    RAISE EXCEPTION 'Only admins can reopen accounting periods';
  END IF;

  UPDATE public.accounting_periods
  SET status = 'open',
      reopened_by = auth.uid(),
      reopened_at = now(),
      notes = CASE WHEN p_reason IS NOT NULL
                   THEN COALESCE(notes, '') || E'\n[reopened] ' || p_reason
                   ELSE notes END,
      updated_at = now()
  WHERE fiscal_year = p_year
    AND period_month = p_month
    AND status = 'closed'
  RETURNING * INTO v_row;

  IF v_row.id IS NULL THEN
    RAISE EXCEPTION 'Period %-% not found, already open, or permanently locked', p_year, p_month;
  END IF;

  RETURN v_row;
END;
$$;


ALTER FUNCTION "public"."reopen_accounting_period"("p_year" integer, "p_month" integer, "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."request_skill_approval"("p_skill_name" "text", "p_skill_id" "uuid", "p_args" "jsonb", "p_activity_id" "uuid", "p_agent" "text" DEFAULT 'mcp'::"text", "p_conversation_id" "uuid" DEFAULT NULL::"uuid", "p_amount_cents" bigint DEFAULT NULL::bigint, "p_currency" "text" DEFAULT 'SEK'::"text", "p_reason" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_request_id uuid;
  v_rule record;
  v_required_role app_role := 'admin';
  v_rule_id uuid := NULL;
BEGIN
  SELECT er.rule_id, er.required_role
    INTO v_rule
    FROM public.evaluate_approval_required('agent_skill', p_amount_cents, COALESCE(p_currency,'SEK')) er
    LIMIT 1;

  IF FOUND THEN
    v_rule_id := v_rule.rule_id;
    v_required_role := v_rule.required_role;
  END IF;

  INSERT INTO public.approval_requests (
    rule_id, entity_type, entity_id, amount_cents, currency,
    reason, required_role, requested_by, context
  ) VALUES (
    v_rule_id,
    'agent_skill',
    COALESCE(p_activity_id::text, gen_random_uuid()::text),
    p_amount_cents,
    COALESCE(p_currency, 'SEK'),
    COALESCE(p_reason, 'Agent skill "' || p_skill_name || '" requires approval before execution'),
    v_required_role,
    NULL,
    jsonb_build_object(
      'skill_name', p_skill_name,
      'skill_id', p_skill_id,
      'args', p_args,
      'agent', p_agent,
      'conversation_id', p_conversation_id,
      'activity_id', p_activity_id
    )
  )
  RETURNING id INTO v_request_id;

  IF p_activity_id IS NOT NULL THEN
    UPDATE public.agent_activity
       SET approval_request_id = v_request_id
     WHERE id = p_activity_id;
  END IF;

  RETURN v_request_id;
END;
$$;


ALTER FUNCTION "public"."request_skill_approval"("p_skill_name" "text", "p_skill_id" "uuid", "p_args" "jsonb", "p_activity_id" "uuid", "p_agent" "text", "p_conversation_id" "uuid", "p_amount_cents" bigint, "p_currency" "text", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."reserve_stock"("p_product_id" "uuid", "p_location_id" "uuid", "p_quantity" numeric, "p_reference_type" "text" DEFAULT NULL::"text", "p_reference_id" "text" DEFAULT NULL::"text", "p_lot_id" "uuid" DEFAULT NULL::"uuid", "p_notes" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_id uuid; v_avail numeric; v_reserved numeric;
BEGIN
  IF NOT (has_role(auth.uid(),'writer'::app_role) OR has_role(auth.uid(),'admin'::app_role)) THEN RAISE EXCEPTION 'Insufficient privileges'; END IF;
  IF p_quantity <= 0 THEN RAISE EXCEPTION 'Quantity must be positive'; END IF;
  SELECT COALESCE(quantity,0), COALESCE(reserved_quantity,0) INTO v_avail, v_reserved
    FROM stock_quants WHERE product_id = p_product_id AND location_id = p_location_id AND (lot_id IS NOT DISTINCT FROM p_lot_id);
  IF (COALESCE(v_avail,0) - COALESCE(v_reserved,0)) < p_quantity THEN
    RAISE EXCEPTION 'Insufficient available stock to reserve (free %, need %)', (COALESCE(v_avail,0) - COALESCE(v_reserved,0)), p_quantity;
  END IF;
  INSERT INTO stock_reservations (product_id, location_id, lot_id, quantity, reference_type, reference_id, reserved_by, notes)
  VALUES (p_product_id, p_location_id, p_lot_id, p_quantity, p_reference_type, p_reference_id, auth.uid(), p_notes) RETURNING id INTO v_id;
  UPDATE stock_quants SET reserved_quantity = COALESCE(reserved_quantity,0) + p_quantity, updated_at = now()
    WHERE product_id = p_product_id AND location_id = p_location_id AND (lot_id IS NOT DISTINCT FROM p_lot_id);
  RETURN v_id;
END; $$;


ALTER FUNCTION "public"."reserve_stock"("p_product_id" "uuid", "p_location_id" "uuid", "p_quantity" numeric, "p_reference_type" "text", "p_reference_id" "text", "p_lot_id" "uuid", "p_notes" "text") OWNER TO "postgres";


