CREATE OR REPLACE FUNCTION "public"."schedule_cron_job"("p_jobname" "text", "p_schedule" "text", "p_url" "text", "p_headers" "text", "p_body" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_catalog', 'extensions'
    AS $$
BEGIN
  -- Remove existing job if present
  IF EXISTS(SELECT 1 FROM cron.job WHERE jobname = p_jobname) THEN
    PERFORM cron.unschedule(p_jobname);
  END IF;

  PERFORM cron.schedule(
    p_jobname,
    p_schedule,
    format(
      'SELECT net.http_post(url := %L, headers := %L::jsonb, body := %L::jsonb) AS request_id;',
      p_url,
      p_headers,
      p_body
    )
  );
  
  RETURN true;
END;
$$;


ALTER FUNCTION "public"."schedule_cron_job"("p_jobname" "text", "p_schedule" "text", "p_url" "text", "p_headers" "text", "p_body" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."search_memories_hybrid"("query_text" "text", "query_embedding" "extensions"."vector" DEFAULT NULL::"extensions"."vector", "match_threshold" double precision DEFAULT 0.3, "match_count" integer DEFAULT 10, "filter_category" "public"."agent_memory_category" DEFAULT NULL::"public"."agent_memory_category") RETURNS TABLE("id" "uuid", "key" "text", "value" "jsonb", "category" "public"."agent_memory_category", "similarity" double precision, "search_type" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
BEGIN
  RETURN QUERY
  WITH vector_results AS (
    SELECT
      am.id,
      am.key,
      am.value,
      am.category,
      CASE 
        WHEN query_embedding IS NOT NULL AND am.embedding IS NOT NULL 
        THEN 1 - (am.embedding <=> query_embedding)
        ELSE 0
      END AS vec_score
    FROM public.agent_memory am
    WHERE
      am.key NOT IN ('soul', 'identity')
      AND (filter_category IS NULL OR am.category = filter_category)
      AND (
        (query_embedding IS NOT NULL AND am.embedding IS NOT NULL 
         AND 1 - (am.embedding <=> query_embedding) > match_threshold * 0.5)
        OR
        (query_text IS NOT NULL AND query_text != '' AND (
          am.key ILIKE '%' || query_text || '%'
          OR am.value::text ILIKE '%' || query_text || '%'
          OR similarity(am.key, query_text) > 0.1
          OR similarity(am.value::text, query_text) > 0.05
        ))
      )
  ),
  keyword_results AS (
    SELECT
      vr.id,
      vr.key,
      vr.value,
      vr.category,
      vr.vec_score,
      GREATEST(
        COALESCE(similarity(vr.key, query_text), 0),
        COALESCE(similarity(vr.value::text, query_text), 0) * 0.8,
        CASE WHEN vr.key ILIKE '%' || query_text || '%' THEN 0.5 ELSE 0 END,
        CASE WHEN vr.value::text ILIKE '%' || query_text || '%' THEN 0.3 ELSE 0 END
      ) AS kw_score
    FROM vector_results vr
  )
  SELECT
    kr.id,
    kr.key,
    kr.value,
    kr.category,
    (0.7 * kr.vec_score + 0.3 * kr.kw_score)::double precision AS similarity,
    CASE
      WHEN kr.vec_score > 0.3 AND kr.kw_score > 0.1 THEN 'hybrid'
      WHEN kr.vec_score > 0.3 THEN 'semantic'
      ELSE 'keyword'
    END AS search_type
  FROM keyword_results kr
  WHERE (0.7 * kr.vec_score + 0.3 * kr.kw_score) > match_threshold
  ORDER BY (0.7 * kr.vec_score + 0.3 * kr.kw_score) DESC
  LIMIT match_count;
END;
$$;


ALTER FUNCTION "public"."search_memories_hybrid"("query_text" "text", "query_embedding" "extensions"."vector", "match_threshold" double precision, "match_count" integer, "filter_category" "public"."agent_memory_category") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."search_memories_semantic"("query_embedding" "extensions"."vector", "match_threshold" double precision DEFAULT 0.7, "match_count" integer DEFAULT 10, "filter_category" "public"."agent_memory_category" DEFAULT NULL::"public"."agent_memory_category") RETURNS TABLE("id" "uuid", "key" "text", "value" "jsonb", "category" "public"."agent_memory_category", "similarity" double precision)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    am.id,
    am.key,
    am.value,
    am.category,
    1 - (am.embedding <=> query_embedding) AS similarity
  FROM public.agent_memory am
  WHERE
    am.embedding IS NOT NULL
    AND am.key NOT IN ('soul', 'identity')
    AND (filter_category IS NULL OR am.category = filter_category)
    AND 1 - (am.embedding <=> query_embedding) > match_threshold
  ORDER BY am.embedding <=> query_embedding
  LIMIT match_count;
END;
$$;


ALTER FUNCTION "public"."search_memories_semantic"("query_embedding" "extensions"."vector", "match_threshold" double precision, "match_count" integer, "filter_category" "public"."agent_memory_category") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."seed_demo_accounting"("p_run_id" "uuid", "p_scenario" "text" DEFAULT 'default'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_je int := 0;
  v_jel int := 0;
  v_id uuid;
  r RECORD;
  v_line_id uuid;
BEGIN
  FOR r IN SELECT * FROM (VALUES
    ('Office supplies — Kontorshuset AB',   '6110', 'Office supplies',         '2440', 'Trade payables',    125000, CURRENT_DATE - 25),
    ('Cloud hosting — AWS',                 '6540', 'IT services',             '1930', 'Bank',              348000, CURRENT_DATE - 20),
    ('Consulting income — Globex',          '1510', 'Trade receivables',       '3041', 'Consulting revenue',1500000, CURRENT_DATE - 15),
    ('Bank fee',                            '6570', 'Bank fees',               '1930', 'Bank',               7500, CURRENT_DATE - 10),
    ('Office rent — November',              '5010', 'Rent',                    '1930', 'Bank',             2500000, CURRENT_DATE - 5),
    ('Software license — Adobe',            '6540', 'IT services',             '1930', 'Bank',              125000, CURRENT_DATE - 2)
  ) AS t(descr, debit_code, debit_name, credit_code, credit_name, amount_cents, when_) LOOP
    INSERT INTO journal_entries (entry_date, description, status, source)
    VALUES (r.when_, r.descr, 'posted', 'manual')
    RETURNING id INTO v_id;
    PERFORM _demo_register_row(p_run_id, 'journal_entries', v_id);
    v_je := v_je + 1;

    INSERT INTO journal_entry_lines (journal_entry_id, account_code, account_name, debit_cents, credit_cents)
    VALUES (v_id, r.debit_code, r.debit_name, r.amount_cents, 0)
    RETURNING id INTO v_line_id;
    PERFORM _demo_register_row(p_run_id, 'journal_entry_lines', v_line_id);

    INSERT INTO journal_entry_lines (journal_entry_id, account_code, account_name, debit_cents, credit_cents)
    VALUES (v_id, r.credit_code, r.credit_name, 0, r.amount_cents)
    RETURNING id INTO v_line_id;
    PERFORM _demo_register_row(p_run_id, 'journal_entry_lines', v_line_id);
    v_jel := v_jel + 2;
  END LOOP;
  RETURN jsonb_build_object('journal_entries', v_je, 'lines', v_jel);
END $$;


ALTER FUNCTION "public"."seed_demo_accounting"("p_run_id" "uuid", "p_scenario" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."seed_demo_approvals"("p_run_id" "uuid", "p_scenario" "text" DEFAULT 'default'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_rules int := 0;
  v_reqs int := 0;
  v_id uuid;
  r RECORD;
BEGIN
  FOR r IN SELECT * FROM (VALUES
    ('Expense over 5,000 SEK',     'Expenses above the standard limit require manager approval', 'expense', 500000, 'admin'::app_role),
    ('Purchase order over 25k',    'Large procurement decisions',                                 'purchase_order', 2500000, 'admin'::app_role),
    ('Customer discount over 20%', 'Discount exceeding standard pricing policy',                  'quote', NULL, 'admin'::app_role)
  ) AS t(name_, desc_, entity, thresh, role_) LOOP
    INSERT INTO approval_rules (name, description, entity_type, amount_threshold_cents, currency, required_role)
    VALUES (r.name_, r.desc_, r.entity, r.thresh, 'SEK', r.role_)
    RETURNING id INTO v_id;
    PERFORM _demo_register_row(p_run_id, 'approval_rules', v_id);
    v_rules := v_rules + 1;
  END LOOP;

  FOR r IN SELECT * FROM (VALUES
    ('expense',        'Travel — Berlin trip',         750000, 'pending',  'Need to attend industry conference'),
    ('expense',        'Equipment — MacBook Pro',     3500000, 'pending',  'Replacement for engineering hire'),
    ('purchase_order', 'Annual license renewal',      4800000, 'pending',  'Adobe Creative Cloud team'),
    ('quote',          'Acme Corp — 25% discount',          0, 'approved', 'Strategic account, multi-year commitment'),
    ('expense',        'Client dinner',                620000, 'rejected', 'Above per-diem limit')
  ) AS t(entity, reason_, amount, status_, ctx_) LOOP
    INSERT INTO approval_requests (entity_type, entity_id, amount_cents, currency, reason, status, required_role, context, resolved_at)
    VALUES (
      r.entity, gen_random_uuid()::text, r.amount, 'SEK', r.reason_,
      r.status_::approval_status, 'admin'::app_role,
      jsonb_build_object('demo_note', r.ctx_),
      CASE WHEN r.status_ IN ('approved','rejected') THEN now() - interval '1 day' END
    ) RETURNING id INTO v_id;
    PERFORM _demo_register_row(p_run_id, 'approval_requests', v_id);
    v_reqs := v_reqs + 1;
  END LOOP;

  RETURN jsonb_build_object('rules', v_rules, 'requests', v_reqs);
END $$;


ALTER FUNCTION "public"."seed_demo_approvals"("p_run_id" "uuid", "p_scenario" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."seed_demo_blog"("p_run_id" "uuid", "p_scenario" "text" DEFAULT 'default'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_post_id uuid;
  v_count int := 0;
  v_posts jsonb := jsonb_build_array(
    jsonb_build_object(
      'title', 'Why I drafted this quote at 03:14',
      'slug', 'demo-quote-0314',
      'excerpt', 'A short note from FlowPilot on why the night shift matters.',
      'body', 'A lead came in from the contact form at 03:11. By 03:14 the quote was drafted and waiting in the approval queue. Buyers research at odd hours — if the next morning starts with a polished quote in their inbox, the conversation has already moved forward.',
      'image_seed', 'flowpilot-night-shift',
      'image_alt', 'A dim desk lamp glowing over a keyboard at night'
    ),
    jsonb_build_object(
      'title', 'Three leads, one afternoon',
      'slug', 'demo-three-leads',
      'excerpt', 'How FlowPilot triaged a sudden burst of inbound traffic.',
      'body', 'Three forms hit within twenty minutes. Each one got enriched, scored, and routed within seconds. The smallest deal turned out to be the most interesting — sometimes the obvious lead is not the right one.',
      'image_seed', 'flowpilot-three-leads',
      'image_alt', 'A scattered set of paper notes arranged on a wooden table'
    ),
    jsonb_build_object(
      'title', 'What an autonomous operator actually does all day',
      'slug', 'demo-operator-day',
      'excerpt', 'A walkthrough of the heartbeat loop.',
      'body', 'Every minute the heartbeat fires. It checks objectives, reviews open work, and either acts or waits. Most of the day is waiting. The interesting moments are when a signal arrives and the loop turns into action.',
      'image_seed', 'flowpilot-heartbeat',
      'image_alt', 'A clean, minimal control room with soft monitor light'
    )
  );
  v_post jsonb;
BEGIN
  FOR v_post IN SELECT * FROM jsonb_array_elements(v_posts) LOOP
    INSERT INTO public.blog_posts (title, slug, excerpt, content_json, status, published_at, featured_image, featured_image_alt)
    VALUES (
      v_post->>'title',
      v_post->>'slug' || '-' || substring(p_run_id::text, 1, 6),
      v_post->>'excerpt',
      jsonb_build_object(
        'type', 'doc',
        'content', jsonb_build_array(
          jsonb_build_object(
            'type', 'paragraph',
            'content', jsonb_build_array(
              jsonb_build_object('type', 'text', 'text', v_post->>'body')
            )
          )
        )
      ),
      'published',
      now(),
      'https://picsum.photos/seed/' || (v_post->>'image_seed') || '/1200/630',
      v_post->>'image_alt'
    )
    RETURNING id INTO v_post_id;

    PERFORM public._demo_register_row(p_run_id, 'blog_posts', v_post_id);
    v_count := v_count + 1;
  END LOOP;

  RETURN jsonb_build_object('blog_posts_created', v_count);
END $$;


