CREATE OR REPLACE FUNCTION "public"."seed_demo_bookings"("p_run_id" "uuid", "p_scenario" "text" DEFAULT 'default'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_svc_count int := 0; v_bk_count int := 0; v_id uuid;
        v_consult uuid; v_strategy uuid; v_workshop uuid; v_suffix text;
        r record;
BEGIN
  v_suffix := substring(p_run_id::text,1,6);
  INSERT INTO public.booking_services(name,description,duration_minutes,price_cents,color,sort_order)
  VALUES ('Discovery call ('||v_suffix||')','Free 30-min intro call to discuss your needs.',30,0,'#10b981',1) RETURNING id INTO v_consult;
  PERFORM public._demo_register_row(p_run_id,'booking_services',v_consult);

  INSERT INTO public.booking_services(name,description,duration_minutes,price_cents,color,sort_order)
  VALUES ('Strategy session ('||v_suffix||')','1-hour deep dive on growth strategy.',60,150000,'#3b82f6',2) RETURNING id INTO v_strategy;
  PERFORM public._demo_register_row(p_run_id,'booking_services',v_strategy);

  INSERT INTO public.booking_services(name,description,duration_minutes,price_cents,color,sort_order)
  VALUES ('Half-day workshop ('||v_suffix||')','4-hour hands-on workshop with your team.',240,800000,'#8b5cf6',3) RETURNING id INTO v_workshop;
  PERFORM public._demo_register_row(p_run_id,'booking_services',v_workshop);
  v_svc_count := 3;

  FOR r IN SELECT * FROM (VALUES
    (v_consult,  'Anders Eriksson','anders@example.com',   '+46701234567',  2, 'confirmed'),
    (v_strategy, 'Maria Lund',     'maria.l@example.com',  '+46707654321',  5, 'confirmed'),
    (v_consult,  'Olof Berg',      'olof@example.com',     NULL,            7, 'pending'),
    (v_workshop, 'Inga Nyström',   'inga@acme.com',        '+46708887766', 14, 'confirmed'),
    (v_strategy, 'Karl Wahlberg',  'karl@example.com',     NULL,           -3, 'completed'),
    (v_consult,  'Pia Hansson',    'pia@example.com',      NULL,           -7, 'cancelled')
  ) AS t(svc,cname,cemail,cphone,day_offset,status) LOOP
    INSERT INTO public.bookings(service_id,customer_name,customer_email,customer_phone,start_time,end_time,status)
    VALUES (r.svc, r.cname, r.cemail, r.cphone,
            (current_date + (r.day_offset || ' days')::interval + interval '10 hours')::timestamptz,
            (current_date + (r.day_offset || ' days')::interval + interval '11 hours')::timestamptz,
            r.status)
    RETURNING id INTO v_id;
    PERFORM public._demo_register_row(p_run_id,'bookings',v_id);
    v_bk_count := v_bk_count+1;
  END LOOP;
  RETURN jsonb_build_object('booking_services', v_svc_count, 'bookings', v_bk_count);
END $$;


