    ('Lars Nilsson',      'Backend Engineer',          'Reliable Go and PostgreSQL services with strong observability.',                    ARRAY['Go','PostgreSQL','gRPC','Microservices'],                    9,  1500, 'available',           ARRAY['Swedish','English']),
