    ('Partner 20% ('||v_suffix||')',   'Partner channel with 20% rebate',       'SEK', false,  50),
    ('Campaign Q4 ('||v_suffix||')',   'Limited campaign October–December',     'SEK', false,  25)
  ) AS t(nm,descr,cur,isdef,prio) LOOP
