CREATE OR REPLACE FUNCTION "public"."set_exchange_rate"("p_base" "text", "p_quote" "text", "p_rate" numeric, "p_rate_date" "date" DEFAULT CURRENT_DATE, "p_source" "text" DEFAULT 'manual'::"text") RETURNS "public"."exchange_rates"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_row public.exchange_rates;
BEGIN
  IF NOT public.has_role(auth.uid(), 'admin') THEN
    RAISE EXCEPTION 'set_exchange_rate: admin role required';
  END IF;

  INSERT INTO public.exchange_rates (base_currency, quote_currency, rate, rate_date, source)
  VALUES (p_base, p_quote, p_rate, p_rate_date, p_source)
  ON CONFLICT (base_currency, quote_currency, rate_date)
  DO UPDATE SET rate = EXCLUDED.rate, source = EXCLUDED.source
  RETURNING * INTO v_row;

  RETURN v_row;
END;
$$;


