CREATE OR REPLACE FUNCTION "public"."set_quote_item_selection"("_accept_token" "text", "_item_id" "uuid", "_selected" boolean) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  _quote_id uuid;
  _is_optional boolean;
  _status text;
  _new_subtotal bigint;
  _new_tax bigint;
  _new_total bigint;
  _tax_rate numeric;
BEGIN
  -- locate the quote via token + verify item belongs to it
  SELECT q.id, q.status::text, q.tax_rate, qi.is_optional
    INTO _quote_id, _status, _tax_rate, _is_optional
  FROM quotes q
  JOIN quote_items qi ON qi.quote_id = q.id
  WHERE qi.id = _item_id AND q.accept_token = _accept_token;

  IF _quote_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Quote or item not found');
  END IF;

  IF _status IN ('accepted','rejected','expired') THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Quote is finalized');
  END IF;

  IF NOT COALESCE(_is_optional, false) THEN
    RETURN jsonb_build_object('ok', false, 'error', 'Line item is not optional');
  END IF;

  UPDATE quote_items SET selected_by_customer = _selected, updated_at = now()
  WHERE id = _item_id;

  -- recompute quote totals from included lines only
  SELECT COALESCE(SUM(line_subtotal_cents),0), COALESCE(SUM(line_tax_cents),0), COALESCE(SUM(line_total_cents),0)
    INTO _new_subtotal, _new_tax, _new_total
  FROM quote_items
  WHERE quote_id = _quote_id AND (is_optional = false OR selected_by_customer = true);

  UPDATE quotes
     SET subtotal_cents = _new_subtotal,
         tax_cents      = _new_tax,
         total_cents    = _new_total,
         updated_at     = now()
   WHERE id = _quote_id;

  RETURN jsonb_build_object(
    'ok', true,
    'subtotal_cents', _new_subtotal,
    'tax_cents', _new_tax,
    'total_cents', _new_total
  );
END;
$$;


ALTER FUNCTION "public"."set_quote_item_selection"("_accept_token" "text", "_item_id" "uuid", "_selected" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."ship_picking"("p_picking_order_id" "uuid", "p_tracking_number" "text" DEFAULT NULL::"text", "p_carrier" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_po RECORD;
  v_line RECORD;
  v_consumed INT := 0;
BEGIN
  IF NOT (public.has_role(auth.uid(), 'admin') OR public.has_role(auth.uid(), 'employee')) THEN
    RAISE EXCEPTION 'Insufficient permissions';
  END IF;

  SELECT * INTO v_po FROM public.picking_orders WHERE id = p_picking_order_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Picking order % not found', p_picking_order_id; END IF;
  IF v_po.status = 'shipped' THEN
    RETURN jsonb_build_object('success', true, 'already_shipped', true);
  END IF;
  IF v_po.status = 'cancelled' THEN
    RAISE EXCEPTION 'Cannot ship cancelled picking_order';
  END IF;

  -- Consume each reserved line
  FOR v_line IN SELECT * FROM public.picking_lines WHERE picking_order_id = p_picking_order_id AND status = 'picked' LOOP
    IF v_line.reservation_id IS NOT NULL THEN
      BEGIN
        PERFORM public.consume_reservation(v_line.reservation_id, v_line.qty_picked);
        v_consumed := v_consumed + 1;
      EXCEPTION WHEN OTHERS THEN
        -- log but continue
        INSERT INTO public.audit_logs (action, entity_type, entity_id, user_id, metadata)
        VALUES ('picking.consume_failed', 'picking_line', v_line.id, auth.uid(),
          jsonb_build_object('error', SQLERRM));
      END;
    END IF;
  END LOOP;

  UPDATE public.picking_orders
  SET status = 'shipped',
      shipped_at = now(),
      tracking_number = COALESCE(p_tracking_number, tracking_number),
      carrier = COALESCE(p_carrier, carrier)
  WHERE id = p_picking_order_id;

  -- Update underlying order status
  IF v_po.order_id IS NOT NULL THEN
    UPDATE public.orders SET status = 'shipped', updated_at = now()
    WHERE id = v_po.order_id;
  END IF;

  -- Emit platform event if helper exists
  BEGIN
    PERFORM public.emit_platform_event(
      'picking.shipped',
      jsonb_build_object(
        'picking_order_id', p_picking_order_id,
        'order_id', v_po.order_id,
        'tracking_number', p_tracking_number,
        'consumed_lines', v_consumed
      ),
      'pick_pack'
    );
  EXCEPTION WHEN OTHERS THEN NULL; END;

  INSERT INTO public.audit_logs (action, entity_type, entity_id, user_id, metadata)
  VALUES ('picking.shipped', 'picking_order', p_picking_order_id, auth.uid(),
    jsonb_build_object('order_id', v_po.order_id, 'tracking_number', p_tracking_number, 'consumed', v_consumed));

  RETURN jsonb_build_object('success', true, 'picking_order_id', p_picking_order_id, 'consumed_lines', v_consumed);
END;
$$;


ALTER FUNCTION "public"."ship_picking"("p_picking_order_id" "uuid", "p_tracking_number" "text", "p_carrier" "text") OWNER TO "postgres";


