CREATE OR REPLACE FUNCTION "public"."sign_employment_contract"("p_contract_id" "uuid", "p_side" "text" DEFAULT 'employee'::"text") RETURNS "public"."employment_contracts"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_row public.employment_contracts;
  v_emp public.employees;
  v_is_admin boolean;
BEGIN
  IF auth.uid() IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF;

  SELECT * INTO v_row FROM public.employment_contracts WHERE id = p_contract_id FOR UPDATE;
  IF v_row.id IS NULL THEN RAISE EXCEPTION 'Contract not found'; END IF;

  v_is_admin := has_role(auth.uid(), 'admin'::app_role);

  IF p_side = 'employer' THEN
    IF NOT v_is_admin THEN RAISE EXCEPTION 'Only admins can sign as employer'; END IF;
    UPDATE public.employment_contracts
    SET signed_by_employer_at = now(),
        status = CASE WHEN signed_by_employee_at IS NOT NULL THEN 'signed' ELSE status END,
        signed_at = CASE WHEN signed_by_employee_at IS NOT NULL THEN now() ELSE signed_at END
    WHERE id = p_contract_id RETURNING * INTO v_row;
  ELSE
    -- employee side
    SELECT * INTO v_emp FROM public.employees WHERE id = v_row.employee_id;
    IF NOT v_is_admin AND (v_emp.user_id IS NULL OR v_emp.user_id <> auth.uid()) THEN
      RAISE EXCEPTION 'Not authorized to sign this contract';
    END IF;
    UPDATE public.employment_contracts
    SET signed_by_employee_at = now(),
        status = CASE WHEN signed_by_employer_at IS NOT NULL THEN 'signed' ELSE status END,
        signed_at = CASE WHEN signed_by_employer_at IS NOT NULL THEN now() ELSE signed_at END
    WHERE id = p_contract_id RETURNING * INTO v_row;
  END IF;

  RETURN v_row;
END;
$$;


ALTER FUNCTION "public"."sign_employment_contract"("p_contract_id" "uuid", "p_side" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."start_mo"("p_mo_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_status public.mo_status;
BEGIN
  IF NOT (public.has_role(auth.uid(), 'writer') OR public.has_role(auth.uid(), 'admin')) THEN
    RAISE EXCEPTION 'Permission denied';
  END IF;

  SELECT status INTO v_status FROM public.manufacturing_orders WHERE id = p_mo_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'MO % not found', p_mo_id; END IF;

  IF v_status = 'in_progress' THEN
    RETURN jsonb_build_object('success', true, 'mo_id', p_mo_id, 'note', 'already in_progress');
  END IF;
  IF v_status <> 'confirmed' THEN
    RAISE EXCEPTION 'MO must be confirmed before starting (current: %)', v_status;
  END IF;

  UPDATE public.manufacturing_orders
     SET status = 'in_progress', started_at = now(), updated_at = now()
   WHERE id = p_mo_id;

  RETURN jsonb_build_object('success', true, 'mo_id', p_mo_id, 'status', 'in_progress');
END;
$$;


ALTER FUNCTION "public"."start_mo"("p_mo_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."start_webinar"("p_webinar_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_row webinars%ROWTYPE;
BEGIN
  IF NOT (has_role(auth.uid(),'writer') OR has_role(auth.uid(),'approver') OR has_role(auth.uid(),'admin')) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  UPDATE webinars SET status='live', updated_at=now() WHERE id=p_webinar_id AND status IN ('draft','published') RETURNING * INTO v_row;
  IF NOT FOUND THEN RAISE EXCEPTION 'webinar % cannot be started', p_webinar_id; END IF;
  PERFORM emit_platform_event('webinar.live', jsonb_build_object('webinar_id',v_row.id,'title',v_row.title), 'webinars');
  RETURN jsonb_build_object('success',true,'id',v_row.id,'status',v_row.status);
END $$;


ALTER FUNCTION "public"."start_webinar"("p_webinar_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."submit_expense_report"("p_report_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_report record;
BEGIN
  SELECT * INTO v_report FROM expense_reports WHERE id = p_report_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Report not found');
  END IF;
  IF v_report.status <> 'draft' THEN
    RETURN jsonb_build_object('success', false, 'error', 'Only draft reports can be submitted');
  END IF;

  UPDATE expense_reports
  SET status = 'submitted', submitted_at = now()
  WHERE id = p_report_id;

  RETURN jsonb_build_object('success', true, 'report_id', p_report_id, 'status', 'submitted');
END;
$$;


