CREATE OR REPLACE FUNCTION "public"."sync_agent_activity_on_approval"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_activity_id uuid;
BEGIN
  IF NEW.entity_type <> 'agent_skill' THEN
    RETURN NEW;
  END IF;

  IF NEW.status = OLD.status THEN
    RETURN NEW;
  END IF;

  BEGIN
    v_activity_id := NEW.entity_id::uuid;
  EXCEPTION WHEN others THEN
    RETURN NEW;
  END;

  IF NEW.status = 'approved' THEN
    UPDATE public.agent_activity
       SET status = 'approved'
     WHERE id = v_activity_id AND status = 'pending_approval';
  ELSIF NEW.status = 'rejected' THEN
    UPDATE public.agent_activity
       SET status = 'rejected',
           error_message = COALESCE(NEW.reason, 'Approval rejected')
     WHERE id = v_activity_id AND status = 'pending_approval';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_agent_activity_on_approval"() OWNER TO "postgres";


