CREATE OR REPLACE FUNCTION "public"."validate_fulfillment_status"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.fulfillment_status NOT IN ('unfulfilled', 'picked', 'packed', 'shipped', 'delivered') THEN
    RAISE EXCEPTION 'Invalid fulfillment_status: %', NEW.fulfillment_status;
  END IF;
  
  -- Auto-set timestamps based on status transitions
  IF NEW.fulfillment_status = 'picked' AND OLD.fulfillment_status = 'unfulfilled' AND NEW.picked_at IS NULL THEN
    NEW.picked_at := now();
  END IF;
  IF NEW.fulfillment_status = 'packed' AND OLD.fulfillment_status IN ('unfulfilled', 'picked') AND NEW.packed_at IS NULL THEN
    IF NEW.picked_at IS NULL THEN NEW.picked_at := now(); END IF;
    NEW.packed_at := now();
  END IF;
  IF NEW.fulfillment_status = 'shipped' AND OLD.fulfillment_status IN ('unfulfilled', 'picked', 'packed') AND NEW.shipped_at IS NULL THEN
    IF NEW.picked_at IS NULL THEN NEW.picked_at := now(); END IF;
    IF NEW.packed_at IS NULL THEN NEW.packed_at := now(); END IF;
    NEW.shipped_at := now();
  END IF;
  IF NEW.fulfillment_status = 'delivered' AND OLD.fulfillment_status IN ('unfulfilled', 'picked', 'packed', 'shipped') AND NEW.delivered_at IS NULL THEN
    IF NEW.picked_at IS NULL THEN NEW.picked_at := now(); END IF;
    IF NEW.packed_at IS NULL THEN NEW.packed_at := now(); END IF;
    IF NEW.shipped_at IS NULL THEN NEW.shipped_at := now(); END IF;
    NEW.delivered_at := now();
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."validate_fulfillment_status"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."validate_leave_balance_on_approve"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_year INTEGER;
  v_allocated NUMERIC;
  v_carried NUMERIC;
  v_used NUMERIC;
  v_available NUMERIC;
BEGIN
  -- Only check on transition into 'approved'
  IF NEW.status <> 'approved' OR (TG_OP = 'UPDATE' AND OLD.status = 'approved') THEN
    RETURN NEW;
  END IF;

  v_year := EXTRACT(YEAR FROM NEW.start_date)::INTEGER;

  SELECT COALESCE(allocated_days, 0), COALESCE(carried_over_days, 0)
  INTO v_allocated, v_carried
  FROM public.leave_allocations
  WHERE employee_id = NEW.employee_id
    AND leave_type = NEW.leave_type
    AND year = v_year;

  -- If no allocation exists, treat as 0 (will block unless days = 0)
  v_allocated := COALESCE(v_allocated, 0);
  v_carried := COALESCE(v_carried, 0);

  -- Sum already-approved days for this type/year (excluding current row)
  SELECT COALESCE(SUM(days), 0)
  INTO v_used
  FROM public.leave_requests
  WHERE employee_id = NEW.employee_id
    AND leave_type = NEW.leave_type
    AND status = 'approved'
    AND id <> NEW.id
    AND EXTRACT(YEAR FROM start_date)::INTEGER = v_year;

  v_available := v_allocated + v_carried - v_used;

  IF NEW.days > v_available THEN
    RAISE EXCEPTION 'Cannot approve: requested % days but only % days available for % in % (allocated %, carried %, already approved %)',
      NEW.days, v_available, NEW.leave_type, v_year, v_allocated, v_carried, v_used
      USING ERRCODE = 'check_violation';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."validate_leave_balance_on_approve"() OWNER TO "postgres";


