CREATE OR REPLACE FUNCTION "public"."webinar_reminder_tick"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_confirm int := 0;
  v_t24     int := 0;
  v_t1      int := 0;
  v_post    int := 0;
  r record;
BEGIN
  -- 1. Confirmation: any registration without confirm marker, webinar not cancelled
  FOR r IN
    SELECT wr.id, wr.webinar_id, wr.email, wr.name, wr.lead_id, w.title, w.date, w.meeting_url
    FROM webinar_registrations wr
    JOIN webinars w ON w.id = wr.webinar_id
    WHERE wr.reminder_confirm_sent_at IS NULL
      AND w.status IN ('draft','published','live')
    LIMIT 200
  LOOP
    PERFORM emit_platform_event(
      'webinar.reminder.confirm',
      jsonb_build_object(
        'registration_id', r.id, 'webinar_id', r.webinar_id,
        'email', r.email, 'name', r.name, 'lead_id', r.lead_id,
        'title', r.title, 'date', r.date, 'meeting_url', r.meeting_url
      ),
      'webinars'
    );
    UPDATE webinar_registrations SET reminder_confirm_sent_at = now() WHERE id = r.id;
    v_confirm := v_confirm + 1;
  END LOOP;

  -- 2. T-24h: webinar starts within next 24h, more than 23h away
  FOR r IN
    SELECT wr.id, wr.webinar_id, wr.email, wr.name, wr.lead_id, w.title, w.date, w.meeting_url
    FROM webinar_registrations wr
    JOIN webinars w ON w.id = wr.webinar_id
    WHERE wr.reminder_t24_sent_at IS NULL
      AND w.status IN ('published','live')
      AND w.date BETWEEN now() + interval '23 hours' AND now() + interval '25 hours'
    LIMIT 500
  LOOP
    PERFORM emit_platform_event(
      'webinar.reminder.t24',
      jsonb_build_object(
        'registration_id', r.id, 'webinar_id', r.webinar_id,
        'email', r.email, 'name', r.name, 'lead_id', r.lead_id,
        'title', r.title, 'date', r.date, 'meeting_url', r.meeting_url
      ),
      'webinars'
    );
    UPDATE webinar_registrations SET reminder_t24_sent_at = now() WHERE id = r.id;
    v_t24 := v_t24 + 1;
  END LOOP;

  -- 3. T-1h: webinar starts within next hour
  FOR r IN
    SELECT wr.id, wr.webinar_id, wr.email, wr.name, wr.lead_id, w.title, w.date, w.meeting_url
    FROM webinar_registrations wr
    JOIN webinars w ON w.id = wr.webinar_id
    WHERE wr.reminder_t1_sent_at IS NULL
      AND w.status IN ('published','live')
      AND w.date BETWEEN now() + interval '40 minutes' AND now() + interval '90 minutes'
    LIMIT 500
  LOOP
    PERFORM emit_platform_event(
      'webinar.reminder.t1',
      jsonb_build_object(
        'registration_id', r.id, 'webinar_id', r.webinar_id,
        'email', r.email, 'name', r.name, 'lead_id', r.lead_id,
        'title', r.title, 'date', r.date, 'meeting_url', r.meeting_url
      ),
      'webinars'
    );
    UPDATE webinar_registrations SET reminder_t1_sent_at = now() WHERE id = r.id;
    v_t1 := v_t1 + 1;
  END LOOP;

  -- 4. Post-webinar: 30m+ after end, only for completed webinars
  FOR r IN
    SELECT wr.id, wr.webinar_id, wr.email, wr.name, wr.lead_id, wr.attended,
           w.title, w.recording_url, w.date
    FROM webinar_registrations wr
    JOIN webinars w ON w.id = wr.webinar_id
    WHERE wr.reminder_post_sent_at IS NULL
      AND w.status = 'completed'
      AND (w.date + (COALESCE(w.duration_minutes,60) || ' minutes')::interval + interval '30 minutes') < now()
    LIMIT 500
  LOOP
    PERFORM emit_platform_event(
      'webinar.reminder.post',
      jsonb_build_object(
        'registration_id', r.id, 'webinar_id', r.webinar_id,
        'email', r.email, 'name', r.name, 'lead_id', r.lead_id,
        'title', r.title, 'recording_url', r.recording_url,
        'attended', COALESCE(r.attended, false),
        'variant', CASE WHEN r.attended THEN 'thanks' ELSE 'missed_you' END
      ),
      'webinars'
    );
    UPDATE webinar_registrations SET reminder_post_sent_at = now() WHERE id = r.id;
    v_post := v_post + 1;
  END LOOP;

  RETURN jsonb_build_object(
    'success', true,
    'emitted', jsonb_build_object(
      'confirm', v_confirm, 't24', v_t24, 't1', v_t1, 'post', v_post
    )
  );
END $$;


ALTER FUNCTION "public"."webinar_reminder_tick"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."webinar_reminder_tick"() IS 'Emits webinar.reminder.{confirm,t24,t1,post} platform events. Cron every 15 min. Each reminder dedup''d via marker column on webinar_registrations.';



CREATE OR REPLACE FUNCTION "public"."webinar_tick"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_started int := 0; v_completed int := 0; r record;
BEGIN
  FOR r IN SELECT id, title, date FROM webinars
           WHERE status='published' AND date <= now() AND date > now() - interval '1 hour'
  LOOP
    UPDATE webinars SET status='live', updated_at=now() WHERE id=r.id;
    PERFORM emit_platform_event('webinar.live', jsonb_build_object('webinar_id',r.id,'title',r.title,'auto',true), 'webinars');
    v_started := v_started + 1;
  END LOOP;

  FOR r IN SELECT id, title, date, duration_minutes FROM webinars
           WHERE status='live' AND date + (duration_minutes || ' minutes')::interval < now()
  LOOP
    UPDATE webinars SET status='completed', updated_at=now() WHERE id=r.id;
    PERFORM emit_platform_event('webinar.completed', jsonb_build_object('webinar_id',r.id,'title',r.title,'auto',true), 'webinars');
    v_completed := v_completed + 1;
  END LOOP;

  RETURN jsonb_build_object('started',v_started,'completed',v_completed,'at',now());
END $$;


ALTER FUNCTION "public"."webinar_tick"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."wiki_pages_stamp"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    IF NEW.created_by IS NULL THEN NEW.created_by := auth.uid(); END IF;
    IF NEW.updated_by IS NULL THEN NEW.updated_by := auth.uid(); END IF;
    NEW.created_at := COALESCE(NEW.created_at, now());
    NEW.updated_at := now();
  ELSIF TG_OP = 'UPDATE' THEN
    NEW.updated_by := COALESCE(auth.uid(), NEW.updated_by);
    NEW.updated_at := now();
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."wiki_pages_stamp"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."year_end_readiness"("p_year" integer DEFAULT ((EXTRACT(year FROM CURRENT_DATE))::integer - 1)) RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE v_periods_open int; v_draft_entries int; v_voucher_gaps int; v_unreconciled int; v_unpaid_invoices int; v_open_expenses int; v_checks jsonb;
BEGIN
  SELECT COUNT(*) INTO v_periods_open FROM public.accounting_periods WHERE fiscal_year = p_year AND status <> 'closed';
  SELECT COUNT(*) INTO v_draft_entries FROM public.journal_entries WHERE EXTRACT(YEAR FROM entry_date)::int = p_year AND status = 'draft';
  SELECT COUNT(*) INTO v_voucher_gaps FROM public.list_voucher_gaps(p_year, NULL);
  BEGIN EXECUTE 'SELECT COUNT(*) FROM public.payment_reconciliations WHERE status = ''pending'' AND EXTRACT(YEAR FROM created_at)::int <= $1' INTO v_unreconciled USING p_year;
  EXCEPTION WHEN OTHERS THEN v_unreconciled := NULL; END;
  BEGIN EXECUTE 'SELECT COUNT(*) FROM public.invoices WHERE status IN (''sent'',''overdue'') AND EXTRACT(YEAR FROM issue_date)::int <= $1' INTO v_unpaid_invoices USING p_year;
  EXCEPTION WHEN OTHERS THEN v_unpaid_invoices := NULL; END;
  BEGIN EXECUTE 'SELECT COUNT(*) FROM public.expense_reports WHERE status NOT IN (''paid'',''rejected'') AND EXTRACT(YEAR FROM report_date)::int <= $1' INTO v_open_expenses USING p_year;
  EXCEPTION WHEN OTHERS THEN v_open_expenses := NULL; END;
  v_checks := jsonb_build_array(
    jsonb_build_object('id','periods_closed','label','All 12 periods closed','pass', v_periods_open = 0, 'detail', v_periods_open || ' periods still open'),
    jsonb_build_object('id','no_drafts','label','No draft journal entries','pass', v_draft_entries = 0, 'detail', v_draft_entries || ' draft entries remain'),
    jsonb_build_object('id','voucher_integrity','label','No voucher-number gaps','pass', v_voucher_gaps = 0, 'detail', v_voucher_gaps || ' gaps found'),
    jsonb_build_object('id','reconciliations','label','No pending reconciliations','pass', COALESCE(v_unreconciled,0) = 0, 'detail', COALESCE(v_unreconciled::text,'n/a')),
    jsonb_build_object('id','invoices_settled','label','No unpaid customer invoices','pass', COALESCE(v_unpaid_invoices,0) = 0, 'detail', COALESCE(v_unpaid_invoices::text,'n/a')),
    jsonb_build_object('id','expenses_settled','label','No open expense reports','pass', COALESCE(v_open_expenses,0) = 0, 'detail', COALESCE(v_open_expenses::text,'n/a'))
  );
  RETURN jsonb_build_object('fiscal_year', p_year,
    'ready', NOT EXISTS (SELECT 1 FROM jsonb_array_elements(v_checks) c WHERE (c->>'pass')::boolean = false),
    'checks', v_checks, 'generated_at', now());
END; $_$;


ALTER FUNCTION "public"."year_end_readiness"("p_year" integer) OWNER TO "postgres";


