COMMENT ON TABLE "public"."federation_peer_missions" IS 'Stores mission metadata for federation peer agents. Allows agents to discover their role and responsibilities via /rest/resources/mission endpoint.';



COMMENT ON COLUMN "public"."federation_peer_missions"."mission_id" IS 'Mission template ID (e.g., "growth-operator", "commerce-operator", "custom")';



COMMENT ON COLUMN "public"."federation_peer_missions"."mission_name" IS 'Human-readable mission name (e.g., "Growth Operator")';



COMMENT ON COLUMN "public"."federation_peer_missions"."instructions" IS 'Complete mission instructions and responsibilities';



COMMENT ON COLUMN "public"."federation_peer_missions"."focus_resources" IS 'Array of resource types to prioritize (e.g., ["briefing", "leads"])';



COMMENT ON COLUMN "public"."federation_peer_missions"."focus_tools" IS 'Array of skill names to prioritize (e.g., ["score_lead", "update_deal"])';



